window.__I18N_EMBEDDED__={"zh-tw":{"meta":{"title":"專案全面翻新：AI 驅動的敏捷考古與重構計畫"},"common":{"label_input":"Input","label_output":"Output","fold_specs":"展開詳細規格要求","fold_doc_tree":"📂 點擊展開：考古期工作目錄（records/ + main/，Agent 寫入）","fold_figma_org":"組織架構：中央範本，本地清洗","fold_figma_pattern":"業務模組維護邊界","fold_figma_align":"Figma 文案與 i18n 分界","fold_i18n_json":"🔍 查看：i18n 數據型別與腳本規範細節","fold_i18n_steps":"翻譯準備完整步驟（共 {n} 步）","fold_deliverables":"產出物清單","tier_budget":"可省","tier_required":"必用","tier_context":"需上下文","tier_human":"人工","tool_claude":"Claude","tool_cursor":"Cursor","tool_human":"人工","audit_layers_label":"考古驗證三層級（Role 4）","issue_tag_legend_heading":"Issue 類型標籤","issue_tag_legend":[{"tag":"Schema","meaning":"資料邊界／Transformer／純函數"},{"tag":"UI","meaning":"元件或頁面，需 Figma To-be"},{"tag":"BDD","meaning":"Flow 驗收案例，合併前須全綠"}],"glossary":{"L1":{"short":"覆蓋地圖","tip":"比對 flow.md § Scoped Files：scope 內每個 .ts/.tsx 皆有歸屬。AI 自動驗證，未歸屬檔案 = 0。"},"L2":{"short":"結構閘門","tip":"flow 七章節、endpoint 閉環、BDD 對齊、transform 收攏。AI 產 gap report，全綠即過。"},"L3":{"short":"人工抽樣","tip":"隨機對照原始碼，確認考古內容寫對而非只寫齊。人類簽核，核心 flow 建議 5 項。"},"四區":{"short":"survey-checklist 四區塊","tip":"Flows、Endpoints、Static Pages、Global Constraints——盤點凍結需四區 100% 勾選。"},"可先翻修":{"short":"Scope 標記","tip":"Phase 2 PM 對齊後標記為可立即開工的 flow／頁面；Phase 3 僅此類進開工池。"},"待後續對齊":{"short":"Scope 標記","tip":"spec + Figma As-is 仍須就緒，但 refactor 第一輪不動；其餘翻修告一段落後再與 PM 更新 To-be。"},"As-is":{"short":"現況還原稿","tip":"100% 對正式環境的 Figma 畫布；Phase 2 PM 對齊硬性前置。"},"To-be":{"short":"目標設計稿","tip":"重構開工後，僅「可先翻修」項目增量更新；UI Issue 開工前需對應區塊 To-be。"}},"s9_layers_note":"此「三層防線」指 API 資料流（Upstream → Contract → Runtime），與考古驗證的 L1／L2／L3 不同。"},"hero":{"title":"專案全面翻新：AI 驅動的敏捷考古與重構計畫","subtitle":"透過 AI 考古補齊缺失的 Specification（步驟、頁面、流程）、從前端視角釐清 API Schema 並建立穩定 Transformer、重建 Figma 設計系統，並以 Agent Skills 流水線驅動文件化驗收，系統性降低設計脫鉤與技術債。"},"toc":[{"id":"s1","label":"前情提要"},{"id":"s2","label":"頂層架構"},{"id":"s3","label":"四角色 Workflow"},{"id":"s4","label":"考古盤點"},{"id":"s5","label":"凍結管理"},{"id":"s6","label":"Figma 設計系統"},{"id":"s7","label":"多國語系"},{"id":"s8","label":"開始翻新"},{"id":"s9","label":"API 邊界與 Zod"}],"s1":{"emoji":"🛑","heading":"前情提要與現況痛點盤點","table_cols":["痛點","影響","根因描述"],"table_rows":[{"pain":"缺乏規格書","impact":"商業邏輯無法核對、變更風險高","cause":"沒有標準文件能核對商業邏輯；步驟、頁面、流程全靠從程式碼通靈還原。"},{"pain":"前端程式碼混亂","impact":"修復成本極高","cause":"出現許多不推薦的寫法，導致踩到某些 Framework Bug 時極難排查。"},{"pain":"後端無規格","impact":"前端通靈判斷","cause":"後端沒有規格書，單從前端程式碼中無法準確判斷回應格式，且為了暫時解決某些後端回傳的錯誤格式而前端加上的額外通靈判斷。此為後續 error 格式混亂與 transform 分散的上游根因。"},{"pain":"Error 格式不統一","impact":"髒邏輯累積","cause":"回傳 error 格式不統一，前端出現很多為了處理不同錯誤格式而加上的髒邏輯。"},{"pain":"資料格式命名混亂","impact":"重構難追溯","cause":"前端目前自創了一層 transform，但因為分散在各處，重構時難以快速找到原始 value。"},{"pain":"設計稿與正式環境脫鉤","impact":"UI 還原靠猜、設計迭代無法追溯","cause":"Figma 未與 codebase 同步維護，正式環境與設計稿長期分歧。"}],"vision_heading":"現況痛點 vs 翻新願景","as_is_title":"As-is 現況痛點","to_be_title":"To-be 翻新願景","as_is_items":["缺乏可核對商業邏輯的規格書","設計稿與正式環境脫鉤","程式碼劣化、技術債累積","新人 Onboarding 困難、通靈成本高","後端格式混亂，前端 transform 分散"],"to_be_items":["Specification 成為商業邏輯 SSOT","考古業務行為皆有 BDD 驗收案例","Figma 設計系統與程式碼同步","AI Agent 自動化派工 + 人機協作邊界清晰","資料邊界隔離，乾淨型別取代髒資料"]},"s2":{"emoji":"🗺️","heading":"頂層架構、文件流向與目錄規範","subheading":"從舊 Codebase 到盤點凍結的完整產出鏈。考古期工作資料寫入 records/ 與 main/；盤點完成後另產 Docusaurus 供 PM 對齊。","example_callout":"⚠️ 本區 `[flow-name]`、`[endpoint-name]` 及下方範例清單僅為說明目錄結構與切分粒度，並非本專案真實 flow 或 API。實際名稱與邊界於考古階段依現有 codebase 業務邏輯逐一定義。","taxonomy_heading":"考古產物三層分類","taxonomy_intro":"Flow 不是唯一分類軸。Endpoint 規格與 Flow 正交——一個 flow 可引用多個 endpoint，一個 endpoint 也可被多個 flow 共用。","taxonomy_cols":["層級","路徑","顆粒度","考古深度"],"taxonomy_rows":[{"tier":"User Flow（Record）","path":"docs/records/flows/[flow-name]/","granularity":"一條完整使用者任務（Entry → Terminal State）","depth":"flow.md + BDD + 引用 endpoints"},{"tier":"靜態／內容","path":"docs/main/pages/","granularity":"一頁或一區塊","depth":"只列區塊結構 + i18n key，不寫 schema / BDD"},{"tier":"全域約束","path":"docs/records/global-constraints/","granularity":"跨 flow 的橫切邏輯","depth":"只有 BDD，無獨立 flow.md"}],"taxonomy_endpoint_note":"Endpoint 規格（docs/records/endpoints/）為另一條正交軸：一 endpoint 一檔，考古期推測 upstream 結構，規劃師產出 Frontend Interface + Transformer 至 main/contract-schemas/endpoints/。","flow_granularity_heading":"Flow 切分準則（Highway Bus 服務 — 範例示意）","flow_granularity_rules":["以使用者任務（User Journey）為單位，不以頁面或路由切分。","一 Record = 一條可獨立封檔的完整旅程（Entry Point → Terminal State）。","Endpoint 規格（endpoints/）與 Flow（flows/）正交：一 flow 可引用多個 endpoint，endpoint 可跨 flow 共用。","有獨立 Entry Point 與完整旅程者另開 flow（如 Email 深連結的 Coupon 流程）；僅在另一 flow 途中觸發的邏輯（如訂票途中的 Coupon 套用）寫入該 flow 的 Edge Cases。","導向外部表單、站內無完整任務的介紹頁（如 Affiliate）→ 靜態頁盤點，不開 flow。","跨 flow 橫切邏輯（Session 時效、防刷、URL 語系同步）收攏至 global-constraints/。"],"flow_examples_note":"以下僅示範切分粒度類型，[flow-name] 為 placeholder，非本專案真實 flow 名稱：","flow_examples":[{"name":"[search-flow]","desc":"搜尋與篩選（含 status 驅動的隱藏 UI 狀態）"},{"name":"[booking-flow]","desc":"訂票主流程（跨頁面完整旅程）"},{"name":"[coupon-email-flow]","desc":"Email 深連結入口的 Coupon 流程（獨立 Entry Point）"},{"name":"[lookup-flow]","desc":"預約查詢／變更類流程"}],"endpoint_examples_note":"Endpoint 檔名同為範例，考古時依實際 API 命名：","endpoint_examples":["search-routes.ts","get-seat-map.ts","post-reservation.ts","get-reservation.ts"],"diagram":"graph TD\n    Code[\"舊原始碼\"] -->|Repomix 打包 + Agent 探索| R1[\"🕵️ 1.代碼考古學家\"]\n    R1 -->|As-is 業務行為| Flow[\"docs/records/flows/[flow-name]/flow.md\"]\n    R1 -->|推測 endpoint 回傳結構| Upstream[\"docs/records/endpoints/[endpoint-name].ts\"]\n    Flow --> R2[\"📐 2.資料邊界規劃師\"]\n    Upstream --> R2\n    Comp[\"Components / Store 衍生邏輯\"] --> R2\n    R2 -->|Frontend Interface + Transformer| Schema[\"docs/main/contract-schemas/endpoints/\"]\n    R2 --> Ctx[\"CONTEXT.md\"]\n    Flow --> R3[\"✍️ 3.行為測試架構師\"]\n    Schema --> R3\n    R3 -->|BDD 案例| BDD[\"docs/records/flows/[flow-name]/e2e-cases.feature\"]\n    Flow --> R4[\"⚖️ 4.文件盤點員\"]\n    Schema --> R4\n    BDD --> R4\n    R4 -->|Cover 審查| Check[\"docs/survey-checklist.md\"]\n    Check -->|100% Check| Freeze[\"盤點凍結\"]\n    Freeze -->|整理盤點文件| Docs[\"Docusaurus 文件網站\"]\n    Docs -->|PM 對齊| PM[\"業務／技術變更討論\"]\n    Freeze -.->|開發者 reference| Ref[\"records/ + main/ 留存\"]","doc_tree_note":"以下為考古與重構期的工作目錄，供 Agent 寫入與開發者查閱、refactor 引用；非 PM 直接閱讀格式。","docusaurus_heading":"盤點完成後：Docusaurus 產出","docusaurus_intro":"survey-checklist 達 100% 後，依盤點文件（records/ + main/ + CONTEXT.md）整理為 Docusaurus 格式，於獨立 repo 建置文件網站，作為與 PM 對齊認知的正式介面。main/ 與 records/ 仍留存，供開發者自用與重構 reference。","docusaurus_steps":["以凍結後的盤點文件為 source（非考古期即寫 Docusaurus）","Skill / Script 轉換為 Docusaurus 結構（MDX、sidebar、Admonitions 等）","彙整各 flow.md § 待 PM 釐清 至 Open Questions 專區","獨立 repo 部署文件網站","以此網站與 PM 進行技術與業務變更討論"],"doc_tree_cols":["路徑","用途"],"doc_tree_rows":[{"path":"CONTEXT.md","desc":"全域 glossary（常駐）。考古期持續更新，grill-with-docs 沿用。"},{"path":"docs/survey-checklist.md","desc":"考古進度追蹤表。四區 + 每條 Record 的 L1/L2/L3 子勾選。"},{"path":"docs/records/","desc":"As-is 考古工作區。開發者查閱與 refactor reference；盤點凍結後留存，不作 PM 對外介面。"},{"path":"docs/records/flows/[flow-name]/flow.md","desc":"As-is 現況業務流程。名稱於考古階段依 codebase 定義（placeholder: [flow-name]）。"},{"path":"docs/records/endpoints/[endpoint-name].ts","desc":"考古期從 codebase 推測的單一 endpoint 原始回傳結構（TypeScript type）。名稱於考古階段定義。"},{"path":"docs/records/flows/[flow-name]/e2e-cases.feature","desc":"BDD 測試案例。"},{"path":"docs/main/flows/","desc":"確認過的 As-is 流程；重構期 To-be SSOT 基石。開發者 reference。"},{"path":"docs/main/pages/","desc":"頁面邏輯盤點。開發者 reference。"},{"path":"docs/main/contract-schemas/shared/","desc":"全域 Entities（To-be）。開發者 reference。"},{"path":"docs/main/contract-schemas/endpoints/","desc":"Frontend Interface + Transformer（To-be）。開發者 reference。"}]},"s3":{"emoji":"🛠️","heading":"透過 Skills Workflow 產出資料","subheading":"四角色核心任務與精準 I/O。技術規格收進各自折疊抽屜；Role 4 的三層檢核流程見下方專節。","auditor_heading":"文件盤點三層檢核流程","auditor_intro":"Role 4 不重新考古，而是驗證 Role 1–3 的模板契約是否履行。「不漏檔案」與「不漏細節」分開處理：L1/L2 可自動驗證，L3 由人工抽樣對照原始碼。","auditor_diagram":"flowchart TD\n    Draft[\"① AI 草稿 checklist\"] --> L1[\"② L1 覆蓋地圖<br/>未歸屬檔案 = 0\"]\n    L1 --> L2[\"③ L2 結構閘門<br/>模板 + 交叉引用\"]\n    L2 --> Gap[\"④ gap report\"]\n    Gap --> L3[\"⑤ L3 人工抽樣<br/>對照原始碼\"]\n    L3 --> Check[\"⑥ survey-checklist 勾選\"]\n    Check --> Freeze[\"四區 100% → 凍結\"]","auditor_workflow_heading":"每條 Record 的實際執行步驟","auditor_workflow_steps":["AI 依 legacy 檔案樹與已產出物，草稿更新 survey-checklist.md 四區項目。","AI 跑 L1：比對 flow.md § Scoped Files，確認 scope 內每個 .ts/.tsx 有歸屬，未歸屬檔案 = 0。","AI 跑 L2：檢查 flow 七章節齊全、Referenced Endpoints 閉環（upstream .ts + contract-schema .md）、BDD Scenario 與 flow.md 對齊、@old_logic_location 出現在 Scoped Files。","產出 gap report，列出未通過項；未全綠則退回對應 Role 補件。","人類審 gap report，對該 Record 執行 L3 抽樣（見下方清單）。","L1 + L2 + L3 全過 → 勾選該 Record；四區全部勾選 → 第一階段凍結。"],"auditor_layers_heading":"三層檢核定義","auditor_layers_cols":["層級","檢查什麼","執行者","過關條件"],"auditor_layers_rows":[{"layer":"L1 覆蓋地圖","checks":"scope 內 legacy 檔案是否皆有歸屬","who":"AI","pass":"未歸屬檔案 = 0"},{"layer":"L2 結構閘門","checks":"flow 模板、endpoint 閉環、BDD 對齊、transform 收攏","who":"AI","pass":"gap report 全綠"},{"layer":"L3 人工抽樣","checks":"隨機對照原始碼，確認內容寫對而非只寫齊","who":"Human","pass":"抽樣項全過（核心 flow 建議 5 項）"}],"auditor_spotcheck_heading":"L3 人工抽樣清單（每條 Flow Record）","auditor_spotcheck_items":["隨機挑 1 個 Edge Case → 對照原始 component 的 if-else，確認 flow.md 描述正確。","隨機挑 1 個 @old_logic_location → 確認 transformer 邏輯有收攏、沒有漏算。","隨機挑 1 個 Unverified Logic → 確認確實無法從 code 解釋（非偷懶標記）。","（核心業務 flow 追加）再抽 1 個 Happy Path 步驟 + 1 個 Referenced Endpoint 欄位語意。"],"checklist_heading":"survey-checklist.md 四區結構","checklist_intro":"不同考古產物類型過關標準不同。每格勾選前必須附 L1/L2/L3 子勾選，避免「有文件但沒驗過」。","checklist_cols":["區塊","勾選單位","過關標準","檢核深度"],"checklist_rows":[{"area":"Flows","unit":"每條 [flow-name] Record","standard":"flow.md（含待 PM 釐清）+ e2e-cases.feature + 引用的 endpoints 皆有 contract-schemas；BDD 與 flow.md 對齊","depth":"L1 + L2 + L3"},{"area":"Endpoints","unit":"每個 [endpoint-name].ts","standard":"對應 main/contract-schemas/endpoints/[name].md 存在且引用 upstream","depth":"L2"},{"area":"Static Pages","unit":"每頁","standard":"main/pages/ 有區塊 + i18n key 列表（不需 BDD）","depth":"L1"},{"area":"Global Constraints","unit":"整包","standard":"global-constraints/e2e-cases.feature 涵蓋 s4 列出的橫切邏輯","depth":"L2 + L3"}],"checklist_example_note":"以下為 checklist 條目格式範例（抽象示意）：","roles":[{"emoji":"🕵️","title":"代碼考古學家 (Code Archaeologist)","task":"摸清舊系統的「現況（As-is）」：提煉純粹業務行為、從 codebase 推測相關 endpoint 回傳結構與所有可能性，排除死碼。","input":["Repomix 打包的 codebase","指定 flow 相關路由／組件 scope"],"output":["docs/records/flows/[flow-name]/flow.md","docs/records/endpoints/[endpoint-name].ts","CONTEXT.md（增量更新 glossary）"],"ai_recommendation":{"tool":"claude","model":"Sonnet 4.5","tier":"budget","hint":"大量檔案分批考古"},"spec_summary":"展開 flow.md 模板要求","spec_example_note":"以下為抽象範例，僅示範章節結構，非本專案真實 flow 或 endpoint。","spec_sections":[{"title":"### Entry Points","desc":"哪些頁面／路由／首頁區塊可進入此 flow。首頁 spec 只註明引用，行為細節寫在此處。"},{"title":"### Referenced Endpoints","desc":"此 flow 涉及的 endpoints/[name].ts 清單，作為與 endpoint 正交軸的索引。"},{"title":"### Happy Path","desc":"極簡的使用者成功操作步驟。"},{"title":"### Edge Cases","desc":"程式碼內所有涉及業務邏輯的分支（排除網路斷線等基建錯誤）。"},{"title":"### 待 PM 釐清","desc":"商務意圖或場景不明：code 看得懂行為，但不知「為什麼」或正確規則為何。標註來源位置與疑問，盤點凍結後經 Docusaurus Open Questions 與 PM 對齊。"},{"title":"### Unverified Logic","desc":"程式碼謎團：有寫但無踩到、無法 reproduce 或無法解釋的分支。標註來源檔案位置，留待上線 log 驗證或後端確認（非 PM 商務問題）。"},{"title":"### Scoped Files（覆蓋地圖）","desc":"Record 封檔前必填。scope 內每個 .ts/.tsx 必須有歸屬：被 flow 章節引用、Dead Code（附理由）、Unverified Logic、或交叉引用其他 flow。未歸屬檔案 = 0 方可交 Role 4。"}],"spec_code":"# [flow-name]\n\n### Entry Points\n- `/some-list-page` — 使用者從列表頁選項進入\n- `/landing#quick-action` — 首頁某區塊作為此 flow 的捷徑入口\n\n### Referenced Endpoints\n- `endpoints/search-items.ts` — 查詢與篩選\n- `endpoints/submit-action.ts` — 送出主要動作\n\n### Happy Path\n1. 使用者設定必要條件\n2. 系統顯示可選結果\n3. 使用者完成主要動作並看到成功狀態\n\n### Edge Cases\n- 查無結果時顯示空狀態提示\n- 條件不符時阻止進入下一步\n\n### 待 PM 釐清\n- 某身份是否應有不同折扣規則？code 有分支但無業務說明（`src/legacy/Pricing.tsx:120`）\n\n### Unverified Logic\n- `src/legacy/foo.ts:88` — 某分支從未觸發，原因不明\n\n### Scoped Files\n| 檔案 | 歸屬 |\n|---|---|\n| src/pages/Booking.tsx | Happy Path + Edge Cases |\n| src/utils/legacyCoupon.ts | Edge Cases: 優惠券過期 |\n| src/deprecated/oldFlow.ts | Dead Code（已確認無路由引用） |\n| src/hooks/useMystery.ts | → Unverified Logic |\n\n---\n# endpoints/submit-action.ts（同 Record 產出，抽象範例）\n\n/** @endpoint POST /api/some-action */\ninterface RawActionResponse {\n  /** 欄位語意待確認，可能非字面意思 */\n  status_code: string;\n  payload: unknown;\n}"},{"emoji":"📐","title":"資料邊界規劃師 (Data Boundary Planner)","task":"以考古產出的 upstream 為起點，定義 To-be Frontend Interface，並將散落在組件與 Store 的轉換邏輯收攏至 Transformer。不直接碰 live API。","input":["docs/records/flows/[flow-name]/flow.md","docs/records/endpoints/[endpoint-name].ts","舊 component／store 應收攏的 transform 片段","既有 docs/main/contract-schemas/shared/"],"output":["docs/main/contract-schemas/endpoints/[endpoint-name].md","（若需）docs/main/contract-schemas/shared/[entity].md","CONTEXT.md（增量更新 glossary）"],"ai_recommendation":{"tool":"claude","model":"Opus 4.6","tier":"required","hint":"型別精度要求高"},"spec_summary":"展開 contract-schema 模板要求","spec_example_note":"以下為抽象範例，非本專案真實 API 或欄位。","spec_sections":[{"title":"Upstream Schema（引用 records/endpoints/）","desc":"以 Role 1 產出的 .ts 為 SSOT，標註欄位語意疑義與已知後端怪癖。"},{"title":"Target TypeScript Interface","desc":"To-be 前端純淨型別。JSDoc 標註 @upstream_source 與 @old_logic_location。"},{"title":"Transformer Pure Functions","desc":"可執行的 TypeScript 轉換函數原型，收攏 component／store 中的衍生計算。"}],"spec_code":"/** @upstream_source records/endpoints/submit-action.ts */\n\n// --- Upstream（引用考古產物，摘要） ---\n// status_code: string  — 非 HTTP status，為業務狀態碼\n\n// --- Target Interface ---\ninterface ActionViewModel {\n  /** @old_logic_location src/legacy/ConfirmPanel.tsx:42 */\n  isSuccess: boolean;\n  displayMessage: string;\n}\n\n// --- Transformer ---\nfunction transformActionResponse(raw: RawActionResponse): ActionViewModel {\n  return {\n    isSuccess: raw.status_code === 'OK',\n    displayMessage: raw.payload?.message ?? '',\n  };\n}"},{"emoji":"✍️","title":"行為測試架構師 (Behavior Test Architect)","task":"將 flow.md 業務邏輯轉化為與實作解耦的 BDD 案例，並與 flow.md 章節保持可追溯對齊。","input":["docs/records/flows/[flow-name]/flow.md","docs/main/contract-schemas/endpoints/ + shared/"],"output":["docs/records/flows/[flow-name]/e2e-cases.feature"],"ai_recommendation":{"tool":"claude","model":"Sonnet 4.5","tier":"budget","hint":"結構化 BDD 輸出"},"spec_summary":"展開 BDD 模板要求","spec_example_note":"以下為抽象範例，非本專案真實情境。","spec_sections":[{"title":"Gherkin 語法","desc":"必須使用 Given-When-Then 語法。"},{"title":"覆蓋率對齊 flow.md","desc":"Happy Path 至少一個 Scenario；每個 Edge Case 至少一個 Scenario。Scenario 上方以 comment 標註對應 flow.md 章節。"},{"title":"待 PM 釐清 / Unverified Logic 不寫 Scenario","desc":"商務待確認項與 code 謎團均不寫入 Scenario；於 feature 檔頂部 comment 分別列出，引用 flow.md 對應章節。"},{"title":"排除基建錯誤","desc":"404/500/網路斷線由全域 Client 處理，不寫入 Feature 檔。"}],"spec_code":"# 待 PM 釐清（引用 flow.md § 待 PM 釐清）:\n# - 某身份折扣規則待確認\n\n# 待 log 驗證（引用 flow.md § Unverified Logic）:\n# - src/legacy/foo.ts:88 — 某分支從未觸發\n\n# 對應 flow.md § Happy Path\nScenario: 使用者完成主要動作\n  Given 使用者已設定有效條件\n  When 使用者提交主要動作\n  Then 畫面應顯示成功狀態\n\n# 對應 flow.md § Edge Cases: 查無結果\nScenario: 查詢條件無匹配結果\n  Given 使用者已設定有效查詢條件\n  When 系統回傳空結果集\n  Then 畫面應顯示空狀態提示"},{"emoji":"⚖️","title":"文件盤點員 (Documentation Auditor)","task":"不重新考古，而是驗證 Role 1–3 的模板契約是否履行：AI 跑 L1 覆蓋地圖與 L2 結構閘門產出 gap report，人類做 L3 抽樣簽核後更新 survey-checklist.md。","input":["legacy 檔案樹","docs/records/ 與 docs/main/ 已產出物","每條 Record 的 flow.md § Scoped Files"],"output":["docs/survey-checklist.md","四區 + 每條 Record 的 L1/L2/L3 子勾選"],"ai_recommendation":{"tool":"claude","model":"Sonnet 4.5","tier":"budget","hint":"L1/L2 自動驗證；L3 人工抽樣簽核"},"spec_summary":"展開 L2 結構閘門細項","spec_sections":[{"title":"L1 覆蓋地圖","desc":"比對 flow.md § Scoped Files：scope 內每個 .ts/.tsx 落在「被 flow 引用 / Dead Code / Unverified / 交叉引用其他 flow」四格之一。未歸屬 = 0。"},{"title":"L2 結構閘門 — flow.md","desc":"七章節齊全：Entry Points、Referenced Endpoints、Happy Path、Edge Cases、待 PM 釐清、Unverified Logic、Scoped Files。"},{"title":"L2 結構閘門 — endpoint 閉環","desc":"Referenced Endpoints 每個都有 records/endpoints/*.ts + main/contract-schemas/endpoints/*.md。"},{"title":"L2 結構閘門 — BDD 對齊","desc":"Scenario 數 ≥ 1（Happy Path）+ Edge Cases 條數；每個 Scenario comment 有對應 flow.md 章節。"},{"title":"L2 結構閘門 — transform 收攏","desc":"contract-schema 的 @old_logic_location 指向的檔案，必須出現在 Scoped Files。"},{"title":"L3 人工抽樣","desc":"見本節下方「L3 人工抽樣清單」。靜態頁只需 L1；Endpoints 只需 L2。"}],"spec_code":"## Flows\n- [ ] booking-flow\n  - [ ] L1 覆蓋地圖：0 未歸屬檔案\n  - [ ] L2 結構閘門：5/5 通過\n  - [ ] L3 抽樣：3/3 通過（YYYY-MM-DD by @reviewer）\n\n## Endpoints\n- [x] post-reservation.ts — L2 通過\n\n## Static Pages\n- [x] /faq — L1 通過\n\n## Global Constraints\n- [ ] session-expiry — L2 + L3 待驗"}]},"s4":{"emoji":"🔄","heading":"核心考古盤點流程與執行 SUPPLEMENT","subheading":"三類考古產物的優先序與盤點深度。商務不確定項於考古期標記，盤點凍結後經 Docusaurus 與 PM 對齊。","example_callout":"⚠️ 以下「已知例子」來自目前對專案的認知，實際 flow 清單與命名於考古階段依 codebase 定義。","pm_clarification_heading":"商務不確定項的三層處理","pm_clarification_items":["考古期：code 謎團 → flow.md § Unverified Logic；商務意圖／場景不明 → flow.md § 待 PM 釐清","盤點凍結 → Docusaurus：彙整所有「待 PM 釐清」至 Open Questions 專區","PM 對齊後：討論通過寫入 main/ To-be；仍不確定者留 TODO + 上線 log"],"card_scope_label":"範圍","card_standard_label":"盤點標準","table_cols":["類別","優先級","範圍","盤點標準"],"table_rows":[{"category":"核心業務流程 (Core Domain Flows)","priority":"最高優先","priority_type":"emerald","scope":"跨頁面、有完整 User Journey 的流程（考古時依 codebase 定義）。已知例子：訂票主流程、搜尋篩選、Email 深連結入口的 Coupon 流程。","standard":"須跑完四角色 pipeline + Role 4 三層檢核。產出 flow.md + contract-schemas + BDD；商務不確定項標入「待 PM 釐清」。"},{"category":"靜態與內容頁面/區塊 (Static & Content)","priority":"簡化盤點","priority_type":"blue","scope":"導覽頁、FAQ、Top Page 區塊等（無 CMS，存於前端翻譯檔）。Affiliate 介紹頁（導向外部表單，站內無完整任務）亦屬此類。","standard":"不需 schemas 與 BDD。於 docs/main/pages/ 列出頁面區塊與 i18n key 即可。"},{"category":"全域設施與約束 (Global Infrastructure)","priority":"收攏 global-constraints","priority_type":"indigo","scope":"驗證狀態有效期限（Session 生存週期）、錯誤嘗試次數限制（防刷提示）、全域狀態與 URL 同步（語系貨幣在網址上的重新整理）","standard":"跨頁面橫切邏輯。收攏至 docs/records/global-constraints/e2e-cases.feature；須跑 Role 4 L2 + L3。"}]},"s5":{"emoji":"🔒","heading":"變更管理 ＆ Scope 凍結","subheading":"兩道關卡：盤點凍結（技術完備）→ Scope 凍結（PM 決策）。帶 spec 與 Figma 與 PM 確認後，從「暫時不會改」的區塊開始翻修。","freeze_callout":"checklist 100% → 盤點凍結 → 產出 Docusaurus。帶 spec + Figma 找 PM 做 Scope 凍結：哪些區塊可先翻修、哪些待後續再對齊。開工從 PM 確認暫時不會修改的部分開始。","two_gates_heading":"兩道凍結關","two_gates_cols":["關卡","觸發條件","產出"],"two_gates_rows":[{"gate":"盤點凍結","trigger":"survey-checklist 100%","output":"Docusaurus 可發布；Open Questions 彙整完畢"},{"gate":"Scope 凍結","trigger":"PM 對 spec + Figma 完成逐區塊決策","output":"每條 flow／頁面標記「可先翻修」或「待後續對齊」"}],"phase1_title":"第一階段（考古期）","phase1_items":["records/ 記錄 As-is；main/ 累積 To-be contract-schemas。","flow.md 標記「待 PM 釐清」與 Unverified Logic。","checklist 達 100% → 盤點凍結，整理 Docusaurus（含 Open Questions）。"],"phase2_title":"第二階段（PM 對齊期）","phase2_items":["帶 Docusaurus spec 與 Figma As-is 稿（詳見 s6）找 PM 逐區塊確認——含「待後續對齊」項目，兩者缺一不可。","討論：哪些維持現有邏輯、哪些要重構、哪些需要一起重想流程。","Open Questions 逐項結案，或升級為 Scope 決策。","每條 flow／頁面標記 Scope（見下方）。"],"scope_decisions_heading":"Scope 決策標記","scope_decisions_intro":"PM 對齊的核心產出。決策記錄於 Docusaurus 各頁 badge，並回寫 main/ 檔案 frontmatter（scope: stable | pending）。","scope_decisions_cols":["標記","PM 的意思","下一步"],"scope_decisions_rows":[{"label":"可先翻修","meaning":"PM 確認此區塊暫時不會修改業務邏輯或流程","next":"優先排入重構開工"},{"label":"待後續對齊","meaning":"PM 表示此區塊日後會調整、重構或重想流程","next":"第一輪仍須 spec + Figma As-is 供 PM 決策；暫緩開工與 To-be 設計。待「可先翻修」完成後，第二輪再帶更新 spec + Figma 與 PM 討論"}],"phase3_title":"第三階段（重構開工期）","phase3_items":["從 Scope 標記為「可先翻修」的區塊開始開發；不動「待後續對齊」項目。","「待後續對齊」項目：其餘翻修告一段落後，再與 PM 重新討論並更新 spec + Figma。","Feature Branch 修改 docs/main/（To-be）；PR 附 CHANGELOG.md（Ticket Link + 變更文件）。","代碼上線時文件一併 Merge，確保「代碼即文件，文件即代碼」。"]},"s6":{"emoji":"🧱","heading":"Figma 設計系統與三層 Token 架構","subheading":"服務 s5 PM 對齊：spec 與 Figma As-is 成對出現。考古期不動 Figma；盤點凍結後建 As-is 畫布，Scope 凍結後「可先翻修」項目才更新 To-be。","timeline_heading":"Figma 四段時程（對齊 s5）","timeline_steps":["① 考古期：前端不碰 Figma。可選——請設計師以新 Token 架構先行同步 production site（As-is 還原），與 code 考古平行。","② 盤點凍結後：依 spec 建／補齊 Figma As-is 畫布（100% 對正式環境），與 Docusaurus 產出平行。","③ PM 對齊期：所有 flow／頁面（含待後續對齊）均需 spec + Figma As-is 一起找 PM 確認。","④ 重構開工：僅「可先翻修」項目更新 Figma To-be；「待後續對齊」維持 As-is，第二輪 PM 討論後再改。"],"pm_deliverable_callout":"PM 對齊的最低交付：每條 flow 關鍵畫面 + 靜態頁區塊，spec（Docusaurus）與 Figma As-is 缺一不可。","kit_callout":"Figma 起點：以 Obra shadcn/ui kit 為社區模板（https://obra.studio/work/figma-shadcn-ui-kit/），複製至各專案本地後覆寫 Token 與 As-is 畫布，不從零自建元件庫。Code 端搭配 shadcn/ui CLI。","intro_p1":"多產品「孤島式維護」：Figma Professional 無法跨檔案 Variables 連動，改採「中央範本（Obra kit + shadcn 組件），本地清洗」——複製模板、映射品牌色、還原 As-is 畫布。","intro_p2":"Token 三層與 Obra／shadcn 哲學一致：底層 Raw 用 Tailwind palette 命名；Brand 建 100–900 漸層；Semantic 對齊 shadcn 並收斂業務專用色。畫布只綁 Semantic。","pro_warning":"⚠️ 建立 Figma Variables 至少需要 Pro plan 的 Full seat（非 Collab seat）。","token_rule":"三層 Token 物理隔離：畫布上只能且必須使用 Semantic Token。Raw（Tailwind palette）與 Brand（100–900 漸層）禁止直接綁定畫布。","token_cols":["層級 (Layer)","命名規範","代碼端對照","設計師權限"],"token_rows":[{"layer":"1. Raw / Primitives 🔒","figma":"Tailwind CSS palette 同名（如 slate-500、blue-600、neutral-100）","css":"tailwind.config / @theme 底層色票","access":"❌ 禁止直接綁定畫布。色彩大字典。"},{"layer":"2. Brand 🔒","figma":"網站品牌色 100–900 漸層（如 brand-blue-100、brand-orange-500）","css":"theme 定義 brand scale；上畫布時經 Semantic alias 暴露（如 --brand-pink）","access":"❌ 禁止直接綁定畫布。"},{"layer":"3. Semantic 🔓","figma":"shadcn 標準（background、primary、muted…）+ 業務語意（如 link、brand-pink）","css":"globals.css :root — shadcn 內建（--background、--primary…）+ 自訂（--link、--brand-pink）","access":"🔓 唯一合法。自 Raw 或 Brand 選色綁定。"}],"token_semantic_heading":"Semantic 層規則","token_semantic_rules":["優先使用 shadcn 內建 semantic（background、foreground、primary、muted、destructive…）。","Semantic 色值來源：從 Raw（Tailwind palette）或 Brand（100–900）選取並建立 alias。","shadcn 未涵蓋的 brand／業務色：在 Semantic 層命名（如 link、brand-pink），於 globals.css :root 新增 CSS variable，值指向 Brand 或 Raw。","Figma Semantic Variables 與 :root 變數名 1:1 對齊（follow shadcn/ui CLI 慣例）。"],"fold_org_content":"中央 Workspace → Obra shadcn/ui kit 範本（Raw Tailwind palette + shadcn 標準組件）。各專案本地 → 複製 kit、覆寫 Brand 漸層與 Semantic mapping、100% 還原 As-is 畫面。","fold_pattern_central":"中央維護：100% 業務邏輯視覺一致、絕無客製化可能（如日本地圖選區）→ Copy-Paste。","fold_pattern_local":"本地維護：會因產品線改變語意的複合組件（如 BookingCard、CouponSelector 等）→ 中央 shadcn 基礎 + 本地組裝。","fold_align_desc":"Figma 畫布只放英文可讀文案（公司網站主語系為 EN），不放 i18n key，也不用 Variables Mode 維護翻譯。","fold_align_rules":["Description 可放設計備註（非 key）：動態文案（API 回傳）、占位符／字數上限、truncation 風險、PM 文案待定、或連結 Docusaurus spec 章節。","Sticky／Comment 僅供 PM 對齊期討論，不作長期 SSOT。","i18n key 與多語對照：legacy 考古 → JSON → Google Sheet → code（見 s7）；靜態頁另在 docs/main/pages/ 列區塊 + key。重構時以「畫面 + spec／Sheet」對照，不靠 Figma 反查 key。"],"fold_align_example":"畫布：\"Please enter your booking code\" → Description：「預約碼 placeholder；靜態文案；詳見 booking flow spec §2」——而非 booking.field.code_placeholder。"},"s7":{"emoji":"🌍","heading":"多國語系 (i18n) 全自動管線 (Pipeline)","figma_boundary":"Figma 只展示英文可讀文案（主語系 EN），不作 i18n SSOT。key 與多語翻譯以考古 JSON → Sheet → code 為準；設計稿 Description 僅放設計語意備註（見 s6）。","sheet_ssot":"考古期 legacy 各語系翻譯已存在——整理只做格式清洗、namespace／key 重命名、status 標記，不重新翻譯。寫入 Sheet 時 en／ja／zh_TW 等欄位應已帶齊，Sheet 即完整對照表。","toolchain_note":"工具鏈：考古用 Claude Web 產出整理 JSON，翻新用 Cursor。目標框架 i18next → next-intl，格式依 next-intl 慣例調整；status 標 unused／in-progress。","gemini_rule":"Gemini 非考古必經步驟：Sheet 已含 legacy 全語系。僅在 refactor 新增 key（in-progress）或人工委託補譯時，可透過 Gemini 操控 Sheet；Instruction Sheet 放 Tone Guide 供補譯參考。","iron_rule":"System Prompt 級別全域鐵律：若需要的翻譯在 JSON 中不存在，嚴禁自行發明新 Key。請先代碼中 Hardcode 並加上 // TODO: i18n-missing 標記批次提取。","migration_heading":"i18next → next-intl 整理規則","normalize_rules":["框架遷移：自 i18next 結構整理為 next-intl 慣例（namespace + key、JSON／message 格式依 next-intl 同步腳本輸出）。","多餘空白不主動清除——legacy 可能為排版刻意保留，整理時原樣帶入 Sheet。","換行合併：legacy 以陣列 [a, b, c] 分句再 map 渲染者，整理為單一 key 內 \\n 換行（例：\"Line one\\nLine two\\nLine three\"），方便譯者在同一欄位編輯。","插值語法：考古整理時 i18next {{var}} 直接轉 next-intl {var}，寫入 Sheet 即為終態；sync script 只做讀寫不負責格式轉換，以便未來可重複使用。","Code 端：含 \\n 的文案用 CSS whitespace-pre-line（或等效）渲染，不再在元件內 map 陣列分句。"],"namespace_heading":"Namespace 切法","namespace_rules":["單一 domain 專案：以「頁面／畫面」為 namespace 單位，不加 -page 後綴（如 checkout、affiliate-intro）。","跨頁共用文案 → common；各頁只引用自己 namespace + common。Flow 不另設 namespace——flow 內各步驟畫面各自吃對應頁面的翻譯。","slug 對齊 docs/main/pages/、Figma frame 名稱與路由 Entry screen，整理時 legacy_key 保留舊名供比對。"],"fold_json_content":"JSON 格式範例：status, namespace, key, legacy_key, en, ja, zh_TW, description。\n\n各語系值自 legacy translations 帶入（非空殼待翻）。例：namespace checkout + key coupon.btn.apply；legacy_key 供 script 比對缺漏。","sync_heading":"Sheet → code 輸出結構","sync_rules":["依 namespace 拆檔：messages/{locale}/{namespace}.json（如 messages/en/common.json、messages/en/checkout.json）。","檔內 JSON 巢狀（如 { \"coupon\": { \"btn\": { \"apply\": \"…\" } } }）。Sheet 的 key 欄仍用 dot notation（coupon.btn.apply）方便編輯；sync script 寫入 code 時展開為巢狀。","Sheet namespace 欄位與檔名 1:1；頁面用 useTranslations('{namespace}') + t('coupon.btn.apply')；common 跨頁共用。"],"steps":["AI 整理 legacy 翻譯為 JSON（i18next → next-intl；{{var}} → {var}；陣列換行合併為 \\n；不 trim 多餘空白）","Script 比對 legacy_key 與原 translations，檢查缺漏（動態 key 需手動標 active）","Script 寫入 Google Spreadsheet（單一 sheet + namespace 欄位；各語系欄位已帶齊）","新專案 sync script：Sheet → messages/{locale}/{namespace}.json（dot key 轉巢狀 JSON；unused 過濾、in-progress 顯示 🚧）","SKILL.md 鐵律：缺 key 禁止自創，hardcode + // TODO: i18n-missing；新增 key 標 in-progress 後再補譯"]},"s8":{"emoji":"🏁","heading":"盤點、校對與開始翻新","validation_heading":"平行對照與翻新門檻","validation_items":["新舊專案放同一個 workspace 方便前後對照。","含 \\n 的多行文案：前端用 CSS whitespace-pre-line（見 s7 換行合併規則），不再 map 陣列分句。","盤點凍結後，依 records/ + main/ 盤點文件整理 Docusaurus 格式，起獨立 repo 部署，與 PM 對齊（工作目錄本身不直接給 PM 看）。"],"gate_heading":"Phase 3 開工與驗收（三段）","gate_project_heading":"1. 專案級（Phase 3 開工前，只做一次）","gate_project_items":["盤點凍結（survey-checklist 100%）","Docusaurus 已整理並部署","Figma As-is 100% 就緒（盤點凍結後與 Docusaurus 並行完成，Scope 凍結前置）","Scope 凍結完成：每條 flow／頁面標記可先翻修或待後續對齊","待後續對齊項目第一輪仍須 spec + Figma As-is，但不進入開工池"],"gate_issue_heading":"2. 單一 Issue／垂直切片（僅可先翻修）","gate_issue_cols":["Issue 類型","開工前最低要求"],"gate_issue_rows":[{"type":"Schema / Transformer / 純函數","requirement":"flow.md + main/contract-schemas/ 規格即可 → TDD 開工"},{"type":"UI 元件／頁面","requirement":"同上 + 該區塊 Figma To-be（可先翻修項目）"},{"type":"Flow（有 BDD）","requirement":"Happy Path Scenarios 已寫；待 PM 釐清／Unverified Logic 維持註解、不寫 Scenario"},{"type":"Static Pages","requirement":"docs/main/pages/ 區塊 + i18n key 列表即可，不要求 BDD"}],"gate_merge_heading":"3. 合併／上線前（驗收，非開工門檻）","gate_merge_items":["該切片 BDD 全綠（有寫 Scenario 的 flow）","AI L1/L2 結構檢核 + 人工 L3 spot-check（見 s3）","PM 對該可先翻修區塊 sign-off（Docusaurus spec + Figma To-be 對照）"],"log_rule_heading":"Unverified Logic 觀測鐵律","log_rule":"重構時邏輯行為須與 legacy 對齊。flow.md § Unverified Logic 所列分支，refactor 版必加 runtime log 觀測是否仍被觸發——禁止 silent 刪除或略過。","log_rule_items":["考古期已標記的 Unverified Logic：保留等價分支並加 log（引用 flow.md 檔案位置）。","觀測期跑一陣子無任何 hit → 可刪除分支，並更新 flow.md § Scoped Files。","refactor 中新發現無法解釋的分支：先補標 flow.md § Unverified Logic 再加 log，不得直接移除。"],"skills_heading":"Issue 拆分與 Matt Pocock Agent Skills","skills_subheading":"拆 Issues 導入 5 大 Agent Skills。活用 monorepo 特性整合。Issue 並行任務。","skills_cols":["Skill","說明","建議 AI","階段"],"skills_rows":[{"name":"Grill-with-Docs","desc":"結合考古文件，沿設計樹逐項釐清決策分支","ai":"Claude Opus 4.6","phase":"規劃"},{"name":"To-PRD","desc":"從共識產出 PRD，含 User Stories 與模組草圖","ai":"Claude Sonnet 4.5","phase":"規劃"},{"name":"To-Issues","desc":"PRD 拆解為垂直切片 Issue，建立 blocking 關係","ai":"Claude Sonnet 4.5","phase":"規劃"},{"name":"TDD","desc":"紅綠重構循環，一行測試一行實作，確保重構不漏","ai":"Cursor Composer 2.5","phase":"開發"},{"name":"Architecture-Refactor","desc":"深化淺層模組、釐清測試邊界，讓 Agent 能穩定導航","ai":"Cursor Composer 2.5","phase":"開發"}],"refs_heading":"技術參考連結","refs":[{"label":"Stop writing docs by hand","url":"https://www.aihero.dev/5-agent-skills-i-use-every-day"},{"label":"Playwright BDD","url":"https://playwright.dev/docs/test-agents"}],"issues_heading":"原子化 Issue 範例","issues":[{"id":"#01","tag":"Schema","title":"實作 transformBookingAmount 純函數","blocks":"可先翻修 + flow.md／schema 到位即可開工"},{"id":"#02","tag":"UI","title":"依據 Figma To-be 實作 BookingCard 靜態元件","blocks":"阻塞於 #01；需該區塊 To-be 稿"},{"id":"#03","tag":"BDD","title":"撰寫預約代碼驗證 Edge Cases 驗收案例","blocks":"可與 #01 平行；合併前需 BDD 綠"}],"roadmap_heading":"Roadmap","roadmap":[{"title":"Phase 1：考古與盤點凍結","desc":"四角色 Skills → records/ + main/ → checklist 100%（盤點凍結）。接續並行產出 Docusaurus 與 Figma As-is（s6 ②，100% 對正式環境）——兩者皆就緒才進 Phase 2。考古期 ① 可選 kit 同步。"},{"title":"Phase 2：Scope 凍結","desc":"前置已滿足：Docusaurus spec + Figma As-is 雙齊。PM 成對確認每條 flow／頁面，標記可先翻修／待後續對齊（s6 ③）。","risk":"🔥 風險控制點：Figma As-is 未完成不得進 PM 對齊"},{"title":"Phase 3：重構開工","desc":"專案級 + Issue 門檻通過後，僅可先翻修垂直切片開工；Figma To-be 隨 UI Issue 增量更新（s6 ④）。合併前 BDD + L3 + PM sign-off。"}],"roadmap_note":"Figma As-is 不是 refactor 才做——是 Phase 2 PM 對齊的硬性前置，與 Docusaurus 在盤點凍結後並行完成。"},"s9":{"emoji":"🛡️","heading":"API 資料邊界：不用 BFF，Zod + Transformers","subheading":"參考《前後端職責拆分與 BFF 設計》討論後的結論：不另建 BFF，前端 fetch Core API 後以 Zod 做 runtime 驗證與資料正規化（Parse, don't validate）。與 s3 資料邊界規劃師產出的 contract-schemas 對齊。","decision_callout":"不建 BFF 層——少一層 infra 與部署成本。前端 `httpClient` 直連後端，在 client 端用 Zod Schema + Transformer 收斂 legacy 怪格式，元件只接 Clean Type。","layers_heading":"三層防線","layers_cols":["層級","職責","產物"],"layers_rows":[{"layer":"1. Upstream（考古）","role":"Role 1 從 codebase 推測後端 Raw 結構","artifact":"docs/records/endpoints/[endpoint-name].ts"},{"layer":"2. Contract（規格 SSOT）","role":"Role 2 定義 Frontend Interface + Transformer 原型","artifact":"docs/main/contract-schemas/endpoints/[name].md"},{"layer":"3. Runtime（程式碼）","role":"refactor 實作 Zod parse + transform + handleResponse","artifact":"lib/api/[endpoint-name]/{schema,transformer,index}.ts"}],"runtime_heading":"Runtime 模式（client-side normalization）","runtime_steps":["httpClient fetch Core API → 取得 unknown","Zod Backend*Schema.safeParse — 攔截 HTML／非 JSON／欄位漂移（ApiProtocolError）",".transform() 轉成前端 Clean Type（snake_case、語意欄位、剔除冗餘）","統一 ApiResponseSuccess / ApiResponseError envelope — 業務錯誤抛 ApiBusinessError","React／Store 只 import Clean Type，禁止直接碰 Raw JSON"],"error_heading":"Error 分類","error_cols":["類型","觸發","處理"],"error_rows":[{"type":"ApiProtocolError","trigger":"非 JSON、HTML 錯誤頁、Zod parse 失敗","handling":"log + 統一錯誤 UI；對應 s1「error 格式不統一」根因"},{"type":"ApiBusinessError","trigger":"後端回 { error: { code, message } }","handling":"依 code 分支；不再在元件內通靈判斷"}],"proto_heading":"原型參考（backend/ — 已暫停）","proto_intro":"曾依上述模式實作多支 endpoint（get-bus-list、get-locations、submit-contact…），每支含 schema.ts（Backend + Clean）、transformer.ts、index.ts，共用 handleResponse 與 contract.ts。","proto_structure":["backend/[endpoint-name]/schema.ts — Backend*Schema（Zod）+ Clean Type","backend/[endpoint-name]/transformer.ts — request／response transform","backend/[endpoint-name]/index.ts — httpClient + handleResponse","backend/utils/handle-response.ts — safeParse 統一入口","backend/contract.ts — ApiResponseSuccess / ApiResponseError"],"proto_pause_heading":"為何暫停","proto_pause_items":["endpoint 數量成長後，資料夾之間容易迷路——缺少與 flow／考古產物的命名對照 SSOT","Backend 命名（PascalCase、嵌套 XML 風格）與前端 Clean 命名難以跨 API 對齊","shared entity（如 BusFacilities）與各 endpoint 邊界不清，重複定義風險"],"plan_bridge_heading":"翻新計畫如何接續","plan_bridge_items":["考古期：records/endpoints/[name].ts 與 flow.md § Referenced Endpoints 1:1 — endpoint 清單不再靠腦記","規劃期：contract-schemas/endpoints/[name].md 為命名與 Transformer 的 SSOT；shared/ 收斂跨 endpoint entity","code 目錄 slug 對齊 contract-schemas 檔名（如 get-bus-list），一 endpoint 一資料夾","第一條 vertical slice 定 golden sample（含 Zod + test）；後續 endpoint 複製結構不重複發明","Role 2 開工前必查 contract-schemas/shared/，禁止重複定義同一 entity"],"bff_note":"BFF 討論中曾評估的地點搜尋、7k 筆快取等——多數可在前端 IndexedDB + 本地 filter 完成；僅少數地理運算場景才需後端。預設路線仍是 client-side transformer，非另開 BFF service。"},"footer":{"text":"Project Renovation & Refactor Plan"}},"en":{"meta":{"title":"Full Project Renovation: AI-Driven Agile Archaeology & Refactoring Plan"},"common":{"label_input":"Input","label_output":"Output","fold_specs":"Expand detailed specification requirements","fold_doc_tree":"📂 Click to expand: Archaeology working directory (records/ + main/, Agent writes here)","fold_figma_org":"Organization: Central template, local customization","fold_figma_pattern":"Business module maintenance boundaries","fold_figma_align":"Figma copy vs. i18n boundary","fold_i18n_json":"🔍 View: i18n data types & script specification details","fold_i18n_steps":"Full translation prep steps ({n} steps total)","fold_deliverables":"Deliverables","tier_budget":"Budget","tier_required":"Required","tier_context":"Context","tier_human":"Human","tool_claude":"Claude","tool_cursor":"Cursor","tool_human":"Human","audit_layers_label":"Archaeology verification three layers (Role 4)","issue_tag_legend_heading":"Issue type tags","issue_tag_legend":[{"tag":"Schema","meaning":"Data boundary / Transformer / pure function"},{"tag":"UI","meaning":"Component or page; requires Figma To-be"},{"tag":"BDD","meaning":"Flow acceptance cases; must be all green before merge"}],"glossary":{"L1":{"short":"Coverage map","tip":"Compare flow.md § Scoped Files: every .ts/.tsx in scope has an assignment. AI auto-verifies; unassigned files = 0."},"L2":{"short":"Structure gate","tip":"Flow seven sections, endpoint closure, BDD alignment, transform consolidation. AI produces gap report; all green to pass."},"L3":{"short":"Manual spot-check","tip":"Randomly compare against source code to confirm archaeology content is correct, not just complete. Human sign-off; core flows recommend 5 items."},"Four zones":{"short":"survey-checklist four zones","tip":"Flows, Endpoints, Static Pages, Global Constraints — survey freeze requires all Four zones 100% checked."},"Refactor-first":{"short":"Scope tag","tip":"After Phase 2 PM alignment, marked as flows/pages ready to start immediately; Phase 3 only these enter the work pool."},"Align later":{"short":"Scope tag","tip":"spec + Figma As-is must still be ready, but refactor round one does not touch them; update To-be with PM after other renovation wraps up."},"As-is":{"short":"Current-state canvas","tip":"Figma canvas 100% matching production; hard prerequisite for Phase 2 PM alignment."},"To-be":{"short":"Target design","tip":"After refactor kickoff, only Refactor-first items get incremental updates; UI Issues need corresponding block To-be before starting."}},"s9_layers_note":"This \"three-layer defense\" refers to API data flow (Upstream → Contract → Runtime), distinct from archaeology verification L1/L2/L3."},"hero":{"title":"Full Project Renovation: AI-Driven Agile Archaeology & Refactoring Plan","subtitle":"Use AI archaeology to fill missing Specifications (steps, pages, flows), clarify API Schema from a frontend perspective and build stable Transformers, rebuild the Figma design system, and drive documented acceptance through an Agent Skills pipeline — systematically reducing design drift and technical debt."},"toc":[{"id":"s1","label":"Background"},{"id":"s2","label":"Top-Level Architecture"},{"id":"s3","label":"4-Role Workflow"},{"id":"s4","label":"Archaeology Survey"},{"id":"s5","label":"Freeze Management"},{"id":"s6","label":"Figma Design System"},{"id":"s7","label":"i18n"},{"id":"s8","label":"Kickoff"},{"id":"s9","label":"API Boundary & Zod"}],"s1":{"emoji":"🛑","heading":"Background & Current Pain Points","table_cols":["Pain Point","Impact","Root Cause"],"table_rows":[{"pain":"No specification docs","impact":"Business logic cannot be verified; high change risk","cause":"No standard documents to verify business logic; steps, pages, and flows are reverse-engineered entirely from code."},{"pain":"Messy frontend code","impact":"Extremely high fix cost","cause":"Many anti-patterns make certain framework bugs extremely hard to trace and debug."},{"pain":"No backend specs","impact":"Frontend guesswork","cause":"Backend has no spec docs — response formats cannot be accurately determined from frontend code alone, plus extra guesswork added to temporarily handle malformed backend responses. This is the upstream root cause of inconsistent error formats and scattered transforms."},{"pain":"Inconsistent error formats","impact":"Dirty logic accumulation","cause":"Inconsistent error response formats force the frontend to add messy handling logic for each variant."},{"pain":"Chaotic data naming","impact":"Hard to trace on refactor","cause":"The frontend created its own transform layer, but because it is scattered everywhere, original values are hard to find quickly during refactors."},{"pain":"Design files drift from production","impact":"UI restoration by guesswork; design iterations untraceable","cause":"Figma is not maintained in sync with the codebase; production and design files have long diverged."}],"vision_heading":"As-is Pain Points vs. To-be Vision","as_is_title":"As-is Pain Points","to_be_title":"To-be Vision","as_is_items":["No spec docs to verify business logic","Design files drift from production","Code degradation and accumulated tech debt","Difficult onboarding, high psychic cost","Chaotic backend formats, scattered frontend transforms"],"to_be_items":["Specification becomes business logic SSOT","All archaeologized business behavior has BDD acceptance cases","Figma design system synced with code","AI Agent automated dispatch + clear human-AI collaboration boundaries","Data boundary isolation; clean types replace dirty data"]},"s2":{"emoji":"🗺️","heading":"Top-Level Architecture, Doc Flow & Directory Spec","subheading":"Complete output chain from legacy codebase to survey freeze. Archaeology working data writes to records/ and main/; after survey completion, Docusaurus is produced separately for PM alignment.","example_callout":"⚠️ `[flow-name]`, `[endpoint-name]` in this section and the example lists below illustrate directory structure and split granularity only — not real flows or APIs for this project. Actual names and boundaries are defined one by one during archaeology based on existing codebase business logic.","taxonomy_heading":"Three-tier archaeology artifact taxonomy","taxonomy_intro":"Flow is not the only classification axis. Endpoint specs are orthogonal to Flow — one flow can reference multiple endpoints, and one endpoint can be shared across flows.","taxonomy_cols":["Tier","Path","Granularity","Archaeology depth"],"taxonomy_rows":[{"tier":"User Flow (Record)","path":"docs/records/flows/[flow-name]/","granularity":"One complete user task (Entry → Terminal State)","depth":"flow.md + BDD + referenced endpoints"},{"tier":"Static / Content","path":"docs/main/pages/","granularity":"One page or block","depth":"Block structure + i18n keys only; no schema / BDD"},{"tier":"Global Constraints","path":"docs/records/global-constraints/","granularity":"Cross-flow cross-cutting logic","depth":"BDD only; no standalone flow.md"}],"taxonomy_endpoint_note":"Endpoint specs (docs/records/endpoints/) are another orthogonal axis: one endpoint per file; archaeology infers upstream structure; planner produces Frontend Interface + Transformer to main/contract-schemas/endpoints/.","flow_granularity_heading":"Flow split criteria (Highway Bus service — illustrative example)","flow_granularity_rules":["Split by user task (User Journey), not by page or route.","One Record = one independently archivable complete journey (Entry Point → Terminal State).","Endpoint specs (endpoints/) and Flow (flows/) are orthogonal: one flow can reference multiple endpoints; endpoints can be shared across flows.","Independent Entry Point with complete journey → separate flow (e.g. Coupon flow via email deep link); logic triggered mid-journey in another flow (e.g. Coupon apply during booking) → write into that flow's Edge Cases.","Pages linking to external forms with no complete in-site task (e.g. Affiliate) → static page survey, no flow.","Cross-flow cross-cutting logic (session expiry, anti-abuse, URL locale sync) → consolidate to global-constraints/."],"flow_examples_note":"Below illustrates split granularity types only; [flow-name] is a placeholder, not a real flow name for this project:","flow_examples":[{"name":"[search-flow]","desc":"Search & filter (including status-driven hidden UI states)"},{"name":"[booking-flow]","desc":"Main booking flow (cross-page complete journey)"},{"name":"[coupon-email-flow]","desc":"Coupon flow via email deep link (independent Entry Point)"},{"name":"[lookup-flow]","desc":"Reservation lookup / change flows"}],"endpoint_examples_note":"Endpoint filenames below are examples; name per actual API during archaeology:","endpoint_examples":["search-routes.ts","get-seat-map.ts","post-reservation.ts","get-reservation.ts"],"diagram":"graph TD\n    Code[\"Legacy source\"] -->|Repomix bundle + Agent exploration| R1[\"🕵️ 1. Code Archaeologist\"]\n    R1 -->|As-is business behavior| Flow[\"docs/records/flows/[flow-name]/flow.md\"]\n    R1 -->|Infer endpoint response structure| Upstream[\"docs/records/endpoints/[endpoint-name].ts\"]\n    Flow --> R2[\"📐 2. Data Boundary Planner\"]\n    Upstream --> R2\n    Comp[\"Components / Store derived logic\"] --> R2\n    R2 -->|Frontend Interface + Transformer| Schema[\"docs/main/contract-schemas/endpoints/\"]\n    R2 --> Ctx[\"CONTEXT.md\"]\n    Flow --> R3[\"✍️ 3. Behavior Test Architect\"]\n    Schema --> R3\n    R3 -->|BDD cases| BDD[\"docs/records/flows/[flow-name]/e2e-cases.feature\"]\n    Flow --> R4[\"⚖️ 4. Documentation Auditor\"]\n    Schema --> R4\n    BDD --> R4\n    R4 -->|Coverage review| Check[\"docs/survey-checklist.md\"]\n    Check -->|100% Check| Freeze[\"Survey freeze\"]\n    Freeze -->|Organize survey docs| Docs[\"Docusaurus doc site\"]\n    Docs -->|PM alignment| PM[\"Business / technical change discussion\"]\n    Freeze -.->|Developer reference| Ref[\"records/ + main/ retained\"]","doc_tree_note":"Below is the working directory for archaeology and refactor — for Agent writes and developer reference during refactor; not a PM-facing format.","docusaurus_heading":"After survey completion: Docusaurus output","docusaurus_intro":"After survey-checklist reaches 100%, organize survey docs (records/ + main/ + CONTEXT.md) into Docusaurus format, build a doc site in a separate repo as the formal interface for PM alignment. main/ and records/ remain for developer use and refactor reference.","docusaurus_steps":["Use frozen survey docs as source (not writing Docusaurus during archaeology)","Skill / Script converts to Docusaurus structure (MDX, sidebar, Admonitions, etc.)","Consolidate each flow.md § Pending PM Clarification to Open Questions section","Deploy doc site in separate repo","Use this site for technical and business change discussions with PM"],"doc_tree_cols":["Path","Purpose"],"doc_tree_rows":[{"path":"CONTEXT.md","desc":"Global glossary (permanent). Continuously updated during archaeology; grill-with-docs reuses it."},{"path":"docs/survey-checklist.md","desc":"Archaeology progress tracker. Four zones + L1/L2/L3 sub-checks per Record."},{"path":"docs/records/","desc":"As-is archaeology workspace. Developer reference during refactor; retained after survey freeze, not PM-facing."},{"path":"docs/records/flows/[flow-name]/flow.md","desc":"As-is current business flow. Name defined during archaeology from codebase (placeholder: [flow-name])."},{"path":"docs/records/endpoints/[endpoint-name].ts","desc":"Single endpoint raw response structure inferred from codebase during archaeology (TypeScript type). Name defined during archaeology."},{"path":"docs/records/flows/[flow-name]/e2e-cases.feature","desc":"BDD test cases."},{"path":"docs/main/flows/","desc":"Verified As-is flows; To-be SSOT foundation during refactor. Developer reference."},{"path":"docs/main/pages/","desc":"Page logic survey. Developer reference."},{"path":"docs/main/contract-schemas/shared/","desc":"Global Entities (To-be). Developer reference."},{"path":"docs/main/contract-schemas/endpoints/","desc":"Frontend Interface + Transformer (To-be). Developer reference."}]},"s3":{"emoji":"🛠️","heading":"Producing Data via Skills Workflow","subheading":"Four roles with core tasks and precise I/O. Technical specs in collapsible drawers; Role 4 three-layer audit flow in dedicated section below.","auditor_heading":"Documentation audit three-layer verification flow","auditor_intro":"Role 4 does not re-archaeologize — it verifies whether Roles 1–3 fulfilled template contracts. \"No missing files\" and \"no missing details\" are handled separately: L1/L2 can be auto-verified; L3 is human spot-check against source code.","auditor_diagram":"flowchart TD\n    Draft[\"① AI draft checklist\"] --> L1[\"② L1 Coverage map<br/>unassigned files = 0\"]\n    L1 --> L2[\"③ L2 Structure gate<br/>template + cross-refs\"]\n    L2 --> Gap[\"④ gap report\"]\n    Gap --> L3[\"⑤ L3 Manual spot-check<br/>compare source code\"]\n    L3 --> Check[\"⑥ survey-checklist check\"]\n    Check --> Freeze[\"Four zones 100% → Freeze\"]","auditor_workflow_heading":"Actual execution steps per Record","auditor_workflow_steps":["AI drafts survey-checklist.md Four zones items from legacy file tree and existing artifacts.","AI runs L1: compare flow.md § Scoped Files, confirm every .ts/.tsx in scope has an assignment; unassigned files = 0.","AI runs L2: check flow seven sections complete, Referenced Endpoints closure (upstream .ts + contract-schema .md), BDD Scenarios aligned with flow.md, @old_logic_location appears in Scoped Files.","Produce gap report listing failures; if not all green, return to corresponding Role for fixes.","Human reviews gap report, performs L3 spot-check for that Record (see list below).","L1 + L2 + L3 all pass → check that Record; all Four zones checked → Phase 1 freeze."],"auditor_layers_heading":"Three-layer audit definitions","auditor_layers_cols":["Layer","What to check","Executor","Pass condition"],"auditor_layers_rows":[{"layer":"L1 Coverage map","checks":"Whether every legacy file in scope has an assignment","who":"AI","pass":"unassigned files = 0"},{"layer":"L2 Structure gate","checks":"flow template, endpoint closure, BDD alignment, transform consolidation","who":"AI","pass":"gap report all green"},{"layer":"L3 Manual spot-check","checks":"Randomly compare source code; confirm content is correct, not just complete","who":"Human","pass":"all spot-check items pass (core flows recommend 5)"}],"auditor_spotcheck_heading":"L3 manual spot-check list (per Flow Record)","auditor_spotcheck_items":["Randomly pick 1 Edge Case → compare original component if-else, confirm flow.md description is correct.","Randomly pick 1 @old_logic_location → confirm transformer logic is consolidated, nothing missed.","Randomly pick 1 Unverified Logic → confirm truly cannot be explained from code (not a lazy tag).","(Core business flow extra) Pick 1 more Happy Path step + 1 Referenced Endpoint field semantics."],"checklist_heading":"survey-checklist.md Four zones structure","checklist_intro":"Different archaeology artifact types have different pass standards. Each checkbox must include L1/L2/L3 sub-checks to avoid \"has docs but not verified\".","checklist_cols":["Zone","Check unit","Pass standard","Audit depth"],"checklist_rows":[{"area":"Flows","unit":"Each [flow-name] Record","standard":"flow.md (incl. Pending PM Clarification) + e2e-cases.feature + referenced endpoints all have contract-schemas; BDD aligned with flow.md","depth":"L1 + L2 + L3"},{"area":"Endpoints","unit":"Each [endpoint-name].ts","standard":"Corresponding main/contract-schemas/endpoints/[name].md exists and references upstream","depth":"L2"},{"area":"Static Pages","unit":"Per page","standard":"main/pages/ has blocks + i18n key list (no BDD required)","depth":"L1"},{"area":"Global Constraints","unit":"Whole package","standard":"global-constraints/e2e-cases.feature covers cross-cutting logic listed in s4","depth":"L2 + L3"}],"checklist_example_note":"Below is checklist entry format example (abstract illustration):","roles":[{"emoji":"🕵️","title":"Code Archaeologist","task":"Map the legacy system's current state (As-is): distill pure business behavior, infer related endpoint response structures and all possibilities from codebase, exclude dead code.","input":["Repomix-bundled codebase","Specified flow-related route / component scope"],"output":["docs/records/flows/[flow-name]/flow.md","docs/records/endpoints/[endpoint-name].ts","CONTEXT.md (incremental glossary update)"],"ai_recommendation":{"tool":"claude","model":"Sonnet 4.5","tier":"budget","hint":"Batch archaeology for large file sets"},"spec_summary":"Expand flow.md template requirements","spec_example_note":"Abstract example below illustrates section structure only — not real flows or endpoints for this project.","spec_sections":[{"title":"### Entry Points","desc":"Which pages / routes / homepage blocks can enter this flow. Homepage spec only notes reference; behavior details written here."},{"title":"### Referenced Endpoints","desc":"List of endpoints/[name].ts this flow involves, as index to the orthogonal endpoint axis."},{"title":"### Happy Path","desc":"Minimal user success operation steps."},{"title":"### Edge Cases","desc":"All business logic branches in code (excluding network outage and other infrastructure errors)."},{"title":"### Pending PM Clarification","desc":"Unclear business intent or scenario: code shows behavior but not \"why\" or correct rules. Note source location and question; after survey freeze, align with PM via Docusaurus Open Questions."},{"title":"### Unverified Logic","desc":"Code mystery: branches written but never hit, cannot reproduce or explain. Note source file location; defer to production log verification or backend confirmation (not PM business questions)."},{"title":"### Scoped Files (Coverage map)","desc":"Required before Record archive. Every .ts/.tsx in scope must have assignment: referenced by flow section, Dead Code (with reason), Unverified Logic, or cross-reference to another flow. unassigned files = 0 before handing to Role 4."}],"spec_code":"# [flow-name]\n\n### Entry Points\n- `/some-list-page` — User enters from list page option\n- `/landing#quick-action` — Homepage block as shortcut entry to this flow\n\n### Referenced Endpoints\n- `endpoints/search-items.ts` — Query and filter\n- `endpoints/submit-action.ts` — Submit main action\n\n### Happy Path\n1. User sets required conditions\n2. System displays selectable results\n3. User completes main action and sees success state\n\n### Edge Cases\n- Show empty state when no results found\n- Block next step when conditions not met\n\n### Pending PM Clarification\n- Should certain identity types have different discount rules? Code has branch but no business explanation (`src/legacy/Pricing.tsx:120`)\n\n### Unverified Logic\n- `src/legacy/foo.ts:88` — Branch never triggered, reason unknown\n\n### Scoped Files\n| File | Assignment |\n|---|---|\n| src/pages/Booking.tsx | Happy Path + Edge Cases |\n| src/utils/legacyCoupon.ts | Edge Cases: coupon expired |\n| src/deprecated/oldFlow.ts | Dead Code (confirmed no route reference) |\n| src/hooks/useMystery.ts | → Unverified Logic |\n\n---\n# endpoints/submit-action.ts (same Record output, abstract example)\n\n/** @endpoint POST /api/some-action */\ninterface RawActionResponse {\n  /** Field semantics pending confirmation; may not be literal meaning */\n  status_code: string;\n  payload: unknown;\n}"},{"emoji":"📐","title":"Data Boundary Planner","task":"Starting from archaeology upstream output, define To-be Frontend Interface and consolidate transform logic scattered in components and Store into Transformers. Does not touch live API directly.","input":["docs/records/flows/[flow-name]/flow.md","docs/records/endpoints/[endpoint-name].ts","Legacy component / store transform fragments to consolidate","Existing docs/main/contract-schemas/shared/"],"output":["docs/main/contract-schemas/endpoints/[endpoint-name].md","(if needed) docs/main/contract-schemas/shared/[entity].md","CONTEXT.md (incremental glossary update)"],"ai_recommendation":{"tool":"claude","model":"Opus 4.6","tier":"required","hint":"High type precision required"},"spec_summary":"Expand contract-schema template requirements","spec_example_note":"Abstract example below — not real APIs or fields for this project.","spec_sections":[{"title":"Upstream Schema (references records/endpoints/)","desc":"Use Role 1 .ts output as SSOT; note field semantic ambiguity and known backend quirks."},{"title":"Target TypeScript Interface","desc":"To-be clean frontend types. JSDoc notes @upstream_source and @old_logic_location."},{"title":"Transformer Pure Functions","desc":"Executable TypeScript transform function prototypes consolidating derived calculations from components / store."}],"spec_code":"/** @upstream_source records/endpoints/submit-action.ts */\n\n// --- Upstream (references archaeology artifact, summary) ---\n// status_code: string  — Not HTTP status; business status code\n\n// --- Target Interface ---\ninterface ActionViewModel {\n  /** @old_logic_location src/legacy/ConfirmPanel.tsx:42 */\n  isSuccess: boolean;\n  displayMessage: string;\n}\n\n// --- Transformer ---\nfunction transformActionResponse(raw: RawActionResponse): ActionViewModel {\n  return {\n    isSuccess: raw.status_code === 'OK',\n    displayMessage: raw.payload?.message ?? '',\n  };\n}"},{"emoji":"✍️","title":"Behavior Test Architect","task":"Convert flow.md business logic into implementation-decoupled BDD cases, keeping traceable alignment with flow.md sections.","input":["docs/records/flows/[flow-name]/flow.md","docs/main/contract-schemas/endpoints/ + shared/"],"output":["docs/records/flows/[flow-name]/e2e-cases.feature"],"ai_recommendation":{"tool":"claude","model":"Sonnet 4.5","tier":"budget","hint":"Structured BDD output"},"spec_summary":"Expand BDD template requirements","spec_example_note":"Abstract example below — not real scenarios for this project.","spec_sections":[{"title":"Gherkin syntax","desc":"Must use Given-When-Then syntax."},{"title":"Coverage aligned with flow.md","desc":"At least one Scenario for Happy Path; at least one Scenario per Edge Case. Comment above each Scenario notes corresponding flow.md section."},{"title":"Pending PM Clarification / Unverified Logic — no Scenarios","desc":"Business pending items and code mysteries are not written as Scenarios; list separately in feature file top comments, referencing flow.md sections."},{"title":"Exclude infrastructure errors","desc":"404/500/network outage handled by global Client — not written in Feature file."}],"spec_code":"# Pending PM Clarification (references flow.md § Pending PM Clarification):\n# - Certain identity discount rules pending confirmation\n\n# Pending log verification (references flow.md § Unverified Logic):\n# - src/legacy/foo.ts:88 — Branch never triggered\n\n# Corresponds to flow.md § Happy Path\nScenario: User completes main action\n  Given user has set valid conditions\n  When user submits main action\n  Then screen should show success state\n\n# Corresponds to flow.md § Edge Cases: no results\nScenario: Query conditions yield no matches\n  Given user has set valid query conditions\n  When system returns empty result set\n  Then screen should show empty state message"},{"emoji":"⚖️","title":"Documentation Auditor","task":"Does not re-archaeologize — verifies Roles 1–3 fulfilled template contracts: AI runs L1 Coverage map and L2 Structure gate producing gap report; human performs L3 spot-check sign-off then updates survey-checklist.md.","input":["Legacy file tree","docs/records/ and docs/main/ existing artifacts","Each Record's flow.md § Scoped Files"],"output":["docs/survey-checklist.md","Four zones + L1/L2/L3 sub-checks per Record"],"ai_recommendation":{"tool":"claude","model":"Sonnet 4.5","tier":"budget","hint":"L1/L2 auto-verify; L3 human spot-check sign-off"},"spec_summary":"Expand L2 Structure gate details","spec_sections":[{"title":"L1 Coverage map","desc":"Compare flow.md § Scoped Files: every .ts/.tsx in scope falls into one of four buckets: referenced by flow / Dead Code / Unverified / cross-reference to another flow. unassigned = 0."},{"title":"L2 Structure gate — flow.md","desc":"Seven sections complete: Entry Points, Referenced Endpoints, Happy Path, Edge Cases, Pending PM Clarification, Unverified Logic, Scoped Files."},{"title":"L2 Structure gate — endpoint closure","desc":"Every Referenced Endpoint has records/endpoints/*.ts + main/contract-schemas/endpoints/*.md."},{"title":"L2 Structure gate — BDD alignment","desc":"Scenario count ≥ 1 (Happy Path) + Edge Case count; each Scenario comment has corresponding flow.md section."},{"title":"L2 Structure gate — transform consolidation","desc":"Files pointed to by contract-schema @old_logic_location must appear in Scoped Files."},{"title":"L3 Manual spot-check","desc":"See \"L3 manual spot-check list\" below. Static pages need L1 only; Endpoints need L2 only."}],"spec_code":"## Flows\n- [ ] booking-flow\n  - [ ] L1 Coverage map: 0 unassigned files\n  - [ ] L2 Structure gate: 5/5 passed\n  - [ ] L3 spot-check: 3/3 passed (YYYY-MM-DD by @reviewer)\n\n## Endpoints\n- [x] post-reservation.ts — L2 passed\n\n## Static Pages\n- [x] /faq — L1 passed\n\n## Global Constraints\n- [ ] session-expiry — L2 + L3 pending"}]},"s4":{"emoji":"🔄","heading":"Core Archaeology Survey Flow & Execution SUPPLEMENT","subheading":"Priority and survey depth for three archaeology artifact types. Business uncertainties marked during archaeology; after survey freeze, align with PM via Docusaurus.","example_callout":"⚠️ \"Known examples\" below reflect current project understanding; actual flow list and naming defined during archaeology from codebase.","pm_clarification_heading":"Three-layer handling of business uncertainties","pm_clarification_items":["Archaeology phase: code mysteries → flow.md § Unverified Logic; unclear business intent / scenario → flow.md § Pending PM Clarification","Survey freeze → Docusaurus: consolidate all \"Pending PM Clarification\" to Open Questions section","After PM alignment: approved items written to main/ To-be; still uncertain items left as TODO + production log"],"card_scope_label":"Scope","card_standard_label":"Survey standard","table_cols":["Category","Priority","Scope","Survey standard"],"table_rows":[{"category":"Core Domain Flows","priority":"Highest","priority_type":"emerald","scope":"Cross-page flows with complete User Journey (defined from codebase during archaeology). Known examples: main booking flow, search & filter, Coupon flow via email deep link.","standard":"Must complete four-role pipeline + Role 4 three-layer audit. Produce flow.md + contract-schemas + BDD; mark business uncertainties as \"Pending PM Clarification\"."},{"category":"Static & Content Pages","priority":"Simplified survey","priority_type":"blue","scope":"Nav pages, FAQ, Top Page blocks, etc. (no CMS, stored in frontend translation files). Affiliate intro pages (link to external forms, no complete in-site task) also belong here.","standard":"No schemas or BDD. List page blocks and i18n keys in docs/main/pages/."},{"category":"Global Infrastructure","priority":"Consolidate global-constraints","priority_type":"indigo","scope":"Auth state validity period (session lifecycle), error attempt limits (anti-abuse prompts), global state & URL sync (locale/currency refresh in URL)","standard":"Cross-page cross-cutting logic. Consolidate to docs/records/global-constraints/e2e-cases.feature; must run Role 4 L2 + L3."}]},"s5":{"emoji":"🔒","heading":"Change Management & Scope Freeze","subheading":"Two gates: survey freeze (technically complete) → Scope freeze (PM decisions). After confirming spec and Figma with PM, start renovation from blocks \"temporarily not changing\".","freeze_callout":"checklist 100% → survey freeze → produce Docusaurus. Bring spec + Figma to PM for Scope freeze: which blocks are Refactor-first, which Align later. Start work from parts PM confirms will not change for now.","two_gates_heading":"Two freeze gates","two_gates_cols":["Gate","Trigger","Output"],"two_gates_rows":[{"gate":"Survey freeze","trigger":"survey-checklist 100%","output":"Docusaurus publishable; Open Questions consolidated"},{"gate":"Scope freeze","trigger":"PM completes per-block decisions on spec + Figma","output":"Each flow / page marked Refactor-first or Align later"}],"phase1_title":"Phase 1 (Archaeology)","phase1_items":["records/ records As-is; main/ accumulates To-be contract-schemas.","flow.md marks \"Pending PM Clarification\" and Unverified Logic.","checklist reaches 100% → survey freeze, organize Docusaurus (incl. Open Questions)."],"phase2_title":"Phase 2 (PM alignment)","phase2_items":["Bring Docusaurus spec and Figma As-is drafts (see s6) to PM for per-block confirmation — including Align later items; both are required.","Discuss: what keeps current logic, what to refactor, what needs joint process rethink.","Close Open Questions one by one, or escalate to Scope decisions.","Mark Scope for each flow / page (see below)."],"scope_decisions_heading":"Scope decision tags","scope_decisions_intro":"Core output of PM alignment. Decisions recorded as Docusaurus page badges and written back to main/ file frontmatter (scope: stable | pending).","scope_decisions_cols":["Tag","What PM means","Next step"],"scope_decisions_rows":[{"label":"Refactor-first","meaning":"PM confirms this block will not change business logic or flow for now","next":"Prioritize for refactor kickoff"},{"label":"Align later","meaning":"PM indicates this block will be adjusted, refactored, or rethought later","next":"Round one still needs spec + Figma As-is for PM decision; defer kickoff and To-be design. After Refactor-first completes, round two brings updated spec + Figma to discuss with PM"}],"phase3_title":"Phase 3 (Refactor kickoff)","phase3_items":["Start development from blocks marked Refactor-first; do not touch Align later items.","Align later items: after other renovation wraps up, re-discuss with PM and update spec + Figma.","Feature Branch modifies docs/main/ (To-be); PR includes CHANGELOG.md (Ticket Link + changed docs).","Docs merge with code on deploy — code is docs, docs is code."]},"s6":{"emoji":"🧱","heading":"Figma Design System & Three-Layer Token Architecture","subheading":"Serves s5 PM alignment: spec and Figma As-is appear as a pair. No Figma changes during archaeology; build As-is canvas after survey freeze; only Refactor-first items update To-be after Scope freeze.","timeline_heading":"Figma four-phase timeline (aligned with s5)","timeline_steps":["① Archaeology: frontend does not touch Figma. Optional — ask designers to sync production site with new Token architecture (As-is restoration) in parallel with code archaeology.","② After survey freeze: build / complete Figma As-is canvas per spec (100% matching production), parallel with Docusaurus output.","③ PM alignment: all flows / pages (including Align later) need spec + Figma As-is together for PM confirmation.","④ Refactor kickoff: only Refactor-first items update Figma To-be; Align later stays As-is, changed after round-two PM discussion."],"pm_deliverable_callout":"Minimum PM alignment deliverable: key screens per flow + static page blocks; spec (Docusaurus) and Figma As-is are both required.","kit_callout":"Figma starting point: use Obra shadcn/ui kit as community template (https://obra.studio/work/figma-shadcn-ui-kit/), copy to each project locally then override Tokens and As-is canvas — do not build component library from scratch. Code side pairs with shadcn/ui CLI.","intro_p1":"Multi-product \"island maintenance\": Figma Professional cannot link Variables across files — adopt \"central template (Obra kit + shadcn components), local customization\" — copy template, map brand colors, restore As-is canvas.","intro_p2":"Three Token layers align with Obra / shadcn philosophy: bottom Raw uses Tailwind palette naming; Brand builds 100–900 scales; Semantic aligns with shadcn and consolidates business-specific colors. Canvas binds only Semantic.","pro_warning":"⚠️ Creating Figma Variables requires at least Pro plan Full seat (not Collab seat).","token_rule":"Three-layer Token physical isolation: canvas must and may only use Semantic Tokens. Raw (Tailwind palette) and Brand (100–900 scales) are forbidden on canvas.","token_cols":["Layer","Naming convention","Code counterpart","Designer access"],"token_rows":[{"layer":"1. Raw / Primitives 🔒","figma":"Same names as Tailwind CSS palette (e.g. slate-500, blue-600, neutral-100)","css":"tailwind.config / @theme base color tokens","access":"❌ Forbidden on canvas. Color dictionary."},{"layer":"2. Brand 🔒","figma":"Site brand colors 100–900 scales (e.g. brand-blue-100, brand-orange-500)","css":"theme defines brand scale; exposed on canvas via Semantic alias (e.g. --brand-pink)","access":"❌ Forbidden on canvas."},{"layer":"3. Semantic 🔓","figma":"shadcn standard (background, primary, muted…) + business semantics (e.g. link, brand-pink)","css":"globals.css :root — shadcn built-in (--background, --primary…) + custom (--link, --brand-pink)","access":"🔓 Only legal layer. Bind colors from Raw or Brand."}],"token_semantic_heading":"Semantic layer rules","token_semantic_rules":["Prefer shadcn built-in semantics (background, foreground, primary, muted, destructive…).","Semantic color sources: select from Raw (Tailwind palette) or Brand (100–900) and create alias.","Brand / business colors not covered by shadcn: name at Semantic layer (e.g. link, brand-pink), add CSS variable in globals.css :root pointing to Brand or Raw.","Figma Semantic Variables 1:1 aligned with :root variable names (follow shadcn/ui CLI conventions)."],"fold_org_content":"Central Workspace → Obra shadcn/ui kit template (Raw Tailwind palette + shadcn standard components). Each project locally → copy kit, override Brand scales and Semantic mapping, 100% restore As-is screens.","fold_pattern_central":"Central maintenance: 100% business-logic visual consistency, zero customization possible (e.g. Japan map selector) → Copy-Paste.","fold_pattern_local":"Local maintenance: composite components whose semantics change by product line (e.g. BookingCard, CouponSelector) → central shadcn base + local assembly.","fold_align_desc":"Figma canvas shows only human-readable English copy (company site primary locale is EN) — no i18n keys, no Variables Mode for translations.","fold_align_rules":["Description can hold design notes (not keys): dynamic copy (API response), placeholder / char limits, truncation risk, PM copy pending, or link to Docusaurus spec section.","Sticky / Comment for PM alignment discussion only — not long-term SSOT.","i18n keys and multilingual mapping: legacy archaeology → JSON → Google Sheet → code (see s7); static pages also list blocks + keys in docs/main/pages/. During refactor, cross-reference via screen + spec / Sheet, not reverse-lookup keys from Figma."],"fold_align_example":"Canvas: \"Please enter your booking code\" → Description: \"Booking code placeholder; static copy; see booking flow spec §2\" — not booking.field.code_placeholder."},"s7":{"emoji":"🌍","heading":"i18n Fully Automated Pipeline","figma_boundary":"Figma shows only human-readable English copy (primary locale EN), not i18n SSOT. Keys and translations follow archaeology JSON → Sheet → code; design Description holds design semantics only (see s6).","sheet_ssot":"Legacy translations for all locales already exist during archaeology — cleanup only does format normalization, namespace / key rename, status tagging; no re-translation. When writing to Sheet, en / ja / zh_TW columns should already be filled; Sheet is the complete reference table.","toolchain_note":"Toolchain: Claude Web for archaeology JSON cleanup, Cursor for renovation. Target framework i18next → next-intl, format adjusted per next-intl conventions; status tags unused / in-progress.","gemini_rule":"Gemini is not required for archaeology: Sheet already has all legacy locales. Only when refactor adds keys (in-progress) or manual translation delegation, use Gemini to operate Sheet; Instruction Sheet holds Tone Guide for supplementary translation.","iron_rule":"System Prompt-level global rule: if needed translation does not exist in JSON, NEVER invent new keys. Hardcode in code with // TODO: i18n-missing for batch extraction.","migration_heading":"i18next → next-intl cleanup rules","normalize_rules":["Framework migration: reorganize from i18next structure to next-intl conventions (namespace + key, JSON / message format per next-intl sync script output).","Do not actively strip extra whitespace — legacy may preserve it intentionally for layout; carry through as-is during cleanup.","Newline merge: legacy renders array [a, b, c] sentences via map → consolidate to single key with \\n newlines (e.g. \"Line one\\nLine two\\nLine three\") for easier translator editing in one column.","Interpolation syntax: during archaeology cleanup, i18next {{var}} directly becomes next-intl {var}; written to Sheet as final form; sync script only reads/writes, no format conversion — for future reuse.","Code side: copy with \\n rendered via CSS whitespace-pre-line (or equivalent), no longer map array sentences in components."],"namespace_heading":"Namespace split","namespace_rules":["Single-domain project: namespace per page / screen, no -page suffix (e.g. checkout, affiliate-intro).","Cross-page shared copy → common; each page references only its namespace + common. Flow does not get its own namespace — each step screen uses its page's translations.","Slug aligns with docs/main/pages/, Figma frame names, and route Entry screen; legacy_key retains old name for comparison during cleanup."],"fold_json_content":"JSON format example: status, namespace, key, legacy_key, en, ja, zh_TW, description.\n\nLocale values come from legacy translations (not empty shells awaiting translation). Example: namespace checkout + key coupon.btn.apply; legacy_key for script gap detection.","sync_heading":"Sheet → code output structure","sync_rules":["Split files by namespace: messages/{locale}/{namespace}.json (e.g. messages/en/common.json, messages/en/checkout.json).","Nested JSON inside files (e.g. { \"coupon\": { \"btn\": { \"apply\": \"…\" } } }). Sheet key column still uses dot notation (coupon.btn.apply) for editing; sync script expands to nested on write.","Sheet namespace column 1:1 with filename; pages use useTranslations('{namespace}') + t('coupon.btn.apply'); common shared across pages."],"steps":["AI organizes legacy translations to JSON (i18next → next-intl; {{var}} → {var}; array newlines merged to \\n; no trim of extra whitespace)","Script compares legacy_key with original translations, checks gaps (dynamic keys manually marked active)","Script writes to Google Spreadsheet (single sheet + namespace column; all locale columns filled)","New project sync script: Sheet → messages/{locale}/{namespace}.json (dot key to nested JSON; unused filtered, in-progress shows 🚧)","SKILL.md rule: missing keys forbidden — hardcode + // TODO: i18n-missing; new keys marked in-progress then translated"]},"s8":{"emoji":"🏁","heading":"Survey, Validation & Renovation Kickoff","validation_heading":"Parallel comparison & renovation thresholds","validation_items":["Legacy and new projects in same workspace for side-by-side comparison.","Multi-line copy with \\n: frontend uses CSS whitespace-pre-line (see s7 newline merge rules), no longer map array sentences.","After survey freeze, organize records/ + main/ survey docs into Docusaurus format, deploy separate repo, align with PM (working directory itself not PM-facing)."],"gate_heading":"Phase 3 kickoff & acceptance (three stages)","gate_project_heading":"1. Project-level (before Phase 3 kickoff, once only)","gate_project_items":["Survey freeze (survey-checklist 100%)","Docusaurus organized and deployed","Figma As-is 100% ready (completed parallel with Docusaurus after survey freeze; prerequisite for Scope freeze)","Scope freeze complete: each flow / page marked Refactor-first or Align later","Align later items still need spec + Figma As-is in round one, but do not enter work pool"],"gate_issue_heading":"2. Single Issue / vertical slice (Refactor-first only)","gate_issue_cols":["Issue type","Minimum before kickoff"],"gate_issue_rows":[{"type":"Schema / Transformer / pure function","requirement":"flow.md + main/contract-schemas/ spec sufficient → TDD kickoff"},{"type":"UI component / page","requirement":"Above + Figma To-be for that block (Refactor-first items)"},{"type":"Flow (with BDD)","requirement":"Happy Path Scenarios written; Pending PM Clarification / Unverified Logic stay as comments, no Scenarios"},{"type":"Static Pages","requirement":"docs/main/pages/ blocks + i18n key list sufficient; BDD not required"}],"gate_merge_heading":"3. Pre-merge / pre-deploy (acceptance, not kickoff threshold)","gate_merge_items":["Slice BDD all green (flows with written Scenarios)","AI L1/L2 structure audit + human L3 spot-check (see s3)","PM sign-off on that Refactor-first block (Docusaurus spec + Figma To-be comparison)"],"log_rule_heading":"Unverified Logic observation rule","log_rule":"During refactor, logic behavior must align with legacy. Branches listed in flow.md § Unverified Logic must add runtime log in refactor version to observe if still triggered — silent deletion or skipping forbidden.","log_rule_items":["Unverified Logic marked during archaeology: keep equivalent branch and add log (reference flow.md file location).","After observation period with zero hits → can delete branch and update flow.md § Scoped Files.","New unexplained branches found during refactor: first tag flow.md § Unverified Logic then add log; do not remove directly."],"skills_heading":"Issue splitting & Matt Pocock Agent Skills","skills_subheading":"Split Issues using 5 Agent Skills. Leverage monorepo integration. Parallel Issue tasks.","skills_cols":["Skill","Description","Recommended AI","Phase"],"skills_rows":[{"name":"Grill-with-Docs","desc":"Combine archaeology docs, clarify decision branches along design tree","ai":"Claude Opus 4.6","phase":"Planning"},{"name":"To-PRD","desc":"Produce PRD from consensus with User Stories and module sketches","ai":"Claude Sonnet 4.5","phase":"Planning"},{"name":"To-Issues","desc":"Split PRD into vertical-slice Issues with blocking relationships","ai":"Claude Sonnet 4.5","phase":"Planning"},{"name":"TDD","desc":"Red-green-refactor loop — one test one implementation, no feature loss on refactor","ai":"Cursor Composer 2.5","phase":"Development"},{"name":"Architecture-Refactor","desc":"Deepen shallow modules, clarify test boundaries for stable Agent navigation","ai":"Cursor Composer 2.5","phase":"Development"}],"refs_heading":"Technical references","refs":[{"label":"Stop writing docs by hand","url":"https://www.aihero.dev/5-agent-skills-i-use-every-day"},{"label":"Playwright BDD","url":"https://playwright.dev/docs/test-agents"}],"issues_heading":"Atomic Issue examples","issues":[{"id":"#01","tag":"Schema","title":"Implement transformBookingAmount pure function","blocks":"Refactor-first + flow.md / schema ready → can start"},{"id":"#02","tag":"UI","title":"Implement BookingCard static component per Figma To-be","blocks":"Blocked by #01; needs To-be draft for that block"},{"id":"#03","tag":"BDD","title":"Write booking code validation Edge Cases acceptance cases","blocks":"Parallel with #01; BDD must be green before merge"}],"roadmap_heading":"Roadmap","roadmap":[{"title":"Phase 1: Archaeology & survey freeze","desc":"Four-role Skills → records/ + main/ → checklist 100% (survey freeze). Then parallel Docusaurus and Figma As-is (s6 ②, 100% matching production) — both ready before Phase 2. Optional kit sync during archaeology ①."},{"title":"Phase 2: Scope freeze","desc":"Prerequisites met: Docusaurus spec + Figma As-is both ready. PM confirms each flow / page as pair, marks Refactor-first / Align later (s6 ③).","risk":"🔥 Risk control: cannot enter PM alignment until Figma As-is complete"},{"title":"Phase 3: Refactor kickoff","desc":"After project-level + Issue thresholds pass, only Refactor-first vertical slices start; Figma To-be incrementally updated with UI Issues (s6 ④). Pre-merge BDD + L3 + PM sign-off."}],"roadmap_note":"Figma As-is is not done at refactor time — it is a hard prerequisite for Phase 2 PM alignment, completed parallel with Docusaurus after survey freeze."},"s9":{"emoji":"🛡️","heading":"API Data Boundary: No BFF, Zod + Transformers","subheading":"Conclusion after reviewing \"Frontend-Backend Responsibility Split & BFF Design\": no separate BFF; frontend fetches Core API then uses Zod for runtime validation and data normalization (Parse, don't validate). Aligns with contract-schemas produced by s3 Data Boundary Planner.","decision_callout":"No BFF layer — less infra and deployment cost. Frontend `httpClient` connects directly to backend; client-side Zod Schema + Transformer consolidates legacy odd formats; components only consume Clean Type.","layers_heading":"Three-layer defense","layers_cols":["Layer","Responsibility","Artifact"],"layers_rows":[{"layer":"1. Upstream (archaeology)","role":"Role 1 infers backend Raw structure from codebase","artifact":"docs/records/endpoints/[endpoint-name].ts"},{"layer":"2. Contract (spec SSOT)","role":"Role 2 defines Frontend Interface + Transformer prototype","artifact":"docs/main/contract-schemas/endpoints/[name].md"},{"layer":"3. Runtime (code)","role":"refactor implements Zod parse + transform + handleResponse","artifact":"lib/api/[endpoint-name]/{schema,transformer,index}.ts"}],"runtime_heading":"Runtime pattern (client-side normalization)","runtime_steps":["httpClient fetch Core API → get unknown","Zod Backend*Schema.safeParse — intercept HTML / non-JSON / field drift (ApiProtocolError)",".transform() to frontend Clean Type (snake_case, semantic fields, strip redundancy)","Unified ApiResponseSuccess / ApiResponseError envelope — business errors throw ApiBusinessError","React / Store only import Clean Type; direct Raw JSON forbidden"],"error_heading":"Error classification","error_cols":["Type","Trigger","Handling"],"error_rows":[{"type":"ApiProtocolError","trigger":"Non-JSON, HTML error page, Zod parse failure","handling":"log + unified error UI; addresses s1 \"inconsistent error formats\" root cause"},{"type":"ApiBusinessError","trigger":"Backend returns { error: { code, message } }","handling":"Branch by code; no more guesswork in components"}],"proto_heading":"Prototype reference (backend/ — paused)","proto_intro":"Previously implemented multiple endpoints per above pattern (get-bus-list, get-locations, submit-contact…), each with schema.ts (Backend + Clean), transformer.ts, index.ts, shared handleResponse and contract.ts.","proto_structure":["backend/[endpoint-name]/schema.ts — Backend*Schema (Zod) + Clean Type","backend/[endpoint-name]/transformer.ts — request / response transform","backend/[endpoint-name]/index.ts — httpClient + handleResponse","backend/utils/handle-response.ts — safeParse unified entry","backend/contract.ts — ApiResponseSuccess / ApiResponseError"],"proto_pause_heading":"Why paused","proto_pause_items":["As endpoint count grows, easy to get lost between folders — missing naming reference SSOT with flows / archaeology artifacts","Backend naming (PascalCase, nested XML style) hard to align with frontend Clean naming across APIs","shared entities (e.g. BusFacilities) vs. per-endpoint boundaries unclear; duplicate definition risk"],"plan_bridge_heading":"How renovation plan continues","plan_bridge_items":["Archaeology: records/endpoints/[name].ts 1:1 with flow.md § Referenced Endpoints — endpoint list no longer by memory","Planning: contract-schemas/endpoints/[name].md as SSOT for naming and Transformer; shared/ consolidates cross-endpoint entities","Code directory slug aligns with contract-schemas filename (e.g. get-bus-list), one endpoint per folder","First vertical slice defines golden sample (incl. Zod + test); subsequent endpoints copy structure, no reinventing","Role 2 must check contract-schemas/shared/ before starting; duplicate entity definitions forbidden"],"bff_note":"BFF discussion evaluated location search, 7k-record cache, etc. — most can be done with frontend IndexedDB + local filter; only a few geographic computation scenarios need backend. Default path remains client-side transformer, not a separate BFF service."},"footer":{"text":"Project Renovation & Refactor Plan"}},"ja":{"meta":{"title":"プロジェクト全面刷新：AI駆動のアジャイル考古学とリファクタリング計画"},"common":{"label_input":"Input","label_output":"Output","fold_specs":"詳細仕様要件を展開","fold_doc_tree":"📂 クリックして展開：考古期作業ディレクトリ（records/ + main/、Agent 書き込み）","fold_figma_org":"組織構造：中央テンプレート、ローカルカスタマイズ","fold_figma_pattern":"ビジネスモジュール保守境界","fold_figma_align":"Figma 文案と i18n の境界","fold_i18n_json":"🔍 表示：i18n データ型とスクリプト規範の詳細","fold_i18n_steps":"翻訳準備の完全ステップ（全 {n} ステップ）","fold_deliverables":"成果物一覧","tier_budget":"節約可","tier_required":"必須","tier_context":"要コンテキスト","tier_human":"人手","tool_claude":"Claude","tool_cursor":"Cursor","tool_human":"人手","audit_layers_label":"考古検証三層級（Role 4）","issue_tag_legend_heading":"Issue タイプタグ","issue_tag_legend":[{"tag":"Schema","meaning":"データ境界／Transformer／純関数"},{"tag":"UI","meaning":"コンポーネントまたはページ。Figma To-be が必要"},{"tag":"BDD","meaning":"Flow 検収ケース。マージ前に全緑必須"}],"glossary":{"L1":{"short":"カバレッジマップ","tip":"flow.md § Scoped Files と照合：scope 内の各 .ts/.tsx に帰属があること。AI が自動検証、未帰属ファイル = 0。"},"L2":{"short":"構造ゲート","tip":"flow 七章節、endpoint 閉環、BDD 整合、transform 集約。AI が gap report を出力、全緑で合格。"},"L3":{"short":"人手サンプリング","tip":"ソースコードとランダム照合し、考古内容が揃っただけでなく正しいことを確認。人間が承認、コア flow は 5 件推奨。"},"四区":{"short":"survey-checklist 四区画","tip":"Flows、Endpoints、Static Pages、Global Constraints——棚卸凍結には四区 100% チェック必須。"},"先行リファクタ可":{"short":"Scope タグ","tip":"Phase 2 PM 整合後、即時着手可能な flow／ページとしてマーク。Phase 3 はこの類のみ着手プールに入る。"},"後続調整待ち":{"short":"Scope タグ","tip":"spec + Figma As-is は準備必須だが、refactor 第一ラウンドでは触らない。他の刷新が一段落後、PM と To-be を更新。"},"As-is":{"short":"現況還原稿","tip":"本番環境と 100% 一致する Figma キャンバス。Phase 2 PM 整合の硬性前提。"},"To-be":{"short":"目標デザイン稿","tip":"リファクタ着手後、「先行リファクタ可」項目のみ段階的に更新。UI Issue 着手前に該当ブロックの To-be が必要。"}},"s9_layers_note":"この「三層防線」は API データフロー（Upstream → Contract → Runtime）を指し、考古検証の L1／L2／L3 とは異なる。"},"hero":{"title":"プロジェクト全面刷新：AI駆動のアジャイル考古学とリファクタリング計画","subtitle":"AI 考古学で欠落した Specification（ステップ、ページ、フロー）を補完し、フロントエンド視点で API Schema を明確化して安定した Transformer を構築、Figma デザインシステムを再構築し、Agent Skills パイプラインで文書化検収を推進——デザイン乖離と技術的負債を体系的に低減します。"},"toc":[{"id":"s1","label":"前情提要"},{"id":"s2","label":"トップアーキテクチャ"},{"id":"s3","label":"4ロール Workflow"},{"id":"s4","label":"考古棚卸"},{"id":"s5","label":"凍結管理"},{"id":"s6","label":"Figma デザインシステム"},{"id":"s7","label":"多言語"},{"id":"s8","label":"刷新開始"},{"id":"s9","label":"API 境界と Zod"}],"s1":{"emoji":"🛑","heading":"前情提要と現状の痛点棚卸","table_cols":["痛点","影響","根本原因"],"table_rows":[{"pain":"仕様書の欠如","impact":"ビジネスロジックの照合不可、変更リスク高","cause":"ビジネスロジックを照合できる標準文書がない。ステップ、ページ、フローはすべてコードからの通霊還元に依存。"},{"pain":"フロントエンドコードの混乱","impact":"修正コスト極大","cause":"非推奨パターンが多く、特定の Framework Bug に遭遇した際の調査が極めて困難。"},{"pain":"バックエンド仕様なし","impact":"フロントの通霊判断","cause":"バックエンドに仕様書がなく、フロントコードだけではレスポンス形式を正確に判断できない。さらにバックエンドの不正形式への暫定対応としてフロントに追加された通霊判断。これが後続の error 形式混乱と transform 分散の上流根本原因。"},{"pain":"Error 形式の不統一","impact":"汚いロジックの蓄積","cause":"error レスポンス形式が不統一で、各形式に対応する汚いロジックがフロントに蓄積。"},{"pain":"データ命名の混乱","impact":"リファクタ時の追跡困難","cause":"フロントが独自の transform 層を作ったが、各所に分散しており、リファクタ時に元の value を素早く見つけられない。"},{"pain":"デザイン稿と本番環境の乖離","impact":"UI 還元が推測頼み、デザイン反復が追跡不能","cause":"Figma が codebase と同期保守されておらず、本番とデザイン稿が長期にわたり乖離。"}],"vision_heading":"現状痛点 vs 刷新ビジョン","as_is_title":"As-is 現状痛点","to_be_title":"To-be 刷新ビジョン","as_is_items":["ビジネスロジックを照合できる仕様書がない","デザイン稿と本番環境の乖離","コード劣化、技術的負債の蓄積","新人オンボーディング困難、通霊コスト高","バックエンド形式混乱、フロント transform 分散"],"to_be_items":["Specification がビジネスロジックの SSOT に","考古したビジネス行為すべてに BDD 検収ケース","Figma デザインシステムとコードの同期","AI Agent 自動化ディスパッチ + 人機協業境界の明確化","データ境界の分離、クリーン型で汚データを置換"]},"s2":{"emoji":"🗺️","heading":"トップアーキテクチャ、文書フローとディレクトリ規範","subheading":"旧 Codebase から棚卸凍結までの完全産出チェーン。考古期の作業データは records/ と main/ に書き込み。棚卸完了後、PM 整合用に Docusaurus を別途産出。","example_callout":"⚠️ 本セクションの `[flow-name]`、`[endpoint-name]` および下記の例示リストはディレクトリ構造と分割粒度の説明のみであり、本プロジェクトの実際の flow や API ではない。実際の名称と境界は考古段階で既存 codebase のビジネスロジックに基づき個別定義。","taxonomy_heading":"考古産物の三層分類","taxonomy_intro":"Flow は唯一の分類軸ではない。Endpoint 仕様と Flow は直交——1 つの flow が複数 endpoint を参照でき、1 つの endpoint が複数 flow で共有される。","taxonomy_cols":["層級","パス","粒度","考古深度"],"taxonomy_rows":[{"tier":"User Flow（Record）","path":"docs/records/flows/[flow-name]/","granularity":"1 つの完全なユーザータスク（Entry → Terminal State）","depth":"flow.md + BDD + 参照 endpoints"},{"tier":"静的／コンテンツ","path":"docs/main/pages/","granularity":"1 ページまたは 1 ブロック","depth":"ブロック構造 + i18n key のみ。schema / BDD は書かない"},{"tier":"グローバル制約","path":"docs/records/global-constraints/","granularity":"flow 横断の横断ロジック","depth":"BDD のみ。独立 flow.md なし"}],"taxonomy_endpoint_note":"Endpoint 仕様（docs/records/endpoints/）は別の直交軸：1 endpoint 1 ファイル。考古期に upstream 構造を推測し、プランナーが Frontend Interface + Transformer を main/contract-schemas/endpoints/ に産出。","flow_granularity_heading":"Flow 分割基準（Highway Bus サービス — 例示）","flow_granularity_rules":["ユーザータスク（User Journey）単位で分割。ページやルートで分割しない。","1 Record = 独立してアーカイブ可能な完全ジャーニー（Entry Point → Terminal State）。","Endpoint 仕様（endpoints/）と Flow（flows/）は直交：1 flow が複数 endpoint を参照可能、endpoint は flow 横断で共有可能。","独立 Entry Point と完全ジャーニーがあるものは別 flow（例：Email ディープリンクの Coupon フロー）。別 flow 途中で発火するロジック（例：予約途中の Coupon 適用）はその flow の Edge Cases に記述。","外部フォームへ誘導、サイト内に完全タスクがない紹介ページ（例：Affiliate）→ 静的ページ棚卸、flow は開かない。","flow 横断の横断ロジック（Session 有効期限、防刷、URL 言語同期）→ global-constraints/ に集約。"],"flow_examples_note":"以下は分割粒度タイプの例示のみ。[flow-name] は placeholder で、本プロジェクトの実際の flow 名ではない：","flow_examples":[{"name":"[search-flow]","desc":"検索とフィルタ（status 駆動の隠し UI 状態を含む）"},{"name":"[booking-flow]","desc":"予約メインフロー（ページ横断の完全ジャーニー）"},{"name":"[coupon-email-flow]","desc":"Email ディープリンク入口の Coupon フロー（独立 Entry Point）"},{"name":"[lookup-flow]","desc":"予約照会／変更系フロー"}],"endpoint_examples_note":"Endpoint ファイル名も例示。考古時は実際の API 命名に従う：","endpoint_examples":["search-routes.ts","get-seat-map.ts","post-reservation.ts","get-reservation.ts"],"diagram":"graph TD\n    Code[\"旧ソースコード\"] -->|Repomix 打包 + Agent 探索| R1[\"🕵️ 1.コード考古学者\"]\n    R1 -->|As-is 業務行為| Flow[\"docs/records/flows/[flow-name]/flow.md\"]\n    R1 -->|endpoint レスポンス構造を推測| Upstream[\"docs/records/endpoints/[endpoint-name].ts\"]\n    Flow --> R2[\"📐 2.データ境界プランナー\"]\n    Upstream --> R2\n    Comp[\"Components / Store 衍生ロジック\"] --> R2\n    R2 -->|Frontend Interface + Transformer| Schema[\"docs/main/contract-schemas/endpoints/\"]\n    R2 --> Ctx[\"CONTEXT.md\"]\n    Flow --> R3[\"✍️ 3.行為テストアーキテクト\"]\n    Schema --> R3\n    R3 -->|BDD ケース| BDD[\"docs/records/flows/[flow-name]/e2e-cases.feature\"]\n    Flow --> R4[\"⚖️ 4.文書棚卸員\"]\n    Schema --> R4\n    BDD --> R4\n    R4 -->|Cover 審査| Check[\"docs/survey-checklist.md\"]\n    Check -->|100% Check| Freeze[\"棚卸凍結\"]\n    Freeze -->|棚卸文書を整理| Docs[\"Docusaurus 文書サイト\"]\n    Docs -->|PM 整合| PM[\"業務／技術変更議論\"]\n    Freeze -.->|開発者 reference| Ref[\"records/ + main/ 留存\"]","doc_tree_note":"以下は考古とリファクタ期の作業ディレクトリ。Agent 書き込みと開発者参照、refactor 引用用。PM 向けフォーマットではない。","docusaurus_heading":"棚卸完了後：Docusaurus 産出","docusaurus_intro":"survey-checklist が 100% 達成後、棚卸文書（records/ + main/ + CONTEXT.md）を Docusaurus 形式に整理し、独立 repo で文書サイトを構築。PM との認知整合の正式インターフェース。main/ と records/ は開発者自用と refactor reference として残す。","docusaurus_steps":["凍結後の棚卸文書を source とする（考古期から Docusaurus を書かない）","Skill / Script で Docusaurus 構造に変換（MDX、sidebar、Admonitions 等）","各 flow.md § PM 確認待ち を Open Questions 専用セクションに集約","独立 repo で文書サイトをデプロイ","このサイトで PM と技術・業務変更を議論"],"doc_tree_cols":["パス","用途"],"doc_tree_rows":[{"path":"CONTEXT.md","desc":"グローバル glossary（常駐）。考古期に継続更新、grill-with-docs で継承。"},{"path":"docs/survey-checklist.md","desc":"考古進度追跡表。四区 + 各 Record の L1/L2/L3 サブチェック。"},{"path":"docs/records/","desc":"As-is 考古作業区。開発者参照と refactor reference。棚卸凍結後も留存、PM 対外インターフェースではない。"},{"path":"docs/records/flows/[flow-name]/flow.md","desc":"As-is 現況業務フロー。名称は考古段階で codebase から定義（placeholder: [flow-name]）。"},{"path":"docs/records/endpoints/[endpoint-name].ts","desc":"考古期に codebase から推測した単一 endpoint の原始レスポンス構造（TypeScript type）。名称は考古段階で定義。"},{"path":"docs/records/flows/[flow-name]/e2e-cases.feature","desc":"BDD テストケース。"},{"path":"docs/main/flows/","desc":"確認済み As-is フロー。リファクタ期 To-be SSOT の基石。開発者 reference。"},{"path":"docs/main/pages/","desc":"ページロジック棚卸。開発者 reference。"},{"path":"docs/main/contract-schemas/shared/","desc":"グローバル Entities（To-be）。開発者 reference。"},{"path":"docs/main/contract-schemas/endpoints/","desc":"Frontend Interface + Transformer（To-be）。開発者 reference。"}]},"s3":{"emoji":"🛠️","heading":"Skills Workflow によるデータ産出","subheading":"4 ロールのコアタスクと精確な I/O。技術仕様は各折りたたみに格納。Role 4 の三層検証フローは下記専用セクション参照。","auditor_heading":"文書棚卸三層検証フロー","auditor_intro":"Role 4 は再考古しない。Role 1–3 のテンプレート契約が履行されたかを検証。「ファイル漏れ」と「詳細漏れ」を分離処理：L1/L2 は自動検証可能、L3 は人手サンプリングでソースコードと照合。","auditor_diagram":"flowchart TD\n    Draft[\"① AI 草稿 checklist\"] --> L1[\"② L1 カバレッジマップ<br/>未帰属ファイル = 0\"]\n    L1 --> L2[\"③ L2 構造ゲート<br/>テンプレート + 相互参照\"]\n    L2 --> Gap[\"④ gap report\"]\n    Gap --> L3[\"⑤ L3 人手サンプリング<br/>ソースコード照合\"]\n    L3 --> Check[\"⑥ survey-checklist チェック\"]\n    Check --> Freeze[\"四区 100% → 凍結\"]","auditor_workflow_heading":"各 Record の実際の実行ステップ","auditor_workflow_steps":["AI が legacy ファイルツリーと既存産出物に基づき、survey-checklist.md 四区項目を草稿更新。","AI が L1 を実行：flow.md § Scoped Files と照合し、scope 内の各 .ts/.tsx に帰属があることを確認。未帰属ファイル = 0。","AI が L2 を実行：flow 七章節の完備、Referenced Endpoints 閉環（upstream .ts + contract-schema .md）、BDD Scenario と flow.md の整合、@old_logic_location が Scoped Files に出現することを確認。","gap report を産出し、不合格項目を列挙。全緑でなければ該当 Role に差し戻し。","人間が gap report を審査し、該当 Record で L3 サンプリングを実行（下記リスト参照）。","L1 + L2 + L3 全合格 → 該当 Record をチェック。四区すべてチェック → 第一段階凍結。"],"auditor_layers_heading":"三層検証の定義","auditor_layers_cols":["層級","検証内容","実行者","合格条件"],"auditor_layers_rows":[{"layer":"L1 カバレッジマップ","checks":"scope 内の legacy ファイルがすべて帰属しているか","who":"AI","pass":"未帰属ファイル = 0"},{"layer":"L2 構造ゲート","checks":"flow テンプレート、endpoint 閉環、BDD 整合、transform 集約","who":"AI","pass":"gap report 全緑"},{"layer":"L3 人手サンプリング","checks":"ソースコードとランダム照合。内容が揃っただけでなく正しいことを確認","who":"Human","pass":"サンプリング項目全合格（コア flow は 5 件推奨）"}],"auditor_spotcheck_heading":"L3 人手サンプリングリスト（各 Flow Record）","auditor_spotcheck_items":["Edge Case を 1 件ランダム選択 → 元 component の if-else と照合し、flow.md の記述が正しいことを確認。","@old_logic_location を 1 件ランダム選択 → transformer ロジックが集約され、漏れがないことを確認。","Unverified Logic を 1 件ランダム選択 → 本当に code から説明できないことを確認（怠慢タグでないこと）。","（コア業務 flow 追加）Happy Path ステップ 1 件 + Referenced Endpoint フィールド語意を 1 件追加サンプリング。"],"checklist_heading":"survey-checklist.md 四区構造","checklist_intro":"考古産物タイプごとに合格基準が異なる。各チェックボックスには L1/L2/L3 サブチェック必須。「文書はあるが未検証」を防ぐ。","checklist_cols":["区画","チェック単位","合格基準","検証深度"],"checklist_rows":[{"area":"Flows","unit":"各 [flow-name] Record","standard":"flow.md（PM 確認待ち含む）+ e2e-cases.feature + 参照 endpoints すべてに contract-schemas。BDD と flow.md が整合","depth":"L1 + L2 + L3"},{"area":"Endpoints","unit":"各 [endpoint-name].ts","standard":"対応する main/contract-schemas/endpoints/[name].md が存在し upstream を参照","depth":"L2"},{"area":"Static Pages","unit":"各ページ","standard":"main/pages/ にブロック + i18n key リスト（BDD 不要）","depth":"L1"},{"area":"Global Constraints","unit":"一式","standard":"global-constraints/e2e-cases.feature が s4 に列挙された横断ロジックをカバー","depth":"L2 + L3"}],"checklist_example_note":"以下は checklist エントリ形式の例（抽象例示）：","roles":[{"emoji":"🕵️","title":"コード考古学者 (Code Archaeologist)","task":"旧システムの「現況（As-is）」を把握：純粋なビジネス行為を抽出、codebase から関連 endpoint レスポンス構造とすべての可能性を推測、デッドコードを排除。","input":["Repomix 打包した codebase","指定 flow 関連ルート／コンポーネント scope"],"output":["docs/records/flows/[flow-name]/flow.md","docs/records/endpoints/[endpoint-name].ts","CONTEXT.md（glossary 増分更新）"],"ai_recommendation":{"tool":"claude","model":"Sonnet 4.5","tier":"budget","hint":"大量ファイルの分批考古"},"spec_summary":"flow.md テンプレート要件を展開","spec_example_note":"以下は抽象例。章節構造の例示のみ。本プロジェクトの実際の flow や endpoint ではない。","spec_sections":[{"title":"### Entry Points","desc":"この flow に入れるページ／ルート／トップページブロック。トップページ spec は参照のみ記載、行為詳細はここに記述。"},{"title":"### Referenced Endpoints","desc":"この flow が関与する endpoints/[name].ts のリスト。endpoint 直交軸へのインデックス。"},{"title":"### Happy Path","desc":"極簡のユーザー成功操作ステップ。"},{"title":"### Edge Cases","desc":"コード内のすべてのビジネスロジック分岐（ネットワーク断等の基建エラー除外）。"},{"title":"### PM 確認待ち","desc":"ビジネス意図やシナリオ不明：code は行為がわかるが「なぜ」や正しいルールが不明。出典位置と疑問を記載。棚卸凍結後 Docusaurus Open Questions で PM と整合。"},{"title":"### Unverified Logic","desc":"コードの謎：書いてあるが未実行、再現不能、説明不能な分岐。出典ファイル位置を記載。本番 log 検証またはバックエンド確認待ち（PM ビジネス問題ではない）。"},{"title":"### Scoped Files（カバレッジマップ）","desc":"Record 封緘前必須。scope 内の各 .ts/.tsx に帰属必須：flow 章節参照、Dead Code（理由付き）、Unverified Logic、または他 flow への相互参照。未帰属ファイル = 0 で Role 4 に渡す。"}],"spec_code":"# [flow-name]\n\n### Entry Points\n- `/some-list-page` — ユーザーがリストページの選択肢から入る\n- `/landing#quick-action` — トップページのブロックがこの flow へのショートカット入口\n\n### Referenced Endpoints\n- `endpoints/search-items.ts` — 照会とフィルタ\n- `endpoints/submit-action.ts` — メインアクション送信\n\n### Happy Path\n1. ユーザーが必要条件を設定\n2. システムが選択可能な結果を表示\n3. ユーザーがメインアクションを完了し成功状態を確認\n\n### Edge Cases\n- 結果なしの場合に空状態メッセージを表示\n- 条件不一致時に次ステップへの進入を阻止\n\n### PM 確認待ち\n- 特定の身份タイプに異なる割引ルールがあるべきか？code に分岐があるがビジネス説明なし（`src/legacy/Pricing.tsx:120`）\n\n### Unverified Logic\n- `src/legacy/foo.ts:88` — 分岐が一度も発火せず、原因不明\n\n### Scoped Files\n| ファイル | 帰属 |\n|---|---|\n| src/pages/Booking.tsx | Happy Path + Edge Cases |\n| src/utils/legacyCoupon.ts | Edge Cases: クーポン期限切れ |\n| src/deprecated/oldFlow.ts | Dead Code（ルート参照なし確認済み） |\n| src/hooks/useMystery.ts | → Unverified Logic |\n\n---\n# endpoints/submit-action.ts（同一 Record 産出、抽象例）\n\n/** @endpoint POST /api/some-action */\ninterface RawActionResponse {\n  /** フィールド語意は確認待ち。文字通りの意味ではない可能性 */\n  status_code: string;\n  payload: unknown;\n}"},{"emoji":"📐","title":"データ境界プランナー (Data Boundary Planner)","task":"考古産出の upstream を起点に、To-be Frontend Interface を定義し、コンポーネントと Store に散在する変換ロジックを Transformer に集約。live API には直接触らない。","input":["docs/records/flows/[flow-name]/flow.md","docs/records/endpoints/[endpoint-name].ts","旧 component／store から集約すべき transform 断片","既存 docs/main/contract-schemas/shared/"],"output":["docs/main/contract-schemas/endpoints/[endpoint-name].md","（必要時）docs/main/contract-schemas/shared/[entity].md","CONTEXT.md（glossary 増分更新）"],"ai_recommendation":{"tool":"claude","model":"Opus 4.6","tier":"required","hint":"型精度要求高"},"spec_summary":"contract-schema テンプレート要件を展開","spec_example_note":"以下は抽象例。本プロジェクトの実際の API やフィールドではない。","spec_sections":[{"title":"Upstream Schema（records/endpoints/ 参照）","desc":"Role 1 産出の .ts を SSOT とし、フィールド語意の曖昧さと既知のバックエンド癖を記載。"},{"title":"Target TypeScript Interface","desc":"To-be フロントエンド純粋型。JSDoc で @upstream_source と @old_logic_location を記載。"},{"title":"Transformer Pure Functions","desc":"実行可能な TypeScript 変換関数プロトタイプ。component／store の衍生計算を集約。"}],"spec_code":"/** @upstream_source records/endpoints/submit-action.ts */\n\n// --- Upstream（考古産物参照、要約） ---\n// status_code: string  — HTTP status ではなくビジネスステータスコード\n\n// --- Target Interface ---\ninterface ActionViewModel {\n  /** @old_logic_location src/legacy/ConfirmPanel.tsx:42 */\n  isSuccess: boolean;\n  displayMessage: string;\n}\n\n// --- Transformer ---\nfunction transformActionResponse(raw: RawActionResponse): ActionViewModel {\n  return {\n    isSuccess: raw.status_code === 'OK',\n    displayMessage: raw.payload?.message ?? '',\n  };\n}"},{"emoji":"✍️","title":"行為テストアーキテクト (Behavior Test Architect)","task":"flow.md のビジネスロジックを実装解耦の BDD ケースに変換し、flow.md 章節とのトレーサブルな整合を維持。","input":["docs/records/flows/[flow-name]/flow.md","docs/main/contract-schemas/endpoints/ + shared/"],"output":["docs/records/flows/[flow-name]/e2e-cases.feature"],"ai_recommendation":{"tool":"claude","model":"Sonnet 4.5","tier":"budget","hint":"構造化 BDD 出力"},"spec_summary":"BDD テンプレート要件を展開","spec_example_note":"以下は抽象例。本プロジェクトの実際のシナリオではない。","spec_sections":[{"title":"Gherkin 構文","desc":"Given-When-Then 構文必須。"},{"title":"flow.md とのカバレッジ整合","desc":"Happy Path に最低 1 Scenario。各 Edge Case に最低 1 Scenario。各 Scenario 上部に comment で対応 flow.md 章節を記載。"},{"title":"PM 確認待ち / Unverified Logic は Scenario を書かない","desc":"ビジネス確認待ち項目と code の謎は Scenario に書かない。feature ファイル先頭 comment に分けて列挙し、flow.md 対応章節を参照。"},{"title":"基建エラー除外","desc":"404/500/ネットワーク断はグローバル Client が処理。Feature ファイルに書かない。"}],"spec_code":"# PM 確認待ち（flow.md § PM 確認待ち 参照）:\n# - 特定身份の割引ルールは確認待ち\n\n# log 検証待ち（flow.md § Unverified Logic 参照）:\n# - src/legacy/foo.ts:88 — 分岐が一度も発火せず\n\n# flow.md § Happy Path に対応\nScenario: ユーザーがメインアクションを完了\n  Given ユーザーが有効な条件を設定済み\n  When ユーザーがメインアクションを送信\n  Then 画面に成功状態が表示される\n\n# flow.md § Edge Cases: 結果なし に対応\nScenario: 照会条件に一致なし\n  Given ユーザーが有効な照会条件を設定済み\n  When システムが空の結果セットを返す\n  Then 画面に空状態メッセージが表示される"},{"emoji":"⚖️","title":"文書棚卸員 (Documentation Auditor)","task":"再考古しない。Role 1–3 のテンプレート契約が履行されたかを検証：AI が L1 カバレッジマップと L2 構造ゲートを実行して gap report を産出、人間が L3 サンプリング承認後 survey-checklist.md を更新。","input":["legacy ファイルツリー","docs/records/ と docs/main/ の既存産出物","各 Record の flow.md § Scoped Files"],"output":["docs/survey-checklist.md","四区 + 各 Record の L1/L2/L3 サブチェック"],"ai_recommendation":{"tool":"claude","model":"Sonnet 4.5","tier":"budget","hint":"L1/L2 自動検証。L3 人手サンプリング承認"},"spec_summary":"L2 構造ゲート詳細を展開","spec_sections":[{"title":"L1 カバレッジマップ","desc":"flow.md § Scoped Files と照合：scope 内の各 .ts/.tsx が「flow 参照 / Dead Code / Unverified / 他 flow 相互参照」のいずれかに該当。未帰属 = 0。"},{"title":"L2 構造ゲート — flow.md","desc":"七章節完備：Entry Points、Referenced Endpoints、Happy Path、Edge Cases、PM 確認待ち、Unverified Logic、Scoped Files。"},{"title":"L2 構造ゲート — endpoint 閉環","desc":"Referenced Endpoints 各々に records/endpoints/*.ts + main/contract-schemas/endpoints/*.md がある。"},{"title":"L2 構造ゲート — BDD 整合","desc":"Scenario 数 ≥ 1（Happy Path）+ Edge Cases 件数。各 Scenario comment に対応 flow.md 章節がある。"},{"title":"L2 構造ゲート — transform 集約","desc":"contract-schema の @old_logic_location が指すファイルは Scoped Files に出現必須。"},{"title":"L3 人手サンプリング","desc":"本節下記「L3 人手サンプリングリスト」参照。静的ページは L1 のみ。Endpoints は L2 のみ。"}],"spec_code":"## Flows\n- [ ] booking-flow\n  - [ ] L1 カバレッジマップ：未帰属ファイル 0\n  - [ ] L2 構造ゲート：5/5 合格\n  - [ ] L3 サンプリング：3/3 合格（YYYY-MM-DD by @reviewer）\n\n## Endpoints\n- [x] post-reservation.ts — L2 合格\n\n## Static Pages\n- [x] /faq — L1 合格\n\n## Global Constraints\n- [ ] session-expiry — L2 + L3 検証待ち"}]},"s4":{"emoji":"🔄","heading":"コア考古棚卸フローと実行 SUPPLEMENT","subheading":"三種類の考古産物の優先順位と棚卸深度。ビジネス不確定項目は考古期にマーク。棚卸凍結後 Docusaurus 経由で PM と整合。","example_callout":"⚠️ 以下の「既知の例」は現時点のプロジェクト認識に基づく。実際の flow リストと命名は考古段階で codebase から定義。","pm_clarification_heading":"ビジネス不確定項目の三層処理","pm_clarification_items":["考古期：code の謎 → flow.md § Unverified Logic。ビジネス意図／シナリオ不明 → flow.md § PM 確認待ち","棚卸凍結 → Docusaurus：すべての「PM 確認待ち」を Open Questions 専用セクションに集約","PM 整合後：議論通過分を main/ To-be に記述。依然不確定なものは TODO + 本番 log として残す"],"card_scope_label":"範囲","card_standard_label":"棚卸基準","table_cols":["カテゴリ","優先度","範囲","棚卸基準"],"table_rows":[{"category":"コア業務フロー (Core Domain Flows)","priority":"最高優先","priority_type":"emerald","scope":"ページ横断で完全 User Journey があるフロー（考古時 codebase から定義）。既知の例：予約メインフロー、検索フィルタ、Email ディープリンク入口の Coupon フロー。","standard":"4 ロール pipeline + Role 4 三層検証を完了必須。flow.md + contract-schemas + BDD を産出。ビジネス不確定項目は「PM 確認待ち」にマーク。"},{"category":"静的・コンテンツページ (Static & Content)","priority":"簡易棚卸","priority_type":"blue","scope":"ナビページ、FAQ、Top Page ブロック等（CMS なし、フロント翻訳ファイルに保存）。Affiliate 紹介ページ（外部フォームへ誘導、サイト内に完全タスクなし）もこの類。","standard":"schemas と BDD 不要。docs/main/pages/ にページブロックと i18n key をリスト。"},{"category":"グローバル施設・制約 (Global Infrastructure)","priority":"global-constraints 集約","priority_type":"indigo","scope":"認証状態有効期限（Session ライフサイクル）、エラー試行回数制限（防刷プロンプト）、グローバル状態と URL 同期（言語・通貨の URL リフレッシュ）","standard":"ページ横断の横断ロジック。docs/records/global-constraints/e2e-cases.feature に集約。Role 4 L2 + L3 必須。"}]},"s5":{"emoji":"🔒","heading":"変更管理と Scope 凍結","subheading":"二つの関門：棚卸凍結（技術的完備）→ Scope 凍結（PM 判断）。spec と Figma を PM と確認後、「当面変更しない」ブロックから刷新を開始。","freeze_callout":"checklist 100% → 棚卸凍結 → Docusaurus 産出。spec + Figma を PM に持ち込み Scope 凍結：どのブロックが先行リファクタ可、どれが後続調整待ちか。着手は PM が当面変更しないと確認した部分から。","two_gates_heading":"二つの凍結関門","two_gates_cols":["関門","トリガー条件","産出"],"two_gates_rows":[{"gate":"棚卸凍結","trigger":"survey-checklist 100%","output":"Docusaurus 公開可能。Open Questions 集約完了"},{"gate":"Scope 凍結","trigger":"PM が spec + Figma でブロック単位の判断完了","output":"各 flow／ページに「先行リファクタ可」または「後続調整待ち」をマーク"}],"phase1_title":"第一段階（考古期）","phase1_items":["records/ に As-is を記録。main/ に To-be contract-schemas を蓄積。","flow.md に「PM 確認待ち」と Unverified Logic をマーク。","checklist 100% 達成 → 棚卸凍結、Docusaurus を整理（Open Questions 含む）。"],"phase2_title":"第二段階（PM 整合期）","phase2_items":["Docusaurus spec と Figma As-is 稿を PM に持ち込みブロック単位で確認（s6 参照）——後続調整待ち項目を含み、両方とも不可欠。","議論：どれが現行ロジック維持、どれをリファクタ、どれがフロー再考が必要か。","Open Questions を一件ずつクローズ、または Scope 判断にエスカレート。","各 flow／ページに Scope をマーク（下記参照）。"],"scope_decisions_heading":"Scope 判断タグ","scope_decisions_intro":"PM 整合のコア産出。判断は Docusaurus 各ページの badge に記録し、main/ ファイル frontmatter に書き戻す（scope: stable | pending）。","scope_decisions_cols":["タグ","PM の意味","次のステップ"],"scope_decisions_rows":[{"label":"先行リファクタ可","meaning":"PM がこのブロックのビジネスロジックやフローは当面変更しないと確認","next":"リファクタ着手を優先配分"},{"label":"後続調整待ち","meaning":"PM がこのブロックは将来調整、リファクタ、またはフロー再考すると示す","next":"第一ラウンドでも spec + Figma As-is は PM 判断用に必要。着手と To-be 設計は保留。「先行リファクタ可」完了後、第二ラウンドで更新 spec + Figma を PM と議論"}],"phase3_title":"第三段階（リファクタ着手期）","phase3_items":["Scope が「先行リファクタ可」のブロックから開発開始。「後続調整待ち」項目には触れない。","「後続調整待ち」項目：他の刷新が一段落後、PM と再議論し spec + Figma を更新。","Feature Branch で docs/main/（To-be）を修正。PR に CHANGELOG.md 添付（Ticket Link + 変更文書）。","コードリリース時に文書も Merge。「コード即文書、文書即コード」。"]},"s6":{"emoji":"🧱","heading":"Figma デザインシステムと三層 Token アーキテクチャ","subheading":"s5 PM 整合を支援：spec と Figma As-is はペアで提示。考古期は Figma に触れない。棚卸凍結後に As-is キャンバスを構築。Scope 凍結後「先行リファクタ可」項目のみ To-be を更新。","timeline_heading":"Figma 四段階タイムライン（s5 と整合）","timeline_steps":["① 考古期：フロントは Figma に触れない。任意——デザイナーに新 Token アーキテクチャで本番サイトを先行同期（As-is 還元）を code 考古と並行依頼。","② 棚卸凍結後：spec に基づき Figma As-is キャンバスを構築／補完（本番と 100% 一致）。Docusaurus 産出と並行。","③ PM 整合期：すべての flow／ページ（後続調整待ち含む）で spec + Figma As-is をセットで PM 確認。","④ リファクタ着手：「先行リファクタ可」項目のみ Figma To-be を更新。「後続調整待ち」は As-is 維持、第二ラウンド PM 議論後に変更。"],"pm_deliverable_callout":"PM 整合の最低交付物：各 flow の主要画面 + 静的ページブロック。spec（Docusaurus）と Figma As-is はどちらも不可欠。","kit_callout":"Figma 起点：Obra shadcn/ui kit をコミュニティテンプレートとして使用（https://obra.studio/work/figma-shadcn-ui-kit/）。各プロジェクトローカルに複製後 Token と As-is キャンバスを上書き。ゼロからコンポーネントライブラリを構築しない。コード側は shadcn/ui CLI と連携。","intro_p1":"マルチプロダクト「孤島式保守」：Figma Professional はファイル横断 Variables 連動不可。「中央テンプレート（Obra kit + shadcn コンポーネント）、ローカルカスタマイズ」を採用——テンプレ複製、ブランド色マッピング、As-is キャンバス還元。","intro_p2":"Token 三層は Obra／shadcn 哲学と一致：底層 Raw は Tailwind palette 命名。Brand は 100–900 スケール構築。Semantic は shadcn に整合しビジネス専用色を集約。キャンバスは Semantic のみバインド。","pro_warning":"⚠️ Figma Variables の作成には Pro plan の Full seat が必要（Collab seat 不可）。","token_rule":"三層 Token 物理隔離：キャンバスは Semantic Token のみ使用可能かつ必須。Raw（Tailwind palette）と Brand（100–900 スケール）はキャンバス直接バインド禁止。","token_cols":["層級 (Layer)","命名規範","コード側対照","デザイナー権限"],"token_rows":[{"layer":"1. Raw / Primitives 🔒","figma":"Tailwind CSS palette と同名（例：slate-500、blue-600、neutral-100）","css":"tailwind.config / @theme 底層色票","access":"❌ キャンバスバインド禁止。色彩大辞書。"},{"layer":"2. Brand 🔒","figma":"サイトブランド色 100–900 スケール（例：brand-blue-100、brand-orange-500）","css":"theme で brand scale 定義。キャンバス露出は Semantic alias 経由（例：--brand-pink）","access":"❌ キャンバスバインド禁止。"},{"layer":"3. Semantic 🔓","figma":"shadcn 標準（background、primary、muted…）+ ビジネス語意（例：link、brand-pink）","css":"globals.css :root — shadcn 内蔵（--background、--primary…）+ カスタム（--link、--brand-pink）","access":"🔓 唯一合法。Raw または Brand から色を選択してバインド。"}],"token_semantic_heading":"Semantic 層ルール","token_semantic_rules":["shadcn 内蔵 semantic を優先（background、foreground、primary、muted、destructive…）。","Semantic 色の出典：Raw（Tailwind palette）または Brand（100–900）から選択し alias を作成。","shadcn 未カバーの brand／ビジネス色：Semantic 層で命名（例：link、brand-pink）。globals.css :root に CSS variable を追加し Brand または Raw を指す。","Figma Semantic Variables と :root 変数名を 1:1 整合（shadcn/ui CLI 慣例に従う）。"],"fold_org_content":"中央 Workspace → Obra shadcn/ui kit テンプレート（Raw Tailwind palette + shadcn 標準コンポーネント）。各プロジェクトローカル → kit 複製、Brand スケールと Semantic mapping を上書き、As-is 画面を 100% 還元。","fold_pattern_central":"中央保守：100% ビジネスロジック視覚一致、カスタマイズ不可（例：日本地図セレクター）→ Copy-Paste。","fold_pattern_local":"ローカル保守：プロダクトラインで意味が変わる複合コンポーネント（例：BookingCard、CouponSelector）→ 中央 shadcn 基礎 + ローカル組立。","fold_align_desc":"Figma キャンバスには英語可読文案のみ（会社サイト主ロケールは EN）。i18n key は置かず、Variables Mode で翻訳も管理しない。","fold_align_rules":["Description にデザイン備考可（key ではない）：動的文案（API レスポンス）、プレースホルダ／文字数上限、truncation リスク、PM 文案未定、または Docusaurus spec 章節へのリンク。","Sticky／Comment は PM 整合期の議論用のみ。長期 SSOT ではない。","i18n key と多言語対照：legacy 考古 → JSON → Google Sheet → code（s7 参照）。静的ページは docs/main/pages/ にブロック + key もリスト。リファクタ時は「画面 + spec／Sheet」で対照。Figma から key を逆引きしない。"],"fold_align_example":"キャンバス：\"Please enter your booking code\" → Description：「予約コード placeholder。静的文案。booking flow spec §2 参照」——booking.field.code_placeholder ではない。"},"s7":{"emoji":"🌍","heading":"多言語 (i18n) 全自動パイプライン","figma_boundary":"Figma は英語可読文案のみ表示（主ロケール EN）。i18n SSOT ではない。key と翻訳は考古 JSON → Sheet → code が正。デザイン稿 Description はデザイン語意備考のみ（s6 参照）。","sheet_ssot":"考古期に legacy 各ロケール翻訳は既存——整理はフォーマット清洗、namespace／key リネーム、status マークのみ。再翻訳しない。Sheet 書き込み時 en／ja／zh_TW 等の列は既に揃っているべき。Sheet が完全対照表。","toolchain_note":"ツールチェーン：考古は Claude Web で整理 JSON 産出、刷新は Cursor。目標フレームワーク i18next → next-intl。フォーマットは next-intl 慣例に調整。status は unused／in-progress。","gemini_rule":"Gemini は考古必須ステップではない：Sheet に legacy 全ロケール含む。refactor で key 追加（in-progress）または人手委託翻訳時のみ Gemini で Sheet 操作可。Instruction Sheet に Tone Guide を配置して補訳参考。","iron_rule":"System Prompt 級グローバル鉄則：必要な翻訳が JSON に存在しない場合、新 Key の創作禁止。まずコードで Hardcode し // TODO: i18n-missing マークでバッチ抽出。","migration_heading":"i18next → next-intl 整理ルール","normalize_rules":["フレームワーク移行：i18next 構造から next-intl 慣例に整理（namespace + key、JSON／message フォーマットは next-intl 同期スクリプト出力に従う）。","余分な空白は積極削除しない——legacy はレイアウト用に意図的保持の可能性。整理時はそのまま Sheet に持ち込む。","改行マージ：legacy が配列 [a, b, c] で文を分け map レンダリングする場合、単一 key 内 \\n 改行に整理（例：\"Line one\\nLine two\\nLine three\"）。訳者が同一列で編集しやすくする。","補間構文：考古整理時 i18next {{var}} を next-intl {var} に直接変換。Sheet 書き込みが終態。sync script は読み書きのみ、フォーマット変換しない——将来再利用のため。","コード側：\\n を含む文案は CSS whitespace-pre-line（または同等）でレンダリング。コンポーネント内で配列 map 分句しない。"],"namespace_heading":"Namespace 分割","namespace_rules":["単一 domain プロジェクト：「ページ／画面」を namespace 単位。-page サフィックスなし（例：checkout、affiliate-intro）。","ページ横断共有文案 → common。各ページは自分の namespace + common のみ参照。Flow 専用 namespace は設けない——flow 内各ステップ画面は対応ページの翻訳を使用。","slug は docs/main/pages/、Figma frame 名、ルート Entry screen と整合。整理時 legacy_key は旧名を保持して比対。"],"fold_json_content":"JSON フォーマット例：status, namespace, key, legacy_key, en, ja, zh_TW, description。\n\n各ロケール値は legacy translations から持ち込み（空殻待訳ではない）。例：namespace checkout + key coupon.btn.apply。legacy_key は script 欠落比対用。","sync_heading":"Sheet → code 出力構造","sync_rules":["namespace 単位でファイル分割：messages/{locale}/{namespace}.json（例：messages/en/common.json、messages/en/checkout.json）。","ファイル内 JSON はネスト（例：{ \"coupon\": { \"btn\": { \"apply\": \"…\" } } }）。Sheet の key 列は dot notation（coupon.btn.apply）のまま編集しやすく。sync script が code 書き込み時にネスト展開。","Sheet namespace 列とファイル名 1:1。ページは useTranslations('{namespace}') + t('coupon.btn.apply')。common はページ横断共有。"],"steps":["AI が legacy 翻訳を JSON に整理（i18next → next-intl。{{var}} → {var}。配列改行を \\n にマージ。余分空白は trim しない）","Script が legacy_key と元 translations を比対し欠落チェック（動的 key は手動で active マーク）","Script が Google Spreadsheet に書き込み（単一 sheet + namespace 列。各ロケール列は揃っている）","新プロジェクト sync script：Sheet → messages/{locale}/{namespace}.json（dot key をネスト JSON に。unused フィルタ、in-progress は 🚧 表示）","SKILL.md 鉄則：key 欠落時は創作禁止。hardcode + // TODO: i18n-missing。新 key は in-progress マーク後に補訳"]},"s8":{"emoji":"🏁","heading":"棚卸、校対と刷新開始","validation_heading":"平行対照と刷新しきい値","validation_items":["新旧プロジェクトを同一 workspace に配置し前後対照。","\\n を含む複数行文案：フロントは CSS whitespace-pre-line を使用（s7 改行マージルール参照）。配列 map 分句はしない。","棚卸凍結後、records/ + main/ 棚卸文書を Docusaurus 形式に整理し独立 repo デプロイ、PM と整合（作業ディレクトリ自体は PM 向けではない）。"],"gate_heading":"Phase 3 着手と検収（三段階）","gate_project_heading":"1. プロジェクト級（Phase 3 着手前、一度のみ）","gate_project_items":["棚卸凍結（survey-checklist 100%）","Docusaurus 整理・デプロイ済み","Figma As-is 100% 準備完了（棚卸凍結後 Docusaurus と並行完了。Scope 凍結の前提）","Scope 凍結完了：各 flow／ページに先行リファクタ可または後続調整待ちをマーク","後続調整待ち項目も第一ラウンドで spec + Figma As-is は必要だが、着手プールには入れない"],"gate_issue_heading":"2. 単一 Issue／垂直スライス（先行リファクタ可のみ）","gate_issue_cols":["Issue タイプ","着手前の最低要件"],"gate_issue_rows":[{"type":"Schema / Transformer / 純関数","requirement":"flow.md + main/contract-schemas/ 仕様で十分 → TDD 着手"},{"type":"UI コンポーネント／ページ","requirement":"上記 + 該当ブロックの Figma To-be（先行リファクタ可項目）"},{"type":"Flow（BDD あり）","requirement":"Happy Path Scenarios 記述済み。PM 確認待ち／Unverified Logic は comment 維持、Scenario は書かない"},{"type":"Static Pages","requirement":"docs/main/pages/ ブロック + i18n key リストで十分。BDD 不要"}],"gate_merge_heading":"3. マージ／リリース前（検収。着手しきい値ではない）","gate_merge_items":["該当スライスの BDD 全緑（Scenario 記述済み flow）","AI L1/L2 構造検証 + 人手 L3 spot-check（s3 参照）","PM が該当先行リファクタ可ブロックを sign-off（Docusaurus spec + Figma To-be 対照）"],"log_rule_heading":"Unverified Logic 観測鉄則","log_rule":"リファクタ時のロジック行為は legacy と整合必須。flow.md § Unverified Logic に列挙された分岐は、refactor 版に runtime log を追加し依然発火するか観測——サイレント削除・スキップ禁止。","log_rule_items":["考古期にマーク済み Unverified Logic：同等分岐を保持し log 追加（flow.md ファイル位置を参照）。","観測期間に hit ゼロ → 分岐削除可。flow.md § Scoped Files を更新。","リファクタ中に新たな説明不能分岐を発見：まず flow.md § Unverified Logic に追記してから log 追加。直接削除禁止。"],"skills_heading":"Issue 分割と Matt Pocock Agent Skills","skills_subheading":"Issues を 5 大 Agent Skills に分割。monorepo 特性を活用。Issue 並行タスク。","skills_cols":["Skill","説明","推奨 AI","段階"],"skills_rows":[{"name":"Grill-with-Docs","desc":"考古文書と組み合わせ、設計ツリーに沿って判断分岐を明確化","ai":"Claude Opus 4.6","phase":"計画"},{"name":"To-PRD","desc":"合意から PRD を産出。User Stories とモジュール草案含む","ai":"Claude Sonnet 4.5","phase":"計画"},{"name":"To-Issues","desc":"PRD を垂直スライス Issue に分解。blocking 関係を構築","ai":"Claude Sonnet 4.5","phase":"計画"},{"name":"TDD","desc":"赤緑リファクタ循環。一行テスト一行実装。リファクタ漏れ防止","ai":"Cursor Composer 2.5","phase":"開発"},{"name":"Architecture-Refactor","desc":"浅いモジュールを深化。テスト境界を明確化し Agent の安定ナビを実現","ai":"Cursor Composer 2.5","phase":"開発"}],"refs_heading":"技術参考リンク","refs":[{"label":"Stop writing docs by hand","url":"https://www.aihero.dev/5-agent-skills-i-use-every-day"},{"label":"Playwright BDD","url":"https://playwright.dev/docs/test-agents"}],"issues_heading":"原子化 Issue 例","issues":[{"id":"#01","tag":"Schema","title":"transformBookingAmount 純関数を実装","blocks":"先行リファクタ可 + flow.md／schema 準備完了で着手可"},{"id":"#02","tag":"UI","title":"Figma To-be に基づき BookingCard 静的コンポーネントを実装","blocks":"#01 にブロック。該当ブロックの To-be 稿が必要"},{"id":"#03","tag":"BDD","title":"予約コード検証 Edge Cases 検収ケースを記述","blocks":"#01 と並行可。マージ前に BDD 緑必須"}],"roadmap_heading":"Roadmap","roadmap":[{"title":"Phase 1：考古と棚卸凍結","desc":"4 ロール Skills → records/ + main/ → checklist 100%（棚卸凍結）。続けて Docusaurus と Figma As-is を並行産出（s6 ②、本番と 100% 一致）——両方準備完了で Phase 2 へ。考古期 ① は kit 同期任意。"},{"title":"Phase 2：Scope 凍結","desc":"前提充足：Docusaurus spec + Figma As-is 両方揃い。PM が各 flow／ページをペアで確認し、先行リファクタ可／後続調整待ちをマーク（s6 ③）。","risk":"🔥 リスク管理：Figma As-is 未完成では PM 整合に進めない"},{"title":"Phase 3：リファクタ着手","desc":"プロジェクト級 + Issue しきい値通過後、先行リファクタ可の垂直スライスのみ着手。Figma To-be は UI Issue とともに段階更新（s6 ④）。マージ前 BDD + L3 + PM sign-off。"}],"roadmap_note":"Figma As-is はリファクタ時にやるものではない——Phase 2 PM 整合の硬性前提。Docusaurus と並行して棚卸凍結後に完了。"},"s9":{"emoji":"🛡️","heading":"API データ境界：BFF なし、Zod + Transformers","subheading":"「前後端職責拆分と BFF 設計」の議論後の結論：BFF を別途構築せず、フロントが Core API を fetch 後 Zod で runtime 検証とデータ正規化（Parse, don't validate）。s3 データ境界プランナー産出の contract-schemas と整合。","decision_callout":"BFF 層を構築しない——infra とデプロイコストを削減。フロント `httpClient` がバックエンドに直結。client 側で Zod Schema + Transformer が legacy 奇異フォーマットを集約。コンポーネントは Clean Type のみ受け取る。","layers_heading":"三層防線","layers_cols":["層級","職責","産物"],"layers_rows":[{"layer":"1. Upstream（考古）","role":"Role 1 が codebase からバックエンド Raw 構造を推測","artifact":"docs/records/endpoints/[endpoint-name].ts"},{"layer":"2. Contract（仕様 SSOT）","role":"Role 2 が Frontend Interface + Transformer プロトタイプを定義","artifact":"docs/main/contract-schemas/endpoints/[name].md"},{"layer":"3. Runtime（コード）","role":"refactor が Zod parse + transform + handleResponse を実装","artifact":"lib/api/[endpoint-name]/{schema,transformer,index}.ts"}],"runtime_heading":"Runtime パターン（client-side normalization）","runtime_steps":["httpClient fetch Core API → unknown を取得","Zod Backend*Schema.safeParse — HTML／非 JSON／フィールドドリフトを遮断（ApiProtocolError）",".transform() でフロント Clean Type に変換（snake_case、語意フィールド、冗長除去）","統一 ApiResponseSuccess / ApiResponseError envelope — ビジネスエラーは ApiBusinessError を throw","React／Store は Clean Type のみ import。Raw JSON 直接接触禁止"],"error_heading":"Error 分類","error_cols":["タイプ","トリガー","処理"],"error_rows":[{"type":"ApiProtocolError","trigger":"非 JSON、HTML エラーページ、Zod parse 失敗","handling":"log + 統一エラー UI。s1「error 形式不統一」根本原因に対応"},{"type":"ApiBusinessError","trigger":"バックエンドが { error: { code, message } } を返す","handling":"code で分岐。コンポーネント内の通霊判断は廃止"}],"proto_heading":"プロトタイプ参考（backend/ — 一時停止中）","proto_intro":"上記パターンで複数 endpoint を実装済み（get-bus-list、get-locations、submit-contact…）。各々 schema.ts（Backend + Clean）、transformer.ts、index.ts。共通 handleResponse と contract.ts。","proto_structure":["backend/[endpoint-name]/schema.ts — Backend*Schema（Zod）+ Clean Type","backend/[endpoint-name]/transformer.ts — request／response transform","backend/[endpoint-name]/index.ts — httpClient + handleResponse","backend/utils/handle-response.ts — safeParse 統一入口","backend/contract.ts — ApiResponseSuccess / ApiResponseError"],"proto_pause_heading":"一時停止の理由","proto_pause_items":["endpoint 数増加後、フォルダ間で迷子になりやすい——flow／考古産物との命名対照 SSOT が不足","Backend 命名（PascalCase、ネスト XML 風）とフロント Clean 命名の API 横断整合が困難","shared entity（例：BusFacilities）と各 endpoint 境界が不明確。重複定義リスク"],"plan_bridge_heading":"刷新計画の継続方法","plan_bridge_items":["考古期：records/endpoints/[name].ts と flow.md § Referenced Endpoints が 1:1——endpoint リストを記憶頼みにしない","計画期：contract-schemas/endpoints/[name].md が命名と Transformer の SSOT。shared/ で endpoint 横断 entity を集約","code ディレクトリ slug は contract-schemas ファイル名と整合（例：get-bus-list）。1 endpoint 1 フォルダ","最初の vertical slice で golden sample 定義（Zod + test 含む）。以降 endpoint は構造を複製、再発明しない","Role 2 着手前に contract-schemas/shared/ を必ず確認。同一 entity の重複定義禁止"],"bff_note":"BFF 議論で評価した地点検索、7k 件キャッシュ等——大半はフロント IndexedDB + ローカル filter で対応可能。地理演算が必要な少数シナリオのみバックエンド。デフォルトルートは client-side transformer。別 BFF service は開かない。"},"footer":{"text":"Project Renovation & Refactor Plan"}},"ko":{"meta":{"title":"프로젝트 전면 개편: AI 기반 애자일 고고학과 리팩터링 계획"},"common":{"label_input":"Input","label_output":"Output","fold_specs":"상세 사양 요건 펼치기","fold_doc_tree":"📂 클릭하여 펼치기: 고고학 기간 작업 디렉터리（records/ + main/, Agent 기록）","fold_figma_org":"조직 구조: 중앙 템플릿, 로컬 커스터마이징","fold_figma_pattern":"비즈니스 모듈 유지보수 경계","fold_figma_align":"Figma 문구와 i18n 경계","fold_i18n_json":"🔍 보기: i18n 데이터 타입 및 스크립트 규격 상세","fold_i18n_steps":"번역 준비 전체 단계（총 {n}단계）","fold_deliverables":"산출물 목록","tier_budget":"비용 절감 가능","tier_required":"필수","tier_context":"컨텍스트 필요","tier_human":"수동","tool_claude":"Claude","tool_cursor":"Cursor","tool_human":"수동","audit_layers_label":"고고학 검증 3계층（Role 4）","issue_tag_legend_heading":"Issue 유형 태그","issue_tag_legend":[{"tag":"Schema","meaning":"데이터 경계／Transformer／순수 함수"},{"tag":"UI","meaning":"컴포넌트 또는 페이지. Figma To-be 필요"},{"tag":"BDD","meaning":"Flow 검수 케이스. 머지 전 전체 통과 필수"}],"glossary":{"L1":{"short":"커버리지 맵","tip":"flow.md § Scoped Files와 대조: scope 내 각 .ts/.tsx에 귀속이 있어야 함. AI가 자동 검증, 미귀속 파일 = 0."},"L2":{"short":"구조 게이트","tip":"flow 7개 섹션, endpoint 폐루프, BDD 정렬, transform 통합. AI가 gap report를 출력, 전부 통과 시 합격."},"L3":{"short":"수동 샘플링","tip":"소스 코드와 무작위 대조하여 고고학 내용이 채워진 것뿐 아니라 정확한지 확인. 사람이 승인, 핵심 flow는 5건 권장."},"4개 구역":{"short":"survey-checklist 4개 구역","tip":"Flows, Endpoints, Static Pages, Global Constraints——인벤토리 동결에는 4개 구역 100% 체크 필수."},"우선 리팩터링":{"short":"Scope 태그","tip":"Phase 2 PM 정렬 후 즉시 착수 가능한 flow／페이지로 표시. Phase 3는 이 유형만 착수 풀에 포함."},"추후 정렬":{"short":"Scope 태그","tip":"spec + Figma As-is는 준비 필수이나 refactor 1라운드에서는 건드리지 않음. 나머지 개편이 한 차례 마무리된 뒤 PM과 To-be를 업데이트."},"As-is":{"short":"현황 복원 고","tip":"프로덕션 환경과 100% 일치하는 Figma 캔버스. Phase 2 PM 정렬의 필수 전제."},"To-be":{"short":"목표 설계 고","tip":"리팩터 착수 후 「우선 리팩터링」 항목만 점진적으로 업데이트. UI Issue 착수 전 해당 블록의 To-be 필요."}},"s9_layers_note":"이 「3계층 방어선」은 API 데이터 흐름（Upstream → Contract → Runtime）을 가리키며, 고고학 검증의 L1／L2／L3과는 다릅니다."},"hero":{"title":"프로젝트 전면 개편: AI 기반 애자일 고고학과 리팩터링 계획","subtitle":"AI 고고학으로 누락된 Specification（단계, 페이지, 플로우）을 보완하고, 프론트엔드 관점에서 API Schema를 명확히 하여 안정적인 Transformer를 구축하며, Figma 디자인 시스템을 재구축하고, Agent Skills 파이프라인으로 문서화 검수를 추진——디자인 불일치와 기술 부채를 체계적으로 줄입니다."},"toc":[{"id":"s1","label":"배경"},{"id":"s2","label":"최상위 아키텍처"},{"id":"s3","label":"4역할 Workflow"},{"id":"s4","label":"고고학 인벤토리"},{"id":"s5","label":"동결 관리"},{"id":"s6","label":"Figma 디자인 시스템"},{"id":"s7","label":"다국어"},{"id":"s8","label":"개편 시작"},{"id":"s9","label":"API 경계와 Zod"}],"s1":{"emoji":"🛑","heading":"배경 및 현황 문제점 인벤토리","table_cols":["문제점","영향","근본 원인"],"table_rows":[{"pain":"사양서 부재","impact":"비즈니스 로직 대조 불가, 변경 리스크 높음","cause":"비즈니스 로직을 대조할 표준 문서가 없음. 단계, 페이지, 플로우는 모두 코드에서 역추적하여 복원해야 함."},{"pain":"프론트엔드 코드 혼란","impact":"수정 비용 극대","cause":"비권장 패턴이 많아 특정 Framework Bug 발생 시 추적이 매우 어려움."},{"pain":"백엔드 사양 없음","impact":"프론트엔드 추측 판단","cause":"백엔드에 사양서가 없어 프론트 코드만으로는 응답 형식을 정확히 판단할 수 없음. 또한 백엔드의 잘못된 형식에 대한 임시 대응으로 프론트에 추가된 추측 로직. 이것이 후속 error 형식 혼란과 transform 분산의 상류 근본 원인."},{"pain":"Error 형식 불일치","impact":"더러운 로직 누적","cause":"error 응답 형식이 통일되지 않아 각 형식에 대응하는 더러운 로직이 프론트에 누적."},{"pain":"데이터 명명 혼란","impact":"리팩터 시 추적 어려움","cause":"프론트가 자체 transform 계층을 만들었으나 각처에 분산되어 있어, 리팩터 시 원래 value를 빠르게 찾기 어려움."},{"pain":"디자인 고와 프로덕션 환경 불일치","impact":"UI 복원이 추측에 의존, 디자인 반복 추적 불가","cause":"Figma가 codebase와 동기 유지보수되지 않아 프로덕션과 디자인 고가 장기간 불일치."}],"vision_heading":"현황 문제점 vs 개편 비전","as_is_title":"As-is 현황 문제점","to_be_title":"To-be 개편 비전","as_is_items":["비즈니스 로직을 대조할 사양서 없음","디자인 고와 프로덕션 환경 불일치","코드 퇴화, 기술 부채 누적","신규 온보딩 어려움, 추측 비용 높음","백엔드 형식 혼란, 프론트 transform 분산"],"to_be_items":["Specification이 비즈니스 로직 SSOT","고고학한 비즈니스 행위 모두에 BDD 검수 케이스","Figma 디자인 시스템과 코드 동기화","AI Agent 자동화 디스패치 + 인기 협업 경계 명확화","데이터 경계 분리, 클린 타입으로 더러운 데이터 대체"]},"s2":{"emoji":"🗺️","heading":"최상위 아키텍처, 문서 흐름 및 디렉터리 규격","subheading":"레거시 Codebase에서 인벤토리 동결까지의 완전한 산출 체인. 고고학 기간 작업 데이터는 records/와 main/에 기록. 인벤토리 완료 후 PM 정렬용 Docusaurus를 별도 산출.","example_callout":"⚠️ 본 섹션의 `[flow-name]`, `[endpoint-name]` 및 아래 예시 목록은 디렉터리 구조와 분할 세분성 설명용이며, 본 프로젝트의 실제 flow나 API가 아닙니다. 실제 이름과 경계는 고고학 단계에서 기존 codebase 비즈니스 로직에 따라 개별 정의.","taxonomy_heading":"고고학 산출물 3계층 분류","taxonomy_intro":"Flow가 유일한 분류 축이 아님. Endpoint 사양과 Flow는 직교——하나의 flow가 여러 endpoint를 참조할 수 있고, 하나의 endpoint가 여러 flow에서 공유될 수 있음.","taxonomy_cols":["계층","경로","세분성","고고학 깊이"],"taxonomy_rows":[{"tier":"User Flow（Record）","path":"docs/records/flows/[flow-name]/","granularity":"하나의 완전한 사용자 태스크（Entry → Terminal State）","depth":"flow.md + BDD + 참조 endpoints"},{"tier":"정적／콘텐츠","path":"docs/main/pages/","granularity":"한 페이지 또는 한 블록","depth":"블록 구조 + i18n key만 나열. schema / BDD는 작성하지 않음"},{"tier":"전역 제약","path":"docs/records/global-constraints/","granularity":"flow 횡단 횡단 로직","depth":"BDD만. 독립 flow.md 없음"}],"taxonomy_endpoint_note":"Endpoint 사양（docs/records/endpoints/）은 별도의 직교 축: endpoint당 1파일. 고고학 기간 upstream 구조를 추측하고, 플래너가 Frontend Interface + Transformer를 main/contract-schemas/endpoints/에 산출.","flow_granularity_heading":"Flow 분할 기준（Highway Bus 서비스 — 예시）","flow_granularity_rules":["사용자 태스크（User Journey） 단위로 분할. 페이지나 라우트로 분할하지 않음.","1 Record = 독립적으로 아카이브 가능한 완전한 여정（Entry Point → Terminal State）.","Endpoint 사양（endpoints/）과 Flow（flows/）는 직교: 하나의 flow가 여러 endpoint를 참조 가능, endpoint는 flow 횡단 공유 가능.","독립 Entry Point와 완전한 여정이 있는 것은 별도 flow（예: Email 딥링크 Coupon 플로우）. 다른 flow 도중에 발생하는 로직（예: 예약 도중 Coupon 적용）은 해당 flow의 Edge Cases에 기술.","외부 폼으로 유도, 사이트 내 완전한 태스크가 없는 소개 페이지（예: Affiliate）→ 정적 페이지 인벤토리, flow는 열지 않음.","flow 횡단 횡단 로직（Session 유효기간, 부정 사용 방지, URL 언어 동기화）→ global-constraints/에 통합."],"flow_examples_note":"아래는 분할 세분성 유형 예시만. [flow-name]은 placeholder이며, 본 프로젝트의 실제 flow 이름이 아님:","flow_examples":[{"name":"[search-flow]","desc":"검색 및 필터（status 기반 숨김 UI 상태 포함）"},{"name":"[booking-flow]","desc":"예약 메인 플로우（페이지 횡단 완전 여정）"},{"name":"[coupon-email-flow]","desc":"Email 딥링크 진입점 Coupon 플로우（독립 Entry Point）"},{"name":"[lookup-flow]","desc":"예약 조회／변경류 플로우"}],"endpoint_examples_note":"Endpoint 파일명도 예시. 고고학 시 실제 API 명명에 따름:","endpoint_examples":["search-routes.ts","get-seat-map.ts","post-reservation.ts","get-reservation.ts"],"diagram":"graph TD\n    Code[\"레거시 소스 코드\"] -->|Repomix 패키징 + Agent 탐색| R1[\"🕵️ 1.코드 고고학자\"]\n    R1 -->|As-is 비즈니스 행위| Flow[\"docs/records/flows/[flow-name]/flow.md\"]\n    R1 -->|endpoint 응답 구조 추측| Upstream[\"docs/records/endpoints/[endpoint-name].ts\"]\n    Flow --> R2[\"📐 2.데이터 경계 플래너\"]\n    Upstream --> R2\n    Comp[\"Components / Store 파생 로직\"] --> R2\n    R2 -->|Frontend Interface + Transformer| Schema[\"docs/main/contract-schemas/endpoints/\"]\n    R2 --> Ctx[\"CONTEXT.md\"]\n    Flow --> R3[\"✍️ 3.행위 테스트 아키텍트\"]\n    Schema --> R3\n    R3 -->|BDD 케이스| BDD[\"docs/records/flows/[flow-name]/e2e-cases.feature\"]\n    Flow --> R4[\"⚖️ 4.문서 인벤토리 담당\"]\n    Schema --> R4\n    BDD --> R4\n    R4 -->|Cover 검토| Check[\"docs/survey-checklist.md\"]\n    Check -->|100% Check| Freeze[\"인벤토리 동결\"]\n    Freeze -->|인벤토리 문서 정리| Docs[\"Docusaurus 문서 사이트\"]\n    Docs -->|PM 정렬| PM[\"비즈니스／기술 변경 논의\"]\n    Freeze -.->|개발자 reference| Ref[\"records/ + main/ 보존\"]","doc_tree_note":"아래는 고고학 및 리팩터 기간 작업 디렉터리. Agent 기록 및 개발자 참조, refactor 인용용. PM용 포맷이 아님.","docusaurus_heading":"인벤토리 완료 후: Docusaurus 산출","docusaurus_intro":"survey-checklist 100% 달성 후, 인벤토리 문서（records/ + main/ + CONTEXT.md）를 Docusaurus 형식으로 정리하여 독립 repo에서 문서 사이트 구축. PM과의 인지 정렬 공식 인터페이스. main/과 records/는 개발자 자용 및 refactor reference로 보존.","docusaurus_steps":["동결 후 인벤토리 문서를 source로 사용（고고학 기간부터 Docusaurus 작성하지 않음）","Skill / Script로 Docusaurus 구조 변환（MDX, sidebar, Admonitions 등）","각 flow.md § PM 확인 대기를 Open Questions 전용 섹션에 통합","독립 repo에서 문서 사이트 배포","이 사이트로 PM과 기술·비즈니스 변경 논의"],"doc_tree_cols":["경로","용도"],"doc_tree_rows":[{"path":"CONTEXT.md","desc":"전역 glossary（상시）. 고고학 기간 지속 업데이트, grill-with-docs에서 계승."},{"path":"docs/survey-checklist.md","desc":"고고학 진행 추적표. 4개 구역 + 각 Record의 L1/L2/L3 서브 체크."},{"path":"docs/records/","desc":"As-is 고고학 작업 구역. 개발자 참조 및 refactor reference. 인벤토리 동결 후 보존, PM 대외 인터페이스 아님."},{"path":"docs/records/flows/[flow-name]/flow.md","desc":"As-is 현황 비즈니스 플로우. 이름은 고고학 단계에서 codebase에서 정의（placeholder: [flow-name]）."},{"path":"docs/records/endpoints/[endpoint-name].ts","desc":"고고학 기간 codebase에서 추측한 단일 endpoint 원시 응답 구조（TypeScript type）. 이름은 고고학 단계에서 정의."},{"path":"docs/records/flows/[flow-name]/e2e-cases.feature","desc":"BDD 테스트 케이스."},{"path":"docs/main/flows/","desc":"확인된 As-is 플로우. 리팩터 기간 To-be SSOT 기반. 개발자 reference."},{"path":"docs/main/pages/","desc":"페이지 로직 인벤토리. 개발자 reference."},{"path":"docs/main/contract-schemas/shared/","desc":"전역 Entities（To-be）. 개발자 reference."},{"path":"docs/main/contract-schemas/endpoints/","desc":"Frontend Interface + Transformer（To-be）. 개발자 reference."}]},"s3":{"emoji":"🛠️","heading":"Skills Workflow로 데이터 산출","subheading":"4역할 핵심 태스크와 정확한 I/O. 기술 사양은 각 접이식에 수납. Role 4의 3계층 검증 플로우는 아래 전용 섹션 참조.","auditor_heading":"문서 인벤토리 3계층 검증 플로우","auditor_intro":"Role 4는 재고고학하지 않음. Role 1–3의 템플릿 계약 이행 여부를 검증. 「파일 누락」과 「상세 누락」을 분리 처리: L1/L2는 자동 검증 가능, L3는 수동 샘플링으로 소스 코드와 대조.","auditor_diagram":"flowchart TD\n    Draft[\"① AI 초안 checklist\"] --> L1[\"② L1 커버리지 맵<br/>미귀속 파일 = 0\"]\n    L1 --> L2[\"③ L2 구조 게이트<br/>템플릿 + 상호 참조\"]\n    L2 --> Gap[\"④ gap report\"]\n    Gap --> L3[\"⑤ L3 수동 샘플링<br/>소스 코드 대조\"]\n    L3 --> Check[\"⑥ survey-checklist 체크\"]\n    Check --> Freeze[\"4개 구역 100% → 동결\"]","auditor_workflow_heading":"각 Record의 실제 실행 단계","auditor_workflow_steps":["AI가 legacy 파일 트리와 기존 산출물에 기반하여 survey-checklist.md 4개 구역 항목을 초안 업데이트.","AI가 L1 실행: flow.md § Scoped Files와 대조하여 scope 내 각 .ts/.tsx에 귀속이 있는지 확인. 미귀속 파일 = 0.","AI가 L2 실행: flow 7개 섹션 완비, Referenced Endpoints 폐루프（upstream .ts + contract-schema .md）, BDD Scenario와 flow.md 정렬, @old_logic_location이 Scoped Files에 나타나는지 확인.","gap report를 산출하고 불합격 항목 나열. 전부 통과하지 않으면 해당 Role에 반려.","사람이 gap report를 검토하고 해당 Record에서 L3 샘플링 실행（아래 목록 참조）.","L1 + L2 + L3 전부 통과 → 해당 Record 체크. 4개 구역 모두 체크 → 1단계 동결."],"auditor_layers_heading":"3계층 검증 정의","auditor_layers_cols":["계층","검증 내용","실행자","합격 조건"],"auditor_layers_rows":[{"layer":"L1 커버리지 맵","checks":"scope 내 legacy 파일이 모두 귀속되어 있는지","who":"AI","pass":"미귀속 파일 = 0"},{"layer":"L2 구조 게이트","checks":"flow 템플릿, endpoint 폐루프, BDD 정렬, transform 통합","who":"AI","pass":"gap report 전부 통과"},{"layer":"L3 수동 샘플링","checks":"소스 코드와 무작위 대조. 내용이 채워진 것뿐 아니라 정확한지 확인","who":"Human","pass":"샘플링 항목 전부 통과（핵심 flow 5건 권장）"}],"auditor_spotcheck_heading":"L3 수동 샘플링 목록（각 Flow Record）","auditor_spotcheck_items":["Edge Case 1건 무작위 선택 → 원본 component의 if-else와 대조하여 flow.md 기술이 정확한지 확인.","@old_logic_location 1건 무작위 선택 → transformer 로직이 통합되었고 누락이 없는지 확인.","Unverified Logic 1건 무작위 선택 → 정말 code에서 설명할 수 없는지 확인（태만 표시가 아닌지）.","（핵심 비즈니스 flow 추가）Happy Path 단계 1건 + Referenced Endpoint 필드 의미 1건 추가 샘플링."],"checklist_heading":"survey-checklist.md 4개 구역 구조","checklist_intro":"고고학 산출물 유형마다 합격 기준이 다름. 각 체크박스에는 L1/L2/L3 서브 체크 필수. 「문서는 있으나 미검증」 방지.","checklist_cols":["구역","체크 단위","합격 기준","검증 깊이"],"checklist_rows":[{"area":"Flows","unit":"각 [flow-name] Record","standard":"flow.md（PM 확인 대기 포함）+ e2e-cases.feature + 참조 endpoints 모두 contract-schemas 보유. BDD와 flow.md 정렬","depth":"L1 + L2 + L3"},{"area":"Endpoints","unit":"각 [endpoint-name].ts","standard":"대응 main/contract-schemas/endpoints/[name].md 존재 및 upstream 참조","depth":"L2"},{"area":"Static Pages","unit":"각 페이지","standard":"main/pages/에 블록 + i18n key 목록（BDD 불필요）","depth":"L1"},{"area":"Global Constraints","unit":"일괄","standard":"global-constraints/e2e-cases.feature가 s4에 나열된 횡단 로직 커버","depth":"L2 + L3"}],"checklist_example_note":"아래는 checklist 항목 형식 예시（추상 예시）:","roles":[{"emoji":"🕵️","title":"코드 고고학자 (Code Archaeologist)","task":"레거시 시스템의 「현황（As-is）」 파악: 순수 비즈니스 행위 추출, codebase에서 관련 endpoint 응답 구조와 모든 가능성 추측, 데드 코드 제외.","input":["Repomix 패키징한 codebase","지정 flow 관련 라우트／컴포넌트 scope"],"output":["docs/records/flows/[flow-name]/flow.md","docs/records/endpoints/[endpoint-name].ts","CONTEXT.md（glossary 증분 업데이트）"],"ai_recommendation":{"tool":"claude","model":"Sonnet 4.5","tier":"budget","hint":"대량 파일 배치 고고학"},"spec_summary":"flow.md 템플릿 요건 펼치기","spec_example_note":"아래는 추상 예시. 섹션 구조 예시만. 본 프로젝트의 실제 flow나 endpoint가 아님.","spec_sections":[{"title":"### Entry Points","desc":"이 flow에 진입 가능한 페이지／라우트／홈페이지 블록. 홈페이지 spec은 참조만 기재, 행위 상세는 여기에 기술."},{"title":"### Referenced Endpoints","desc":"이 flow가 관여하는 endpoints/[name].ts 목록. endpoint 직교 축에 대한 인덱스."},{"title":"### Happy Path","desc":"극히 간결한 사용자 성공 조작 단계."},{"title":"### Edge Cases","desc":"코드 내 모든 비즈니스 로직 분기（네트워크 단절 등 인프라 오류 제외）."},{"title":"### PM 확인 대기","desc":"비즈니스 의도나 시나리오 불명: code는 행위를 알 수 있으나 「왜」나 올바른 규칙을 모름. 출처 위치와 의문 기재. 인벤토리 동결 후 Docusaurus Open Questions로 PM과 정렬."},{"title":"### Unverified Logic","desc":"코드 수수께끼: 작성되어 있으나 미실행, 재현 불가, 설명 불가 분기. 출처 파일 위치 기재. 프로덕션 log 검증 또는 백엔드 확인 대기（PM 비즈니스 문제 아님）."},{"title":"### Scoped Files（커버리지 맵）","desc":"Record 봉인 전 필수. scope 내 각 .ts/.tsx에 귀속 필수: flow 섹션 참조, Dead Code（사유 첨부）, Unverified Logic, 또는 다른 flow 상호 참조. 미귀속 파일 = 0이어야 Role 4에 전달."}],"spec_code":"# [flow-name]\n\n### Entry Points\n- `/some-list-page` — 사용자가 목록 페이지 옵션에서 진입\n- `/landing#quick-action` — 홈페이지 블록이 이 flow의 바로가기 진입점\n\n### Referenced Endpoints\n- `endpoints/search-items.ts` — 조회 및 필터\n- `endpoints/submit-action.ts` — 메인 액션 전송\n\n### Happy Path\n1. 사용자가 필수 조건 설정\n2. 시스템이 선택 가능한 결과 표시\n3. 사용자가 메인 액션 완료 후 성공 상태 확인\n\n### Edge Cases\n- 결과 없을 때 빈 상태 메시지 표시\n- 조건 불일치 시 다음 단계 진입 차단\n\n### PM 확인 대기\n- 특정 신분 유형에 다른 할인 규칙이 있어야 하는가? code에 분기 있으나 비즈니스 설명 없음（`src/legacy/Pricing.tsx:120`）\n\n### Unverified Logic\n- `src/legacy/foo.ts:88` — 분기가 한 번도 발생하지 않음, 원인 불명\n\n### Scoped Files\n| 파일 | 귀속 |\n|---|---|\n| src/pages/Booking.tsx | Happy Path + Edge Cases |\n| src/utils/legacyCoupon.ts | Edge Cases: 쿠폰 만료 |\n| src/deprecated/oldFlow.ts | Dead Code（라우트 참조 없음 확인） |\n| src/hooks/useMystery.ts | → Unverified Logic |\n\n---\n# endpoints/submit-action.ts（동일 Record 산출, 추상 예시）\n\n/** @endpoint POST /api/some-action */\ninterface RawActionResponse {\n  /** 필드 의미 확인 대기. 문자 그대로의 의미가 아닐 수 있음 */\n  status_code: string;\n  payload: unknown;\n}"},{"emoji":"📐","title":"데이터 경계 플래너 (Data Boundary Planner)","task":"고고학 산출 upstream을 시작점으로 To-be Frontend Interface를 정의하고, 컴포넌트와 Store에 분산된 변환 로직을 Transformer로 통합. live API에는 직접 접촉하지 않음.","input":["docs/records/flows/[flow-name]/flow.md","docs/records/endpoints/[endpoint-name].ts","레거시 component／store에서 통합해야 할 transform 조각","기존 docs/main/contract-schemas/shared/"],"output":["docs/main/contract-schemas/endpoints/[endpoint-name].md","（필요 시）docs/main/contract-schemas/shared/[entity].md","CONTEXT.md（glossary 증분 업데이트）"],"ai_recommendation":{"tool":"claude","model":"Opus 4.6","tier":"required","hint":"타입 정밀도 요구 높음"},"spec_summary":"contract-schema 템플릿 요건 펼치기","spec_example_note":"아래는 추상 예시. 본 프로젝트의 실제 API나 필드가 아님.","spec_sections":[{"title":"Upstream Schema（records/endpoints/ 참조）","desc":"Role 1 산출 .ts를 SSOT로, 필드 의미 모호성과 알려진 백엔드 특이점 기재."},{"title":"Target TypeScript Interface","desc":"To-be 프론트엔드 순수 타입. JSDoc으로 @upstream_source와 @old_logic_location 기재."},{"title":"Transformer Pure Functions","desc":"실행 가능한 TypeScript 변환 함수 프로토타입. component／store의 파생 계산 통합."}],"spec_code":"/** @upstream_source records/endpoints/submit-action.ts */\n\n// --- Upstream（고고학 산출물 참조, 요약） ---\n// status_code: string  — HTTP status가 아닌 비즈니스 상태 코드\n\n// --- Target Interface ---\ninterface ActionViewModel {\n  /** @old_logic_location src/legacy/ConfirmPanel.tsx:42 */\n  isSuccess: boolean;\n  displayMessage: string;\n}\n\n// --- Transformer ---\nfunction transformActionResponse(raw: RawActionResponse): ActionViewModel {\n  return {\n    isSuccess: raw.status_code === 'OK',\n    displayMessage: raw.payload?.message ?? '',\n  };\n}"},{"emoji":"✍️","title":"행위 테스트 아키텍트 (Behavior Test Architect)","task":"flow.md 비즈니스 로직을 구현과 분리된 BDD 케이스로 변환하고, flow.md 섹션과 추적 가능한 정렬 유지.","input":["docs/records/flows/[flow-name]/flow.md","docs/main/contract-schemas/endpoints/ + shared/"],"output":["docs/records/flows/[flow-name]/e2e-cases.feature"],"ai_recommendation":{"tool":"claude","model":"Sonnet 4.5","tier":"budget","hint":"구조화 BDD 출력"},"spec_summary":"BDD 템플릿 요건 펼치기","spec_example_note":"아래는 추상 예시. 본 프로젝트의 실제 시나리오가 아님.","spec_sections":[{"title":"Gherkin 문법","desc":"Given-When-Then 문법 필수."},{"title":"flow.md와 커버리지 정렬","desc":"Happy Path 최소 1 Scenario. 각 Edge Case 최소 1 Scenario. 각 Scenario 상단에 comment로 대응 flow.md 섹션 기재."},{"title":"PM 확인 대기 / Unverified Logic은 Scenario 작성하지 않음","desc":"비즈니스 확인 대기 항목과 code 수수께끼는 Scenario에 작성하지 않음. feature 파일 상단 comment에 분리하여 나열하고 flow.md 대응 섹션 참조."},{"title":"인프라 오류 제외","desc":"404/500/네트워크 단절은 전역 Client가 처리. Feature 파일에 작성하지 않음."}],"spec_code":"# PM 확인 대기（flow.md § PM 확인 대기 참조）:\n# - 특정 신분 할인 규칙 확인 대기\n\n# log 검증 대기（flow.md § Unverified Logic 참조）:\n# - src/legacy/foo.ts:88 — 분기가 한 번도 발생하지 않음\n\n# flow.md § Happy Path에 대응\nScenario: 사용자가 메인 액션 완료\n  Given 사용자가 유효한 조건을 설정함\n  When 사용자가 메인 액션을 제출함\n  Then 화면에 성공 상태가 표시됨\n\n# flow.md § Edge Cases: 결과 없음에 대응\nScenario: 조회 조건 일치 없음\n  Given 사용자가 유효한 조회 조건을 설정함\n  When 시스템이 빈 결과 집합을 반환함\n  Then 화면에 빈 상태 메시지가 표시됨"},{"emoji":"⚖️","title":"문서 인벤토리 담당 (Documentation Auditor)","task":"재고고학하지 않음. Role 1–3의 템플릿 계약 이행 여부 검증: AI가 L1 커버리지 맵과 L2 구조 게이트를 실행하여 gap report 산출, 사람이 L3 샘플링 승인 후 survey-checklist.md 업데이트.","input":["legacy 파일 트리","docs/records/와 docs/main/ 기존 산출물","각 Record의 flow.md § Scoped Files"],"output":["docs/survey-checklist.md","4개 구역 + 각 Record의 L1/L2/L3 서브 체크"],"ai_recommendation":{"tool":"claude","model":"Sonnet 4.5","tier":"budget","hint":"L1/L2 자동 검증. L3 수동 샘플링 승인"},"spec_summary":"L2 구조 게이트 상세 펼치기","spec_sections":[{"title":"L1 커버리지 맵","desc":"flow.md § Scoped Files와 대조: scope 내 각 .ts/.tsx가 「flow 참조 / Dead Code / Unverified / 다른 flow 상호 참조」 중 하나에 해당. 미귀속 = 0."},{"title":"L2 구조 게이트 — flow.md","desc":"7개 섹션 완비: Entry Points, Referenced Endpoints, Happy Path, Edge Cases, PM 확인 대기, Unverified Logic, Scoped Files."},{"title":"L2 구조 게이트 — endpoint 폐루프","desc":"Referenced Endpoints 각각에 records/endpoints/*.ts + main/contract-schemas/endpoints/*.md 존재."},{"title":"L2 구조 게이트 — BDD 정렬","desc":"Scenario 수 ≥ 1（Happy Path）+ Edge Cases 건수. 각 Scenario comment에 대응 flow.md 섹션 존재."},{"title":"L2 구조 게이트 — transform 통합","desc":"contract-schema의 @old_logic_location이 가리키는 파일은 Scoped Files에 반드시 나타나야 함."},{"title":"L3 수동 샘플링","desc":"본 섹션 아래 「L3 수동 샘플링 목록」 참조. 정적 페이지는 L1만. Endpoints는 L2만."}],"spec_code":"## Flows\n- [ ] booking-flow\n  - [ ] L1 커버리지 맵: 미귀속 파일 0\n  - [ ] L2 구조 게이트: 5/5 통과\n  - [ ] L3 샘플링: 3/3 통과（YYYY-MM-DD by @reviewer）\n\n## Endpoints\n- [x] post-reservation.ts — L2 통과\n\n## Static Pages\n- [x] /faq — L1 통과\n\n## Global Constraints\n- [ ] session-expiry — L2 + L3 검증 대기"}]},"s4":{"emoji":"🔄","heading":"핵심 고고학 인벤토리 플로우 및 실행 SUPPLEMENT","subheading":"3종류 고고학 산출물의 우선순위와 인벤토리 깊이. 비즈니스 불확실 항목은 고고학 기간에 표시, 인벤토리 동결 후 Docusaurus로 PM과 정렬.","example_callout":"⚠️ 아래 「알려진 예」는 현재 프로젝트 인식에 기반. 실제 flow 목록과 명명은 고고학 단계에서 codebase에서 정의.","pm_clarification_heading":"비즈니스 불확실 항목 3계층 처리","pm_clarification_items":["고고학 기간: code 수수께끼 → flow.md § Unverified Logic. 비즈니스 의도／시나리오 불명 → flow.md § PM 확인 대기","인벤토리 동결 → Docusaurus: 모든 「PM 확인 대기」를 Open Questions 전용 섹션에 통합","PM 정렬 후: 논의 통과분을 main/ To-be에 기술. 여전히 불확실한 것은 TODO + 프로덕션 log로 남김"],"card_scope_label":"범위","card_standard_label":"인벤토리 기준","table_cols":["카테고리","우선순위","범위","인벤토리 기준"],"table_rows":[{"category":"핵심 비즈니스 플로우 (Core Domain Flows)","priority":"최우선","priority_type":"emerald","scope":"페이지 횡단, 완전한 User Journey가 있는 플로우（고고학 시 codebase에서 정의）. 알려진 예: 예약 메인 플로우, 검색 필터, Email 딥링크 진입점 Coupon 플로우.","standard":"4역할 pipeline + Role 4 3계층 검증 완료 필수. flow.md + contract-schemas + BDD 산출. 비즈니스 불확실 항목은 「PM 확인 대기」에 표시."},{"category":"정적·콘텐츠 페이지 (Static & Content)","priority":"간소 인벤토리","priority_type":"blue","scope":"내비 페이지, FAQ, Top Page 블록 등（CMS 없음, 프론트 번역 파일에 저장）. Affiliate 소개 페이지（외부 폼으로 유도, 사이트 내 완전한 태스크 없음）도 이 유형.","standard":"schemas와 BDD 불필요. docs/main/pages/에 페이지 블록과 i18n key 나열."},{"category":"전역 시설·제약 (Global Infrastructure)","priority":"global-constraints 통합","priority_type":"indigo","scope":"인증 상태 유효기간（Session 수명 주기）, 오류 시도 횟수 제한（부정 사용 방지 프롬프트）, 전역 상태와 URL 동기화（언어·통화 URL 새로고침）","standard":"페이지 횡단 횡단 로직. docs/records/global-constraints/e2e-cases.feature에 통합. Role 4 L2 + L3 필수."}]},"s5":{"emoji":"🔒","heading":"변경 관리 및 Scope 동결","subheading":"두 관문: 인벤토리 동결（기술적 완비）→ Scope 동결（PM 판단）. spec과 Figma를 PM과 확인 후 「당분간 변경하지 않을」 블록부터 개편 시작.","freeze_callout":"checklist 100% → 인벤토리 동결 → Docusaurus 산출. spec + Figma를 PM에게 가져 Scope 동결: 어떤 블록이 우선 리팩터링 가능, 어떤 것이 추후 정렬인지. 착수는 PM이 당분간 변경하지 않는다고 확인한 부분부터.","two_gates_heading":"두 동결 관문","two_gates_cols":["관문","트리거 조건","산출"],"two_gates_rows":[{"gate":"인벤토리 동결","trigger":"survey-checklist 100%","output":"Docusaurus 게시 가능. Open Questions 통합 완료"},{"gate":"Scope 동결","trigger":"PM이 spec + Figma로 블록 단위 판단 완료","output":"각 flow／페이지에 「우선 리팩터링」 또는 「추후 정렬」 표시"}],"phase1_title":"1단계（고고학 기간）","phase1_items":["records/에 As-is 기록. main/에 To-be contract-schemas 누적.","flow.md에 「PM 확인 대기」와 Unverified Logic 표시.","checklist 100% 달성 → 인벤토리 동결, Docusaurus 정리（Open Questions 포함）."],"phase2_title":"2단계（PM 정렬 기간）","phase2_items":["Docusaurus spec과 Figma As-is 고를 PM에게 가져 블록 단위 확인（s6 참조）——추후 정렬 항목 포함, 둘 다 필수.","논의: 어떤 것이 현행 로직 유지, 어떤 것을 리팩터, 어떤 것이 플로우 재설계 필요한지.","Open Questions를 건별로 종결, 또는 Scope 판단으로 에스컬레이션.","각 flow／페이지에 Scope 표시（아래 참조）."],"scope_decisions_heading":"Scope 판단 태그","scope_decisions_intro":"PM 정렬의 핵심 산출. 판단은 Docusaurus 각 페이지 badge에 기록하고 main/ 파일 frontmatter에 되돌려 기록（scope: stable | pending）.","scope_decisions_cols":["태그","PM의 의미","다음 단계"],"scope_decisions_rows":[{"label":"우선 리팩터링","meaning":"PM이 이 블록의 비즈니스 로직이나 플로우는 당분간 변경하지 않는다고 확인","next":"리팩터 착수 우선 배정"},{"label":"추후 정렬","meaning":"PM이 이 블록은 향후 조정, 리팩터, 또는 플로우 재설계할 것이라고 표시","next":"1라운드에서도 spec + Figma As-is는 PM 판단용 필요. 착수와 To-be 설계는 보류. 「우선 리팩터링」 완료 후 2라운드에서 업데이트 spec + Figma를 PM과 논의"}],"phase3_title":"3단계（리팩터 착수 기간）","phase3_items":["Scope가 「우선 리팩터링」인 블록부터 개발 시작. 「추후 정렬」 항목에는 접촉하지 않음.","「추후 정렬」 항목: 다른 개편이 한 차례 마무리된 뒤 PM과 재논의하여 spec + Figma 업데이트.","Feature Branch에서 docs/main/（To-be）수정. PR에 CHANGELOG.md 첨부（Ticket Link + 변경 문서）.","코드 릴리스 시 문서도 Merge. 「코드가 곧 문서, 문서가 곧 코드」."]},"s6":{"emoji":"🧱","heading":"Figma 디자인 시스템과 3계층 Token 아키텍처","subheading":"s5 PM 정렬 지원: spec과 Figma As-is는 쌍으로 제시. 고고학 기간 Figma 미접촉. 인벤토리 동결 후 As-is 캔버스 구축. Scope 동결 후 「우선 리팩터링」 항목만 To-be 업데이트.","timeline_heading":"Figma 4단계 타임라인（s5와 정렬）","timeline_steps":["① 고고학 기간: 프론트는 Figma에 접촉하지 않음. 선택——디자이너에게 새 Token 아키텍처로 프로덕션 사이트 선행 동기화（As-is 복원）를 code 고고학과 병행 요청.","② 인벤토리 동결 후: spec에 기반하여 Figma As-is 캔버스 구축／보완（프로덕션과 100% 일치）. Docusaurus 산출과 병행.","③ PM 정렬 기간: 모든 flow／페이지（추후 정렬 포함）에서 spec + Figma As-is를 세트로 PM 확인.","④ 리팩터 착수: 「우선 리팩터링」 항목만 Figma To-be 업데이트. 「추후 정렬」은 As-is 유지, 2라운드 PM 논의 후 변경."],"pm_deliverable_callout":"PM 정렬 최소 산출물: 각 flow 핵심 화면 + 정적 페이지 블록. spec（Docusaurus）과 Figma As-is 둘 다 필수.","kit_callout":"Figma 시작점: Obra shadcn/ui kit을 커뮤니티 템플릿으로 사용（https://obra.studio/work/figma-shadcn-ui-kit/）. 각 프로젝트 로컬에 복제 후 Token과 As-is 캔버스를 덮어쓰기. 제로부터 컴포넌트 라이브러리 구축하지 않음. 코드 측은 shadcn/ui CLI와 연동.","intro_p1":"멀티 프로덕트 「고립식 유지보수」: Figma Professional은 파일 간 Variables 연동 불가. 「중앙 템플릿（Obra kit + shadcn 컴포넌트）, 로컬 커스터마이징」 채택——템플릿 복제, 브랜드 색 매핑, As-is 캔버스 복원.","intro_p2":"Token 3계층은 Obra／shadcn 철학과 일치: 하위 Raw는 Tailwind palette 명명. Brand는 100–900 스케일 구축. Semantic은 shadcn에 정렬하고 비즈니스 전용 색 통합. 캔버스는 Semantic만 바인딩.","pro_warning":"⚠️ Figma Variables 생성에는 Pro plan의 Full seat 필요（Collab seat 불가）.","token_rule":"3계층 Token 물리적 분리: 캔버스는 Semantic Token만 사용 가능하며 필수. Raw（Tailwind palette）와 Brand（100–900 스케일）은 캔버스 직접 바인딩 금지.","token_cols":["계층 (Layer)","명명 규격","코드 측 대조","디자이너 권한"],"token_rows":[{"layer":"1. Raw / Primitives 🔒","figma":"Tailwind CSS palette와 동명（예: slate-500, blue-600, neutral-100）","css":"tailwind.config / @theme 하위 색상","access":"❌ 캔버스 바인딩 금지. 색상 대사전."},{"layer":"2. Brand 🔒","figma":"사이트 브랜드 색 100–900 스케일（예: brand-blue-100, brand-orange-500）","css":"theme에서 brand scale 정의. 캔버스 노출은 Semantic alias 경유（예: --brand-pink）","access":"❌ 캔버스 바인딩 금지."},{"layer":"3. Semantic 🔓","figma":"shadcn 표준（background, primary, muted…）+ 비즈니스 의미（예: link, brand-pink）","css":"globals.css :root — shadcn 내장（--background, --primary…）+ 커스텀（--link, --brand-pink）","access":"🔓 유일하게 허용. Raw 또는 Brand에서 색 선택하여 바인딩."}],"token_semantic_heading":"Semantic 계층 규칙","token_semantic_rules":["shadcn 내장 semantic 우선（background, foreground, primary, muted, destructive…）.","Semantic 색 출처: Raw（Tailwind palette）또는 Brand（100–900）에서 선택하여 alias 생성.","shadcn 미포함 brand／비즈니스 색: Semantic 계층에서 명명（예: link, brand-pink）. globals.css :root에 CSS variable 추가, Brand 또는 Raw를 가리킴.","Figma Semantic Variables와 :root 변수명 1:1 정렬（shadcn/ui CLI 관례 따름）."],"fold_org_content":"중앙 Workspace → Obra shadcn/ui kit 템플릿（Raw Tailwind palette + shadcn 표준 컴포넌트）. 각 프로젝트 로컬 → kit 복제, Brand 스케일과 Semantic mapping 덮어쓰기, As-is 화면 100% 복원.","fold_pattern_central":"중앙 유지보수: 100% 비즈니스 로직 시각 일치, 커스터마이징 불가（예: 일본 지도 선택기）→ Copy-Paste.","fold_pattern_local":"로컬 유지보수: 프로덕트 라인에 따라 의미가 바뀌는 복합 컴포넌트（예: BookingCard, CouponSelector）→ 중앙 shadcn 기반 + 로컬 조립.","fold_align_desc":"Figma 캔버스에는 영어 가독 문구만（회사 사이트 주 로케일 EN）. i18n key는 두지 않고 Variables Mode로 번역도 관리하지 않음.","fold_align_rules":["Description에 디자인 비고 가능（key 아님）: 동적 문구（API 응답）, placeholder／글자 수 상한, truncation 위험, PM 문구 미정, 또는 Docusaurus spec 섹션 링크.","Sticky／Comment는 PM 정렬 기간 논의용만. 장기 SSOT 아님.","i18n key와 다국어 대조: legacy 고고학 → JSON → Google Sheet → code（s7 참조）. 정적 페이지는 docs/main/pages/에 블록 + key도 나열. 리팩터 시 「화면 + spec／Sheet」로 대조. Figma에서 key 역조회하지 않음."],"fold_align_example":"캔버스: \"Please enter your booking code\" → Description: 「예약 코드 placeholder. 정적 문구. booking flow spec §2 참조」——booking.field.code_placeholder가 아님."},"s7":{"emoji":"🌍","heading":"다국어 (i18n) 완전 자동 파이프라인","figma_boundary":"Figma는 영어 가독 문구만 표시（주 로케일 EN）. i18n SSOT 아님. key와 번역은 고고학 JSON → Sheet → code가 정답. 디자인 고 Description은 디자인 의미 비고만（s6 참조）.","sheet_ssot":"고고학 기간 legacy 각 로케일 번역은 이미 존재——정리는 포맷 세척, namespace／key 리네임, status 표시만. 재번역하지 않음. Sheet 기록 시 en／ja／zh_TW 등 열은 이미 갖춰져 있어야 함. Sheet가 완전 대조표.","toolchain_note":"툴체인: 고고학은 Claude Web으로 정리 JSON 산출, 개편은 Cursor. 목표 프레임워크 i18next → next-intl. 포맷은 next-intl 관례에 맞게 조정. status는 unused／in-progress.","gemini_rule":"Gemini는 고고학 필수 단계 아님: Sheet에 legacy 전 로케일 포함. refactor에서 key 추가（in-progress）또는 수동 위탁 보역 시에만 Gemini로 Sheet 조작 가능. Instruction Sheet에 Tone Guide 배치하여 보역 참고.","iron_rule":"System Prompt급 전역 철칙: 필요한 번역이 JSON에 없으면 새 Key 창작 금지. 먼저 코드에서 Hardcode하고 // TODO: i18n-missing 표시로 배치 추출.","migration_heading":"i18next → next-intl 정리 규칙","normalize_rules":["프레임워크 마이그레이션: i18next 구조에서 next-intl 관례로 정리（namespace + key, JSON／message 포맷은 next-intl 동기화 스크립트 출력 따름）.","여분 공백은 적극 삭제하지 않음——legacy는 레이아웃용 의도적 보존일 수 있음. 정리 시 그대로 Sheet에 반영.","줄바꿈 병합: legacy가 배열 [a, b, c]로 문장을 나누어 map 렌더링하는 경우, 단일 key 내 \\n 줄바꿈으로 정리（예: \"Line one\\nLine two\\nLine three\"）. 번역자가 동일 열에서 편집하기 쉽게.","보간 문법: 고고학 정리 시 i18next {{var}}를 next-intl {var}로 직접 변환. Sheet 기록이 종국 형태. sync script는 읽기／쓰기만, 포맷 변환 담당하지 않음——향후 재사용 가능.","코드 측: \\n 포함 문구는 CSS whitespace-pre-line（또는 동등）로 렌더링. 컴포넌트 내 배열 map 분문하지 않음."],"namespace_heading":"Namespace 분할","namespace_rules":["단일 domain 프로젝트: 「페이지／화면」을 namespace 단위. -page 접미사 없음（예: checkout, affiliate-intro）.","페이지 횡단 공유 문구 → common. 각 페이지는 자신의 namespace + common만 참조. Flow 전용 namespace는 두지 않음——flow 내 각 단계 화면은 대응 페이지 번역 사용.","slug는 docs/main/pages/, Figma frame 이름, 라우트 Entry screen과 정렬. 정리 시 legacy_key는 구명 보존하여 대조."],"fold_json_content":"JSON 포맷 예: status, namespace, key, legacy_key, en, ja, zh_TW, description.\n\n각 로케일 값은 legacy translations에서 반영（빈 껍데기 대기 번역 아님）. 예: namespace checkout + key coupon.btn.apply. legacy_key는 script 누락 대조용.","sync_heading":"Sheet → code 출력 구조","sync_rules":["namespace 단위 파일 분할: messages/{locale}/{namespace}.json（예: messages/en/common.json, messages/en/checkout.json）.","파일 내 JSON 중첩（예: { \"coupon\": { \"btn\": { \"apply\": \"…\" } } }）. Sheet key 열은 dot notation（coupon.btn.apply）로 편집 용이. sync script가 code 기록 시 중첩으로 전개.","Sheet namespace 열과 파일명 1:1. 페이지는 useTranslations('{namespace}') + t('coupon.btn.apply'). common은 페이지 횡단 공유."],"steps":["AI가 legacy 번역을 JSON으로 정리（i18next → next-intl. {{var}} → {var}. 배열 줄바꿈을 \\n으로 병합. 여분 공백 trim하지 않음）","Script가 legacy_key와 원본 translations 대조하여 누락 확인（동적 key는 수동 active 표시）","Script가 Google Spreadsheet에 기록（단일 sheet + namespace 열. 각 로케일 열은 갖춰져 있음）","신규 프로젝트 sync script: Sheet → messages/{locale}/{namespace}.json（dot key를 중첩 JSON으로. unused 필터, in-progress는 🚧 표시）","SKILL.md 철칙: key 누락 시 창작 금지. hardcode + // TODO: i18n-missing. 신규 key는 in-progress 표시 후 보역"]},"s8":{"emoji":"🏁","heading":"인벤토리, 교정 및 개편 시작","validation_heading":"병렬 대조 및 개편 임계값","validation_items":["신구 프로젝트를 동일 workspace에 배치하여 전후 대조.","\\n 포함 다중 행 문구: 프론트는 CSS whitespace-pre-line 사용（s7 줄바꿈 병합 규칙 참조）. 배열 map 분문하지 않음.","인벤토리 동결 후 records/ + main/ 인벤토리 문서를 Docusaurus 형식으로 정리하여 독립 repo 배포, PM과 정렬（작업 디렉터리 자체는 PM용 아님）."],"gate_heading":"Phase 3 착수 및 검수（3단계）","gate_project_heading":"1. 프로젝트급（Phase 3 착수 전, 1회만）","gate_project_items":["인벤토리 동결（survey-checklist 100%）","Docusaurus 정리·배포 완료","Figma As-is 100% 준비 완료（인벤토리 동결 후 Docusaurus와 병행 완료. Scope 동결 전제）","Scope 동결 완료: 각 flow／페이지에 우선 리팩터링 또는 추후 정렬 표시","추후 정렬 항목도 1라운드에서 spec + Figma As-is 필요하나 착수 풀에는 포함하지 않음"],"gate_issue_heading":"2. 단일 Issue／수직 슬라이스（우선 리팩터링만）","gate_issue_cols":["Issue 유형","착수 전 최소 요건"],"gate_issue_rows":[{"type":"Schema / Transformer / 순수 함수","requirement":"flow.md + main/contract-schemas/ 사양이면 충분 → TDD 착수"},{"type":"UI 컴포넌트／페이지","requirement":"위 + 해당 블록 Figma To-be（우선 리팩터링 항목）"},{"type":"Flow（BDD 있음）","requirement":"Happy Path Scenarios 작성 완료. PM 확인 대기／Unverified Logic은 comment 유지, Scenario 작성하지 않음"},{"type":"Static Pages","requirement":"docs/main/pages/ 블록 + i18n key 목록이면 충분. BDD 불필요"}],"gate_merge_heading":"3. 머지／릴리스 전（검수. 착수 임계값 아님）","gate_merge_items":["해당 슬라이스 BDD 전부 통과（Scenario 작성된 flow）","AI L1/L2 구조 검증 + 수동 L3 spot-check（s3 참조）","PM이 해당 우선 리팩터링 블록 sign-off（Docusaurus spec + Figma To-be 대조）"],"log_rule_heading":"Unverified Logic 관측 철칙","log_rule":"리팩터 시 로직 행위는 legacy와 정렬 필수. flow.md § Unverified Logic에 나열된 분기는 refactor 버전에 runtime log 추가하여 여전히 발생하는지 관측——무음 삭제·건너뛰기 금지.","log_rule_items":["고고학 기간 표시된 Unverified Logic: 동등 분기 유지하고 log 추가（flow.md 파일 위치 참조）.","관측 기간 hit 없음 → 분기 삭제 가능. flow.md § Scoped Files 업데이트.","리팩터 중 새로 발견된 설명 불가 분기: 먼저 flow.md § Unverified Logic에 추가 표시 후 log 추가. 직접 제거 금지."],"skills_heading":"Issue 분할과 Matt Pocock Agent Skills","skills_subheading":"Issues를 5대 Agent Skills로 분할. monorepo 특성 활용. Issue 병렬 태스크.","skills_cols":["Skill","설명","권장 AI","단계"],"skills_rows":[{"name":"Grill-with-Docs","desc":"고고학 문서와 결합, 설계 트리를 따라 판단 분기 명확화","ai":"Claude Opus 4.6","phase":"계획"},{"name":"To-PRD","desc":"합의에서 PRD 산출. User Stories와 모듈 초안 포함","ai":"Claude Sonnet 4.5","phase":"계획"},{"name":"To-Issues","desc":"PRD를 수직 슬라이스 Issue로 분해. blocking 관계 구축","ai":"Claude Sonnet 4.5","phase":"계획"},{"name":"TDD","desc":"적록 리팩터 순환. 한 줄 테스트 한 줄 구현. 리팩터 누락 방지","ai":"Cursor Composer 2.5","phase":"개발"},{"name":"Architecture-Refactor","desc":"얕은 모듈 심화. 테스트 경계 명확화하여 Agent 안정 탐색 실현","ai":"Cursor Composer 2.5","phase":"개발"}],"refs_heading":"기술 참고 링크","refs":[{"label":"Stop writing docs by hand","url":"https://www.aihero.dev/5-agent-skills-i-use-every-day"},{"label":"Playwright BDD","url":"https://playwright.dev/docs/test-agents"}],"issues_heading":"원자화 Issue 예시","issues":[{"id":"#01","tag":"Schema","title":"transformBookingAmount 순수 함수 구현","blocks":"우선 리팩터링 + flow.md／schema 준비 완료 시 착수 가능"},{"id":"#02","tag":"UI","title":"Figma To-be에 기반하여 BookingCard 정적 컴포넌트 구현","blocks":"#01에 블록. 해당 블록 To-be 고 필요"},{"id":"#03","tag":"BDD","title":"예약 코드 검증 Edge Cases 검수 케이스 작성","blocks":"#01과 병행 가능. 머지 전 BDD 통과 필수"}],"roadmap_heading":"Roadmap","roadmap":[{"title":"Phase 1: 고고학 및 인벤토리 동결","desc":"4역할 Skills → records/ + main/ → checklist 100%（인벤토리 동결）. 이어 Docusaurus와 Figma As-is 병행 산출（s6 ②, 프로덕션과 100% 일치）——둘 다 준비 완료 시 Phase 2로. 고고학 기간 ① kit 동기화 선택."},{"title":"Phase 2: Scope 동결","desc":"전제 충족: Docusaurus spec + Figma As-is 둘 다 갖춤. PM이 각 flow／페이지를 쌍으로 확인하고 우선 리팩터링／추후 정렬 표시（s6 ③）.","risk":"🔥 리스크 관리: Figma As-is 미완성 시 PM 정렬 진행 불가"},{"title":"Phase 3: 리팩터 착수","desc":"프로젝트급 + Issue 임계값 통과 후 우선 리팩터링 수직 슬라이스만 착수. Figma To-be는 UI Issue와 함께 점진 업데이트（s6 ④）. 머지 전 BDD + L3 + PM sign-off."}],"roadmap_note":"Figma As-is는 refactor 때 하는 것이 아님——Phase 2 PM 정렬의 필수 전제. Docusaurus와 병행하여 인벤토리 동결 후 완료."},"s9":{"emoji":"🛡️","heading":"API 데이터 경계: BFF 없이, Zod + Transformers","subheading":"「프론트엔드·백엔드 책임 분리와 BFF 설계」논의 후 결론: BFF를 별도 구축하지 않고, 프론트가 Core API를 fetch한 뒤 Zod로 runtime 검증과 데이터 정규화（Parse, don't validate）. s3 데이터 경계 플래너 산출 contract-schemas와 정렬.","decision_callout":"BFF 계층을 구축하지 않음——infra와 배포 비용 절감. 프론트 `httpClient`가 백엔드에 직접 연결. client 측에서 Zod Schema + Transformer가 legacy 특이 포맷을 통합. 컴포넌트는 Clean Type만 수신.","layers_heading":"3계층 방어선","layers_cols":["계층","책임","산출물"],"layers_rows":[{"layer":"1. Upstream（고고학）","role":"Role 1이 codebase에서 백엔드 Raw 구조 추측","artifact":"docs/records/endpoints/[endpoint-name].ts"},{"layer":"2. Contract（사양 SSOT）","role":"Role 2가 Frontend Interface + Transformer 프로토타입 정의","artifact":"docs/main/contract-schemas/endpoints/[name].md"},{"layer":"3. Runtime（코드）","role":"refactor가 Zod parse + transform + handleResponse 구현","artifact":"lib/api/[endpoint-name]/{schema,transformer,index}.ts"}],"runtime_heading":"Runtime 패턴（client-side normalization）","runtime_steps":["httpClient fetch Core API → unknown 획득","Zod Backend*Schema.safeParse — HTML／비 JSON／필드 드리프트 차단（ApiProtocolError）",".transform()로 프론트 Clean Type 변환（snake_case, 의미 필드, 중복 제거）","통일 ApiResponseSuccess / ApiResponseError envelope — 비즈니스 오류는 ApiBusinessError throw","React／Store는 Clean Type만 import. Raw JSON 직접 접촉 금지"],"error_heading":"Error 분류","error_cols":["유형","트리거","처리"],"error_rows":[{"type":"ApiProtocolError","trigger":"비 JSON, HTML 오류 페이지, Zod parse 실패","handling":"log + 통일 오류 UI. s1 「error 형식 불일치」근본 원인 대응"},{"type":"ApiBusinessError","trigger":"백엔드가 { error: { code, message } } 반환","handling":"code로 분기. 컴포넌트 내 추측 판단 폐지"}],"proto_heading":"프로토타입 참고（backend/ — 일시 중단）","proto_intro":"위 패턴으로 다수 endpoint 구현（get-bus-list, get-locations, submit-contact…）. 각각 schema.ts（Backend + Clean）, transformer.ts, index.ts. 공통 handleResponse와 contract.ts.","proto_structure":["backend/[endpoint-name]/schema.ts — Backend*Schema（Zod）+ Clean Type","backend/[endpoint-name]/transformer.ts — request／response transform","backend/[endpoint-name]/index.ts — httpClient + handleResponse","backend/utils/handle-response.ts — safeParse 통일 진입점","backend/contract.ts — ApiResponseSuccess / ApiResponseError"],"proto_pause_heading":"일시 중단 이유","proto_pause_items":["endpoint 수 증가 후 폴더 간 길을 잃기 쉬움——flow／고고학 산출물과의 명명 대조 SSOT 부족","Backend 명명（PascalCase, 중첩 XML 스타일）과 프론트 Clean 명명의 API 횡단 정렬 어려움","shared entity（예: BusFacilities）와 각 endpoint 경계 불명확. 중복 정의 위험"],"plan_bridge_heading":"개편 계획 연속 방법","plan_bridge_items":["고고학 기간: records/endpoints/[name].ts와 flow.md § Referenced Endpoints 1:1——endpoint 목록을 기억에 의존하지 않음","계획 기간: contract-schemas/endpoints/[name].md가 명명과 Transformer의 SSOT. shared/에서 endpoint 횡단 entity 통합","code 디렉터리 slug는 contract-schemas 파일명과 정렬（예: get-bus-list）. endpoint당 1폴더","첫 vertical slice에서 golden sample 정의（Zod + test 포함）. 이후 endpoint는 구조 복제, 재발명하지 않음","Role 2 착수 전 contract-schemas/shared/ 반드시 확인. 동일 entity 중복 정의 금지"],"bff_note":"BFF 논의에서 평가한 지점 검색, 7k건 캐시 등——대부분 프론트 IndexedDB + 로컬 filter로 대응 가능. 지리 연산이 필요한 소수 시나리오만 백엔드. 기본 경로는 client-side transformer. 별도 BFF service는 열지 않음."},"footer":{"text":"Project Renovation & Refactor Plan"}}};
